def ensure_farmer_expeditor_offer_ids(request: dict) -> list:
    """Гарантирует стабильные ID у откликов экспедитора в заявке фермера."""
    if not isinstance(request, dict):
        return []

    offers = request.get("expeditor_offers")
    if not isinstance(offers, list):
        request["expeditor_offers"] = []
        return request["expeditor_offers"]

    max_offer_id = 0
    seen_ids = set()
    for offer in offers:
        if not isinstance(offer, dict):
            continue
        raw_id = offer.get("id")
        try:
            numeric_id = int(raw_id)
        except (TypeError, ValueError):
            continue
        key = str(numeric_id)
        if key in seen_ids:
            offer["id"] = None
            continue
        seen_ids.add(key)
        if numeric_id > max_offer_id:
            max_offer_id = numeric_id

    for offer in offers:
        if not isinstance(offer, dict):
            continue
        raw_id = offer.get("id")
        try:
            int(raw_id)
            continue
        except (TypeError, ValueError):
            pass
        max_offer_id += 1
        offer["id"] = max_offer_id

    return offers


def find_farmer_expeditor_offer(request: dict, offer_ref, prefer_index: bool = False):
    """
    Поиск отклика экспедитора в заявке фермера по стабильному offer_id.
    Возвращает (offer_id, offer, index).
    Для legacy-кнопок допускает fallback на индекс списка.
    """
    offers = ensure_farmer_expeditor_offer_ids(request)

    if prefer_index:
        try:
            offer_idx = int(offer_ref)
        except (TypeError, ValueError):
            offer_idx = None
        if offer_idx is not None and 0 <= offer_idx < len(offers):
            offer = offers[offer_idx]
            if isinstance(offer, dict):
                offer_id = offer.get("id")
                return offer_id, offer, offer_idx

    for idx, offer in enumerate(offers):
        if not isinstance(offer, dict):
            continue
        offer_id = offer.get("id")
        if same_id(offer_id, offer_ref):
            return offer_id, offer, idx

    if not prefer_index:
        try:
            offer_idx = int(offer_ref)
        except (TypeError, ValueError):
            offer_idx = None
        if offer_idx is not None and 0 <= offer_idx < len(offers):
            offer = offers[offer_idx]
            if isinstance(offer, dict):
                offer_id = offer.get("id")
                return offer_id, offer, offer_idx

    return None, None, None


