# Функция завершения создания быстрой партии
async def finish_quick_batch(message_or_callback, state: FSMContext, user_id: int):
    """Создать партию и добавить в пулл"""
    global batch_counter, deal_counter
    data = await state.get_data()
    pull_id = data.get("pull_id")
    user_info = get_user_by_id(user_id) or {}
    if user_info.get("role") not in {"farmer", "admin"}:
        if hasattr(message_or_callback, "answer"):
            await message_or_callback.answer("❌ Доступно только фермеру")
        else:
            await message_or_callback.message.answer("❌ Доступно только фермеру")
        await state.finish()
        return

    # ✅ ИСПРАВЛЕНО: Получаем пулы из правильного места
    all_pulls = pulls.get("pulls", {})
    pull = all_pulls.get(pull_id) or all_pulls.get(str(pull_id))

    if not pull:
        if hasattr(message_or_callback, "answer"):
            await message_or_callback.answer("❌ Пул не найден")
        else:
            await message_or_callback.message.answer("❌ Пул не найден")
        await state.finish()
        return
    if not is_pull_open_status(pull.get("status")):
        if hasattr(message_or_callback, "answer"):
            await message_or_callback.answer("❌ Пул закрыт для присоединения")
        else:
            await message_or_callback.message.answer("❌ Пул закрыт для присоединения")
        await state.finish()
        return

    batch_volume = safe_float(data.get("volume", 0), 0.0)
    batch_price = safe_float(data.get("price", 0), 0.0)
    if batch_volume <= 0:
        if hasattr(message_or_callback, "answer"):
            await message_or_callback.answer("❌ Некорректный объём партии")
        else:
            await message_or_callback.message.answer("❌ Некорректный объём партии")
        await state.finish()
        return

    target_volume = safe_float(pull.get("target_volume", 0), 0.0)
    current_volume = safe_float(pull.get("current_volume", 0), 0.0)
    available_volume = max(target_volume - current_volume, 0.0)
    if target_volume > 0 and batch_volume > available_volume:
        msg = (
            "❌ Объём партии превышает доступный объём пула.\n"
            f"Доступно: {available_volume:,.0f} т"
        )
        if hasattr(message_or_callback, "answer"):
            await message_or_callback.answer(msg)
        else:
            await message_or_callback.message.answer(msg)
        await state.finish()
        return

    # Создаём партию с числовым ID (совместимо с parse_callback_id)
    batch_id = max(batch_counter, max((int(bid) for bid, _, _ in iter_all_batches()), default=0)) + 1
    batch_counter = batch_id
    batch = {
        "id": batch_id,
        "farmer_id": user_id,
        "culture": pull.get("culture"),
        "volume": batch_volume,
        "price": batch_price,
        "region": pull.get("region", "?"),
        "status": "active",
        "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
    }

    # Добавляем качество если есть
    if "nature" in data:
        batch["nature"] = data.get("nature")
        batch["moisture"] = data.get("moisture")
        batch["impurity"] = data.get("impurity")

    # Сохраняем партию
    if user_id not in batches:
        batches[user_id] = []
    batches[user_id].append(batch)

    # ✅ ИСПРАВЛЕНО: Работа с глобальной переменной pullparticipants
    pull_id_str = str(pull_id)

    if pull_id_str not in pullparticipants:
        pullparticipants[pull_id_str] = []

    pullparticipants[pull_id_str].append(
        {
            "farmer_id": user_id,
            "farmer_name": user_info.get("name", "?"),
            "batch_id": batch_id,
            "volume": batch_volume,
            "joined_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        }
    )

    # Диагностика
    logging.info(f"✅ Участник добавлен в pullparticipants[{pull_id_str}]")
    logging.info(f"   Всего участников в пуле: {len(pullparticipants[pull_id_str])}")

    # Добавляем в пулл
    if "batches" not in pull:
        pull["batches"] = []

    pull["batches"].append(
        {
            "id": batch_id,
            "farmer_id": user_id,
            "culture": batch.get("culture"),
            "volume": batch.get("volume"),
            "price": batch.get("price"),
            "moisture": batch.get("moisture", 0),
            "impurity": batch.get("impurity", 0),
            "joined_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        }
    )

    if "batch_ids" not in pull:
        pull["batch_ids"] = []
    pull["batch_ids"].append(batch_id)

    if "farmer_ids" not in pull:
        pull["farmer_ids"] = []
    if not any(same_id(existing_farmer_id, user_id) for existing_farmer_id in pull["farmer_ids"]):
        pull["farmer_ids"].append(user_id)

    # ✅ ИСПРАВЛЕНО: Используем current_volume
    pull["current_volume"] = pull.get("current_volume", 0) + batch_volume

    # Создаём сделку с числовым ID (совместимо с parse_callback_id)
    deal_id = next_numeric_id(deals)
    deal_counter = max(deal_counter, int(deal_id))
    deal = {
        "id": deal_id,
        "pull_id": pull_id,
        "batch_id": batch_id,
        "farmer_id": user_id,
        "exporter_id": pull.get("exporter_id"),
        "status": "matched",
        "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
    }
    deals[deal_id] = deal

    # Сохраняем
    save_batches_to_pickle()
    save_pulls_to_pickle()
    save_deals_to_pickle()

    # Уведомления
    farmer = user_info
    exporter_id = pull.get("exporter_id")
    target_volume = pull.get("target_volume", 0)
    fill_percent = (
        (pull["current_volume"] / target_volume * 100) if target_volume > 0 else 0
    )

    await bot.send_message(
        user_id,
        "✅ <b>Партия создана и добавлена в пулл!</b>\n\n"
        f"🌾 {batch['culture']} • {batch['volume']:,.0f} т • {batch['price']:,.0f} ₽/т\n"
        f"📊 Пулл заполнен: {pull['current_volume']:,.0f}/{target_volume:,.0f} т ({fill_percent:.0f}%)",
        parse_mode="HTML",
    )

    if exporter_id:
        await bot.send_message(
            exporter_id,
            f"📦 <b>Новая партия добавлена в ваш пулл #{pull_id}!</b>\n\n"
            f"👤 Фермер: {farmer.get('name')}\n"
            f"🌾 {batch['culture']} • {batch['volume']:,.0f} т • {batch['price']:,.0f} ₽/т\n"
            f"📊 Заполнено: {pull['current_volume']:,.0f}/{target_volume:,.0f} т ({fill_percent:.0f}%)",
            parse_mode="HTML",
        )

    # Проверяем заполнение пулла
    if pull["current_volume"] >= target_volume:
        pull["status"] = "filled"
        save_pulls_to_pickle()
        logging.info(f"🎉 Пул #{pull_id} заполнен!")

    # Возвращаемся к пуллу
    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton("📊 К пуллу", callback_data=f"view_pull:{pull_id}")
    )

    if isinstance(message_or_callback, types.Message):
        await message_or_callback.answer(
            "✅ Готово! Партия добавлена в пулл", reply_markup=keyboard
        )
    else:
        try:
            await message_or_callback.message.edit_text(
                "✅ Готово! Партия добавлена в пулл", reply_markup=keyboard
            )
        except Exception as e:
            logging.debug(f"Не удалось отредактировать сообщение после добавления партии: {e}")
            await message_or_callback.message.answer(
                "✅ Готово! Партия добавлена в пулл", reply_markup=keyboard
            )


@dp.callback_query_handler(
    lambda c: c.data.startswith("createbatchforpull:"), state="*"
)
async def create_batch_for_pull_callback(
    callback: types.CallbackQuery, state: FSMContext
):
    """Создание партии для присоединения к пулу"""
    try:
        pull_id = parse_callback_id(callback.data)
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка обработки данных", show_alert=True)
        return
    if pull_id is None:
        await callback.answer("❌ Ошибка данных пула", show_alert=True)
        return

    _, pull = find_pull_by_id(pull_id)
    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        return
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if user_role not in {"farmer", "admin"}:
        await callback.answer(
            "❌ Создание партии для пула доступно только фермерам",
            show_alert=True,
        )
        return
    if not is_pull_open_status(pull.get("status")):
        await callback.answer("❌ Пул закрыт для присоединения", show_alert=True)
        return

    # Сохраняем ID пула и культуру для последующего присоединения
    await state.update_data(
        create_batch_for_pull_id=pull_id, culture=pull.get("culture", "Культура")
    )

    await callback.message.answer(
        f"**📦 Создание партии для пула #{pull_id}**\n\n"
        f"🌾 Культура: **{pull.get('culture', 'Культура')}**\n\n"
        "**Шаг 1/8:** Укажите регион производства:",
        reply_markup=region_keyboard(),
        parse_mode="Markdown",
    )

    await AddBatch.region.set()  # ✅ ИСПРАВЛЕНО: AddBatch вместо AddBatchStatesGroup
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("selectbatchjoin:"),
    state=JoinPullStatesGroup.select_batch,
)
async def select_batch_for_join(callback: types.CallbackQuery, state: FSMContext):
    """Выбор партии для присоединения к пулу"""
    try:
        batch_id = parse_callback_id(callback.data)
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        await state.finish()
        return
    if batch_id is None:
        await callback.answer("❌ Ошибка данных партии", show_alert=True)
        await state.finish()
        return

    data = await state.get_data()
    pull_id = data.get("join_pull_id")

    if not pull_id:
        await callback.answer("❌ Пул не найден. Попробуйте снова.", show_alert=True)
        await state.finish()
        return

    all_pulls = pulls.get("pulls", {})
    pull = all_pulls.get(pull_id) or all_pulls.get(str(pull_id))
    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        await state.finish()
        return

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if user_role != "farmer":
        await callback.answer("❌ Только фермер может присоединять партию", show_alert=True)
        await state.finish()
        return

    pull_status = normalize_transition_status(pull.get("status", ""))
    if not is_pull_open_status(pull_status):
        await callback.answer("❌ Пул закрыт для присоединения", show_alert=True)
        await state.finish()
        return

    # Ищем партию только у текущего пользователя
    user_batches = get_user_batches(user_id)

    batch = next((b for b in user_batches if same_id(b.get("id"), batch_id)), None)

    if not batch:
        await callback.answer("❌ Партия не найдена", show_alert=True)
        await state.finish()
        return

    batch_status = normalize_transition_status(batch.get("status"))
    if batch_status not in {"active", "open"}:
        await callback.answer(
            "❌ Можно присоединить только активную партию", show_alert=True
        )
        await state.finish()
        return

    # Сравнение культур с учетом регистра и пробелов
    batch_culture = (batch.get("culture") or "").strip().lower()
    pull_culture = (pull.get("culture") or "").strip().lower()
    if batch_culture != pull_culture:
        await callback.answer(
            "❌ Культура партии не совпадает с пулом!", show_alert=True
        )
        await state.finish()
        return

    target_volume = pull.get("target_volume", 0)
    current_volume = pull.get("current_volume", 0)
    available = target_volume - current_volume

    if batch.get("volume", 0) > available:
        await callback.answer(
            "❌ Объем партии больше доступного в пуле!", show_alert=True
        )
        await state.finish()
        return

    # ✅ ИСПРАВЛЕНО: Работа с pullparticipants через глобальную переменную
    # Нормализуем ключ к строке для единообразия
    pull_id_str = str(pull_id)

    if pull_id_str not in pullparticipants:
        pullparticipants[pull_id_str] = []

    if any(
        isinstance(p, dict) and same_id(p.get("batch_id"), batch_id)
        for p in pullparticipants[pull_id_str]
    ):
        await callback.answer("❌ Эта партия уже присоединена к пулу", show_alert=True)
        await state.finish()
        return

    participant = {
        "farmer_id": user_id,
        "farmer_name": (get_user_by_id(user_id) or {}).get("name", ""),
        "batch_id": batch_id,
        "volume": batch.get("volume", 0),
        "joined_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
    }
    pullparticipants[pull_id_str].append(participant)

    # ✅ ДИАГНОСТИКА - можно убрать после отладки
    logging.info(f"✅ Участник добавлен в pullparticipants[{pull_id_str}]")
    logging.info(f"   Участников в пуле: {len(pullparticipants[pull_id_str])}")

    pull.setdefault("batch_ids", [])
    if not any(same_id(existing_batch_id, batch_id) for existing_batch_id in pull["batch_ids"]):
        pull["batch_ids"].append(batch.get("id", batch_id))

    pull.setdefault("farmer_ids", [])
    if not any(same_id(existing_farmer_id, user_id) for existing_farmer_id in pull["farmer_ids"]):
        pull["farmer_ids"].append(user_id)

    pull.setdefault("batches", [])
    if not any(
        (
            isinstance(b, dict)
            and same_id(b.get("id"), batch_id)
        )
        or (
            not isinstance(b, dict)
            and same_id(b, batch_id)
        )
        for b in pull["batches"]
    ):
        pull["batches"].append(
            {
                "id": batch.get("id", batch_id),
                "farmer_id": user_id,
                "culture": batch.get("culture"),
                "volume": batch.get("volume"),
                "price": batch.get("price"),
                "moisture": batch.get("moisture", 0),
                "impurity": batch.get("impurity", batch.get("impurities", 0)),
                "quality_class": batch.get("quality_class", ""),
                "joined_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            }
        )

    pull["current_volume"] = current_volume + batch.get("volume", 0)

    # Закрытие пула при заполнении
    if pull["current_volume"] >= target_volume:
        pull["status"] = "filled"
        save_pulls_to_pickle()
        logging.info(f"🎉 Пул #{pull_id} заполнен на 100%!")

    # Уведомление экспортера с данными фермера
    exporter_id = pull.get("exporter_id")
    if exporter_id:
        farmer = get_user_by_id(user_id) or {}
        farmer_name = farmer.get("name", "Неизвестно")
        farmer_phone = farmer.get("phone", "Не указан")
        farmer_email = farmer.get("email", "Не указан")
        farmer_company = farmer.get("company_details", "Не указано")

        fill_ratio = (pull["current_volume"] / target_volume * 100) if target_volume > 0 else 0
        message_exporter = (
            f"🎉 <b>Фермер присоединился к пулу #{pull_id}!</b>\n"
            f"Культура: {pull.get('culture')}\n"
            f"Объём партии: {batch.get('volume', 0):,.0f} т\n"
            f"Текущий объём пула: {pull['current_volume']:,.0f}/{target_volume:,.0f} т\n"
            f"Заполненность: {fill_ratio:.1f}%\n\n"
            "👤 <b>Данные фермера:</b>\n"
            f"Имя: {farmer_name}\n"
            f"Компания: {farmer_company}\n"
            f"Телефон: {farmer_phone}\n"
            f"Email: {farmer_email}"
        )
        try:
            await bot.send_message(exporter_id, message_exporter, parse_mode="HTML")
        except Exception as e:
            logging.error(f"Ошибка уведомления экспортёру: {e}")

    # Уведомление фермера с данными экспортера
    exporter = get_user_by_id(exporter_id) or {}
    if exporter:
        exporter_name = exporter.get("name", "Неизвестно")
        exporter_phone = exporter.get("phone", "Не указан")
        exporter_email = exporter.get("email", "Не указан")
        exporter_company = exporter.get("company_details", "Не указано")

        message_farmer = (
            f"✅ <b>Вы присоединились к пулу #{pull_id}!</b>\n"
            f"Культура: {batch.get('culture')}\n"
            f"Объём: {batch.get('volume')} т\n"
            f"Цена: {batch.get('price'):,.0f} ₽/т\n\n"
            "👤 <b>Данные экспортера:</b>\n"
            f"Имя: {exporter_name}\n"
            f"Компания: {exporter_company}\n"
            f"Телефон: {exporter_phone}\n"
            f"Email: {exporter_email}"
        )
        try:
            await bot.send_message(user_id, message_farmer, parse_mode="HTML")
        except Exception as e:
            logging.error(f"Ошибка уведомления фермеру: {e}")

    batch["status"] = "reserved"

    save_pulls_to_pickle()
    save_batches_to_pickle()

    # ✅ ДИАГНОСТИКА - можно убрать после отладки
    logging.info("✅ Данные сохранены в файл")

    try:
        await callback.message.delete()
    except Exception as e:
        logging.warning(f"Не удалось удалить сообщение: {e}")

    if normalize_transition_status(pull.get("status")) == "filled":
        await callback.answer(
            "✅ Партия добавлена! Пул заполнен на 100%!", show_alert=True
        )
    else:
        await callback.answer("✅ Успешно присоединились к пулу!", show_alert=True)

    await state.finish()


@dp.callback_query_handler(lambda c: c.data.startswith("viewparticipants:"), state="*")
async def view_pullparticipants(callback: types.CallbackQuery, state: FSMContext):
    """Просмотр участников пула с полными контактами"""
    await state.finish()

    try:
        pull_id = parse_callback_id(callback.data)
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return
    if pull_id is None:
        await callback.answer("❌ Ошибка данных пула", show_alert=True)
        return

    resolved_pull_id, pull = find_pull_by_id(pull_id)
    pull_id = resolved_pull_id if resolved_pull_id is not None else pull_id

    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        return

    # ✅ ИСПРАВЛЕНО: Используем глобальную переменную напрямую
    participants = pullparticipants.get(pull_id, []) or pullparticipants.get(
        str(pull_id), []
    )
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    pull_owner_id = pull.get("exporter_id") or pull.get("creator_id")
    is_participant = any(
        isinstance(p, dict) and same_id(p.get("farmer_id"), user_id)
        for p in participants
    )
    if not (user_role == "admin" or same_id(pull_owner_id, user_id) or is_participant):
        await callback.answer("❌ Нет доступа к участникам этого пула", show_alert=True)
        return
    can_view_full_contacts = user_role == "admin" or same_id(pull_owner_id, user_id)

    # Диагностика
    logging.info(
        f"🔍 view_pullparticipants: pull_id={pull_id} (type={type(pull_id).__name__})"
    )
    logging.info(f"🔍 pullparticipants.keys() = {list(pullparticipants.keys())}")
    logging.info(f"🔍 Найдено участников: {len(participants)}")

    if not participants:
        await callback.answer("В пуле пока нет участников", show_alert=True)
        return

    msg = f"👥 <b>Участники пула #{pull_id}</b>\n\n"
    msg += f"🌾 Культура: {pull.get('culture', '?')}\n"
    msg += f"📦 Целевой объём: {pull.get('target_volume', 0)} т\n"
    msg += f"📊 Текущий объём: {pull.get('current_volume', 0)} т\n"

    target_vol = pull.get("target_volume", 1)
    current_vol = pull.get("current_volume", 0)
    progress = (current_vol / target_vol * 100) if target_vol > 0 else 0

    msg += f"📈 Заполнено: {progress:.1f}%\n\n"
    msg += f"<b>Участники ({len(participants)}):</b>\n\n"

    for i, p in enumerate(participants, 1):
        farmer_id = p.get("farmer_id")
        farmer = get_user_by_id(farmer_id) or {}

        msg += f"{i}. <b>{p.get('farmer_name', '?')}</b>\n"
        msg += f"   📦 Объём: {p.get('volume', 0)} т\n"

        batch_id = p.get("batch_id")
        batch = None
        if farmer_id in batches:
            for b in batches[farmer_id]:
                if same_id(b.get("id"), batch_id):
                    batch = b
                    break

        if batch:
            msg += f"   💰 Цена: {batch.get('price', 0):,.0f} ₽/т\n"
            msg += f"   📍 Регион: {batch.get('region', 'Не указано')}\n"

        msg += f"   📅 Присоединился: {p.get('joined_at', '?')}\n"

        phone = farmer.get("phone", "Не указан")
        email = farmer.get("email", "Не указан")

        if can_view_full_contacts or same_id(farmer_id, user_id):
            msg += f"   📱 Телефон: <code>{phone}</code>\n"
            msg += f"   📧 Email: <code>{email}</code>\n"
        else:
            msg += "   📱 Телефон: <i>скрыт</i>\n"
            msg += "   📧 Email: <i>скрыт</i>\n"
        msg += "\n"

    keyboard = InlineKeyboardMarkup(row_width=1)
    keyboard.add(
        InlineKeyboardButton("◀️ Назад к пулу", callback_data=f"view_pull:{pull_id}")
    )

    await callback.message.edit_text(msg, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("region:"), state=RegistrationStatesGroup.region
)
async def registration_region(callback: types.CallbackQuery, state: FSMContext):
    """Обработка выбора региона"""

    region = callback.data.split(":", 1)[1]

    if region == "other":
        await callback.message.answer("Введите название вашего региона:")
        return

    await state.update_data(region=region)

    data = await state.get_data()
    user_id = callback.from_user.id
    role = data.get("role")

    logging.info(
        f"📝 Завершение регистрации user_id={user_id}, role={role}, region={region}"
    )

    users[user_id] = {
        "name": data.get("name"),
        "phone": data.get("phone"),
        "email": data.get("email"),
        "inn": data.get("inn"),
        "ogrn": data.get("ogrn"),
        "company_details": data.get("company_details"),
        "role": role,
        "region": region,
        "registered_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
    }

    save_users_to_pickle()

    # Синхронизация с Google Sheets
    if gs and gs.spreadsheet:
        try:
            gs.sync_user_to_sheets(users[user_id], user_id)
        except Exception as e:
            logging.error(f"Ошибка синхронизации с Google Sheets: {e}")

    await state.finish()

    # ✅ УДАЛЯЕМ СООБЩЕНИЕ С ВЫБОРОМ РЕГИОНА
    try:
        await callback.message.delete()
    except Exception as e:
        logging.warning(f"⚠️ Не удалось удалить сообщение региона: {e}")

    keyboard = get_role_keyboard(role)

    role_names_display = {
        "farmer": "Фермер",
        "exporter": "Экспортёр",
        "logistic": "Логист",
        "expeditor": "Экспедитор",
    }

    # ✅ ОТПРАВЛЯЕМ НОВОЕ СООБЩЕНИЕ (не редактируем)
    await callback.message.answer(
        "✅ <b>Регистрация завершена!</b>\n\n"
        f"👤 Имя: {data.get('name')}\n"
        f"📱 Телефон: {data.get('phone')}\n"
        f"📧 Email: {data.get('email')}\n"
        f"🎭 Роль: {role_names_display.get(role, role)}\n"
        f"📍 Регион: {region}\n\n"
        "Добро пожаловать в EXPORTUM!",
        reply_markup=keyboard,
        parse_mode="HTML",
    )

    await callback.answer("✅ Регистрация завершена!")


