# РАСШИРЕННЫЙ ФУНКЦИОНАЛ ЭКСПОРТЁРА
# Добавление партий в пулл, выбор логистов и экспедиторов
# ═══════════════════════════════════════════════════════════════════════════


@dp.callback_query_handler(lambda c: c.data.startswith("add_batch_to_pull:"), state="*")
async def add_batch_to_pull_select(callback: types.CallbackQuery):
    """Выбор пулла для добавления партии"""
    try:
        batch_id = parse_callback_id(callback.data)
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return
    if batch_id is None:
        await callback.answer("❌ Ошибка данных партии", show_alert=True)
        return

    user_id = callback.from_user.id

    _, batch = find_batch_by_id(batch_id)

    if not batch:
        await callback.answer("❌ Партия не найдена", show_alert=True)
        return

    # Получаем активные пулы экспортёра с той же культурой
    user_pulls = []
    all_pulls = pulls.get("pulls", pulls) if isinstance(pulls, dict) else {}
    for pid, p in all_pulls.items():
        if not isinstance(p, dict):
            continue
        if (
            (same_id(p.get("creator_id"), user_id) or same_id(p.get("exporter_id"), user_id))
            and p.get("culture", "").lower() == batch.get("culture", "").lower()
            and is_pull_open_status(p.get("status"))
        ):
            user_pulls.append((pid, p))

    if not user_pulls:
        await callback.answer(
            f"❌ У вас нет активных пулов для культуры: {batch.get('culture', 'Неизвестно')}\n"
            "Создайте пулл сначала!",
            show_alert=True,
        )
        return

    # Показываем список пулов
    keyboard = InlineKeyboardMarkup(row_width=1)

    for pull_id, pull in user_pulls:
        current_vol = pull.get("current_volume")
        if current_vol is None:
            current_vol = 0
            for b in pull.get("batches_data", []):
                if isinstance(b, dict):
                    current_vol += b.get("volume", 0)

        target_vol = pull.get("target_volume", 0) or 0

        keyboard.add(
            InlineKeyboardButton(
                f"Пулл #{pull_id}: {current_vol:.1f}/{target_vol:.1f} т",
                callback_data=f"confirm_add_batch:{batch_id}:{pull_id}",
            )
        )

    keyboard.add(InlineKeyboardButton("❌ Отмена", callback_data="cancel_action"))

    await callback.message.edit_text(
        "📦 <b>Добавление партии в пулл</b>\n\n"
        f"🌾 Партия: {batch.get('culture', 'Неизвестно')} • {batch.get('volume', 0):.1f} т\n"
        f"📍 Регион: {batch.get('region', 'Не указан')}\n"
        f"💰 Цена: {batch.get('price', 0):,} ₽/т\n\n"
        "Выберите пулл для добавления:",
        parse_mode="HTML",
        reply_markup=keyboard,
    )
    await callback.answer()


# ════════════════════════════════════════════════════════════════════════════════════
# ИСПРАВЛЕННАЯ ВЕРСИЯ
# ════════════════════════════════════════════════════════════════════════════════════
@dp.callback_query_handler(lambda c: c.data.startswith("confirm_add_batch:"), state="*")
async def confirm_add_batch_to_pull(callback: types.CallbackQuery):
    """✅ Подтверждение добавления партии в пулл - ПОЛНОСТЬЮ ИСПРАВЛЕННАЯ ВЕРСИЯ"""
    try:
        _, batch_id, pull_id = callback.data.split(":")
        batch_id = int(batch_id)
        pull_id = int(pull_id)

        # 🔍 ЛОГИРУЕМ ТИП И ЗНАЧЕНИЕ
        logging.info(f"🔍 batch_id type: {type(batch_id).__name__}, value: {batch_id}")
        logging.info(f"🔍 pull_id type: {type(pull_id).__name__}, value: {pull_id}")

    except (ValueError, IndexError) as e:
        logging.error(f"❌ Ошибка парсинга: {e}")
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return

    try:
        # 1️⃣ ИЩЕМ ПАРТИЮ И ФЕРМЕРА
        farmer_id, batch = find_batch_by_id(batch_id)

        if not batch or not farmer_id:
            logging.error(
                f"❌ Партия не найдена: batch_id={batch_id}, farmer_id={farmer_id}"
            )
            await callback.answer("❌ Партия не найдена", show_alert=True)
            return
        batch_status = normalize_transition_status(batch.get("status"))
        if batch_status not in {"active", "open", "pending"}:
            await callback.answer(
                "❌ Партия недоступна для добавления в пулл", show_alert=True
            )
            return

        # 2️⃣ ИЩЕМ ПУЛЛ
        pulls_dict = pulls.get("pulls", {}) if isinstance(pulls, dict) else {}
        pull = pulls_dict.get(pull_id) or pulls_dict.get(str(pull_id))
        if not pull:
            logging.error(f"❌ Пулл не найден: pull_id={pull_id}")
            await callback.answer("❌ Пулл не найден", show_alert=True)
            return

        # 3️⃣ ПРОВЕРЯЕМ ПРАВА
        pull_owner_id = pull.get("creator_id") or pull.get("exporter_id")
        if not same_id(pull_owner_id, callback.from_user.id):
            await callback.answer("❌ Это не ваш пулл", show_alert=True)
            return
        if not is_pull_open_status(pull.get("status")):
            await callback.answer("❌ Пулл закрыт для добавления партий", show_alert=True)
            return

        batch_volume = safe_float(batch.get("volume", 0), 0.0)
        target_volume = safe_float(pull.get("target_volume", 0), 0.0)
        current_volume = safe_float(pull.get("current_volume", 0), 0.0)
        available_volume = max(target_volume - current_volume, 0.0)
        if target_volume > 0 and batch_volume > available_volume:
            await callback.answer(
                f"❌ Недостаточно места в пулле. Доступно: {available_volume:.1f} т",
                show_alert=True,
            )
            return
        batch_culture = normalize_status_key(batch.get("culture"))
        pull_culture = normalize_status_key(pull.get("culture"))
        if batch_culture != pull_culture:
            await callback.answer("❌ Культура партии не совпадает с пуллом", show_alert=True)
            return

        # 4️⃣ ИНИЦИАЛИЗИРУЕМ ПОЛЯ ПУЛЛА
        if "batches" not in pull:
            pull["batches"] = []
        if "batch_ids" not in pull:
            pull["batch_ids"] = []
        if "farmer_ids" not in pull:
            pull["farmer_ids"] = []

        # ИНИЦИАЛИЗИРУЕМ pullparticipants
        participants_key = (
            pull_id
            if pull_id in pullparticipants
            else str(pull_id)
            if str(pull_id) in pullparticipants
            else pull_id
        )
        if participants_key not in pullparticipants:
            pullparticipants[participants_key] = []

        # 5️⃣ ПРОВЕРЯЕМ ЧТО ПАРТИЯ НЕ ДОБАВЛЕНА
        if any(same_id(existing_batch_id, batch_id) for existing_batch_id in pull["batch_ids"]):
            await callback.answer("⚠️ Партия уже в пуле", show_alert=True)
            return

        # 6️⃣ ДОБАВЛЯЕМ ПАРТИЮ В ПУЛ
        if not any(
            (
                (
                    isinstance(b, dict)
                    and same_id(b.get("id"), batch_id)
                )
                or (
                    not isinstance(b, dict)
                    and same_id(b, batch_id)
                )
            )
            for b in pull.get("batches", [])
        ):
            pull["batches"].append(
                {
                    "id": batch_id,
                    "farmer_id": farmer_id,
                    "culture": batch.get("culture"),
                    "volume": batch.get("volume"),
                    "price": batch.get("price"),
                    "moisture": batch.get("moisture", batch.get("humidity", 0)),
                    "impurity": batch.get("impurity", batch.get("impurities", 0)),
                    "quality_class": batch.get("quality_class", ""),
                    "joined_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                }
            )
        pull["batch_ids"].append(batch_id)
        batch["status"] = "reserved"
        batch["pull_id"] = pull_id

        # 7️⃣ ДОБАВЛЯЕМ ФЕРМЕРА
        if not any(same_id(existing_farmer_id, farmer_id) for existing_farmer_id in pull["farmer_ids"]):
            pull["farmer_ids"].append(farmer_id)
            logging.info(f"✅ Фермер {farmer_id} добавлен в пулл {pull_id}")

        # 8️⃣ ДОБАВЛЯЕМ В pullparticipants
        farmer_info = get_user_by_id(farmer_id) or {}
        participant_record = {
            "batch_id": batch_id,
            "farmer_id": farmer_id,
            "farmer_name": farmer_info.get("name", "Unknown"),
            "volume": batch.get("volume", 0),
            "quality_class": batch.get("quality_class", ""),
            "culture": batch.get("culture", ""),
            "price_per_ton": batch.get("price", 0),
        }

        if not any(
            same_id(p.get("batch_id"), batch_id)
            for p in pullparticipants.get(participants_key, [])
            if isinstance(p, dict)
        ):
            pullparticipants[participants_key].append(participant_record)
            logging.info(
                f"✅ Участник добавлен: farmer_id={farmer_id}, batch_id={batch_id}"
            )

        # 9️⃣ СЧИТАЕМ ОБЪЁМ
        current_volume = 0
        for b_id in pull["batch_ids"]:
            _, existing_batch = find_batch_by_id(b_id)
            if existing_batch:
                current_volume += existing_batch.get("volume", 0)

        target_volume = pull.get("target_volume", 0)
        pull["current_volume"] = current_volume

        # 🔟 ПРОВЕРЯЕМ ЗАПОЛНЕНИЕ
        status_msg = ""
        if target_volume > 0 and current_volume >= target_volume:
            pull["status"] = "filled"
            status_msg = "🎉 Пулл собран!"
            logging.info(f"🎉 Пулл #{pull_id} СОБРАН!")

            try:
                await bot.send_message(
                    callback.from_user.id,
                    f"🎉 <b>Пулл #{pull_id} собран!</b>\n\n"
                    f"🌾 {pull.get('culture', 'Культура')}\n"
                    f"📊 Объём: {current_volume:.1f}/{target_volume:.1f} т\n"
                    f"👥 Фермеров: <b>{len(pull['farmer_ids'])}</b>\n"
                    f"📦 Партий: <b>{len(pull['batch_ids'])}</b>\n"
                    f"📍 Порт: {pull.get('port', 'Не указан')}",
                    parse_mode="HTML",
                )
            except Exception as e:
                logging.error(f"❌ Ошибка уведомления экспортёра: {e}")
        else:
            status_msg = "✅ Партия добавлена"

        # 1️⃣1️⃣ УВЕДОМЛЯЕМ ФЕРМЕРА
        if farmer_id in users:
            try:
                await bot.send_message(
                    farmer_id,
                    "✅ <b>Ваша партия добавлена в пулл!</b>\n\n"
                    f"🌾 {batch.get('culture', 'Культура')} • {batch.get('volume', 0):.1f} т\n"
                    f"📦 Пулл #{pull_id}\n"
                    f"👥 Участников в пуле: <b>{len(pull['farmer_ids'])}</b>\n"
                    f"📊 Собрано: {current_volume:.1f}/{target_volume:.1f} т\n"
                    f"🚢 Порт: {pull.get('port', 'Не указан')}\n"
                    f"💰 Цена: {batch.get('price', 0):,} ₽/т",
                    parse_mode="HTML",
                )
            except Exception as e:
                logging.error(f"❌ Ошибка уведомления фермера: {e}")

        # 🔴 ГЛАВНАЯ ИСПРАВКА - СОХРАНЯЕМ ПУЛЛ В ГЛОБАЛЬНЫЙ СЛОВАРЬ!
        pulls["pulls"][pull_id] = pull

        # 1️⃣2️⃣ СОХРАНЯЕМ ДАННЫЕ
        save_data()

        # ✅ ЛОГИРУЕМ РЕЗУЛЬТАТ
        logging.info("✅ Данные сохранены:")
        logging.info(
            f"   pulls['pulls'][{pull_id}]['batch_ids'] = {pulls['pulls'][pull_id].get('batch_ids', [])}"
        )
        logging.info(
            f"   pullparticipants[{participants_key}] кол-во = {len(pullparticipants.get(participants_key, []))}"
        )

        # 1️⃣3️⃣ ОТВЕТ ПОЛЬЗОВАТЕЛЮ
        await callback.message.edit_text(
            f"✅ <b>Партия добавлена в пулл #{pull_id}!</b>\n\n"
            f"📊 Текущий объём: {current_volume:.1f}/{target_volume:.1f} т\n"
            f"👥 Фермеров в пуле: <b>{len(pull['farmer_ids'])}</b>\n"
            f"📦 Партий: <b>{len(pull['batch_ids'])}</b>\n"
            f"📋 Участников добавлено: <b>{len(pullparticipants[participants_key])}</b>\n"
            f"{status_msg}",
            parse_mode="HTML",
        )
        await callback.answer("✅ Партия добавлена!")

    except Exception as e:
        logging.error(f"❌ ОШИБКА в confirm_add_batch_to_pull: {e}", exc_info=True)
        await callback.answer(f"❌ Ошибка: {str(e)[:100]}", show_alert=True)


# ═══════════════════════════════════════════════════════════════════════════
# 🚚 ФЕРМЕР СОЗДАЕТ ЗАЯВКУ НА ДОСТАВКУ (копия логики экспортера)
# ═══════════════════════════════════════════════════════════════════════════
@dp.message_handler(lambda m: m.text == "🚚 Создать заявку на доставку", state="*")
async def create_logistics_from_menu(message: types.Message, state: FSMContext):
    """Показывает список партий для выбора"""
    await state.finish()
    user_id = message.from_user.id

    user_batches = get_user_batches(user_id)

    if not user_batches:
        await message.answer(
            "❌ <b>У вас нет партий!</b>\n\n"
            "Сначала создайте партию:\n➕ Добавить партию",
            parse_mode="HTML",
        )
        return

    text = "🚚 <b>СОЗДАТЬ ЗАЯВКУ НА ДОСТАВКУ</b>\n\nВыберите партию:"
    keyboard = InlineKeyboardMarkup(row_width=1)

    for batch in user_batches:
        batch_id = batch.get("id")
        culture = batch.get("culture", "Не указана")
        volume = batch.get("volume", 0)
        price = batch.get("price", 0)

        keyboard.add(
            InlineKeyboardButton(
                f"🌾 {culture} • {volume} т • {price:,} ₽/т",
                callback_data=f"create_logistics_from_batch:{batch_id}",
            )
        )

    keyboard.add(InlineKeyboardButton("❌ Отмена", callback_data="cancel_action"))

    await message.answer(text, reply_markup=keyboard, parse_mode="HTML")


@dp.callback_query_handler(
    lambda c: c.data.startswith("create_logistics_from_batch:"), state="*"
)
async def create_logistics_from_batch_handler(
    callback: types.CallbackQuery, state: FSMContext
):
    """
    Фермер нажимает "🚚 Создать заявку на доставку" в просмотре партии.
    Новый мастер: регион назначения -> порт -> транспорт -> цена -> подтверждение.
    """
    await state.finish()

    try:
        batch_id = int(callback.data.split(":")[1])
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка: некорректный ID партии", show_alert=True)
        logging.error(f"❌ Неверный callback_data: {callback.data}")
        return

    user_id = callback.from_user.id

    # Найти партию фермера
    batch = None
    for b in get_user_batches(user_id):
        if same_id(b.get("id"), batch_id):
            batch = b
            break

    if not batch:
        await callback.answer("❌ Партия не найдена", show_alert=True)
        logging.error(f"❌ Партия {batch_id} не найдена у фермера {user_id}")
        return

    logging.info(
        f"🚚 Фермер {user_id} начал создание заявки на доставку для партии {batch_id}"
    )

    farmer_region = (get_user_by_id(user_id) or {}).get("region", "Не указан")

    # Сохраняем данные партии в состояние
    await state.update_data(batch_id=batch_id, batch=batch, farmer_region=farmer_region)

    # ШАГ 1: выбор региона / города назначения
    await callback.message.edit_text(
        "🚚 <b>ЗАЯВКА НА ДОСТАВКУ</b>\n\n"
        "━━━━━━━━━━━━━━━━━━━━━━\n"
        f"🌾 <b>Культура:</b> {batch.get('culture')}\n"
        f"📦 <b>Объём:</b> {batch.get('volume')} т\n"
        f"💰 <b>Цена партии:</b> {batch.get('price'):,} ₽/т\n"
        f"💵 <b>Общая стоимость:</b> {batch.get('volume') * batch.get('price'):,} ₽\n"
        f"📍 <b>Откуда:</b> {farmer_region}\n"
        "━━━━━━━━━━━━━━━━━━━━━━\n\n"
        "<b>ШАГ 1/5:</b> Укажите <b>регион/город назначения</b>\n\n"
        "Например: <code>Астраханская область</code> или <code>Ростов-на-Дону</code>",
        parse_mode="HTML",
        reply_markup=InlineKeyboardMarkup().add(
            InlineKeyboardButton("❌ Отмена", callback_data="farmer_main_menu")
        ),
    )

    await FarmerShippingRequestStates.route_to_region.set()
    await callback.answer()


@dp.message_handler(state=FarmerShippingRequestStates.route_to_region)
async def farmer_enter_destination_region(message: types.Message, state: FSMContext):
    """ШАГ 2: фермер вводит регион/город назначения, затем выбирает порт."""
    to_region = message.text.strip()

    if not to_region or len(to_region) < 2:
        await message.answer(
            "❌ Укажите корректный регион/город назначения\n\n"
            "Пример: <code>Астраханская область</code> или <code>Ростов-на-Дону</code>",
            parse_mode="HTML",
        )
        return

    await state.update_data(to_region=to_region)

    # Клавиатура выбора порта
    ports = [
        ("Ариб", "ariyb"),
        ("ПКФ «Волга-Порт»", "volga_port"),
        ("ПКФ «Юг-Тер»", "yug_ter"),
        ("ПАО «Астр.Порт»", "astr_port"),
        ("Универ.Порт", "univer_port"),
        ("Юж.Порт", "yuzh_port"),
        ("Агрофуд", "agrofud"),
        ("Моспорт", "mosport"),
        ("ЦГП", "cgp"),
        ("АЗТ", "fzt"),
        ("АМП", "amp"),
        ("Армада", "armada"),
        ("Стрелец", "strelec"),
        ("Альфа", "alfa"),
    ]

    keyboard = InlineKeyboardMarkup(row_width=1)
    for name, code in ports:
        keyboard.add(
            InlineKeyboardButton(
                f"⚓ {name}", callback_data=f"farmer_select_port:{code}"
            )
        )
    keyboard.add(InlineKeyboardButton("❌ Отмена", callback_data="farmer_main_menu"))

    await message.answer(
        "⚓ <b>ШАГ 2/5:</b> выберите <b>порт назначения</b>\n\n"
        f"Регион/город: <b>{to_region}</b>",
        reply_markup=keyboard,
        parse_mode="HTML",
    )

    await FarmerShippingRequestStates.route_to_port.set()


@dp.callback_query_handler(
    lambda c: c.data.startswith("__legacy_create_logistic_req_disabled:"), state="*"
)
async def select_pull_for_logistics_legacy(
    callback: types.CallbackQuery, state: FSMContext
):
    """Выбор пула для заявки"""
    try:
        pull_id = parse_callback_id(callback.data)
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return
    if pull_id is None:
        await callback.answer("❌ Ошибка данных пула", show_alert=True)
        return

    _, pull = find_pull_by_id(pull_id)
    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        return

    await state.update_data(
        pull_id=pull_id,
        culture=pull.get("culture", "Культура"),
        volume=pull.get("current_volume", 0),
        port=pull.get("port", ""),
    )

    await callback.message.edit_text(
        "🚚 <b>Заявка на логистику</b>\n\n"
        "<b>Шаг 1 из 4</b>\n\n"
        f"Пул: #{pull_id} • {pull.get('culture', 'Культура')} • {pull.get('current_volume', 0):.0f} т\n"
        f"Порт: {pull.get('port', '')}\n\n"
        "Откуда (регион/город погрузки):",
        parse_mode="HTML",
    )

    await CreateLogisticRequestStatesGroup.route_from.set()
    await callback.answer()


