@dp.callback_query_handler(text="farmer_confirm_logistics_request", state="*")
async def farmer_confirm_logistics_request(
    callback: types.CallbackQuery, state: FSMContext
):
    """СОЗДАНИЕ ЗАЯВКИ ФЕРМЕРОМ (уведомление логистов и экспедиторов)."""
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if not (user_role == "admin" or user_role == "farmer"):
        await callback.answer("❌ Доступно только фермерам", show_alert=True)
        return

    data = await state.get_data()
    farmer_user = get_user_by_id(user_id) or {}

    if not data.get("batch"):
        await callback.answer("❌ Ошибка: данные потеряны", show_alert=True)
        return

    batch = data["batch"]
    port = data["port"]
    transport = data["transport"]
    to_region = data.get("to_region", "Не указан")

    ports_dict = {
        "ariyb": "Ариб",
        "volga_port": "ПКФ «Волга-Порт»",
        "yug_ter": "ПКФ «Юг-Тер»",
        "astr_port": "ПАО «Астр.Порт»",
        "univer_port": "Универ.Порт",
        "yuzh_port": "Юж.Порт",
        "agrofud": "Агрофуд",
        "mosport": "Моспорт",
        "cgp": "ЦГП",
        "fzt": "АЗТ",
        "amp": "АМП",
        "armada": "Армада",
        "strelec": "Стрелец",
        "alfa": "Альфа",
    }

    transports_dict = {
        "railway": "ЖД",
        "grain": "Зерновоз",
        "truck": "Фура",
    }

    port_name = ports_dict.get(port, port)
    transport_name = transports_dict.get(transport, transport)

    farmer_region = farmer_user.get("region", "Не указан")

    request_id = next_numeric_id(farmer_logistics_requests)

    farmer_logistics_requests[request_id] = {
        "id": request_id,
        "farmer_id": user_id,
        "farmer_name": farmer_user.get("name", "Неизвестно"),
        "farmer_phone": farmer_user.get("phone", "Не указан"),
        "farmer_email": farmer_user.get("email", "Не указана"),
        "farmer_region": farmer_region,
        "batch_id": data["batch_id"],
        "culture": batch["culture"],
        "volume": batch["volume"],
        "price_per_ton": batch["price"],
        "total_sum": batch["volume"] * batch["price"],
        "route_from": farmer_region,
        "route_to_region": to_region,
        "route_to": port_name,
        "port_to": port_name,
        "port_code": port,
        "transport_type": transport_name,
        "transport_code": transport,
        "desired_price": data["desired_price"],
        "status": "active",
        "offers_count": 0,
        "created_at": datetime.now().strftime("%d.%m.%Y %H:%M"),
        "offers": [],
        "expeditor_offers": [],
        "expeditor_offers_count": 0,
    }

    save_data()

    logging.info(
        f"✅ Фермер {user_id} создал заявку #{request_id}: "
        f"{batch['culture']} {batch['volume']}т, {to_region} ({port_name}), "
        f"{transport_name}, {data['desired_price']}₽/т"
    )

    # Уведомления логистам и экспедиторам — меняем только текст маршрута

    logists_count = 0
    for logist_id, user_data in users.items():
        if not isinstance(user_data, dict):
            continue
        if is_logistic_role(user_data.get("role")):
            try:
                msg = (
                    "📬 <b>НОВАЯ ЗАЯВКА НА ДОСТАВКУ!</b>\n\n"
                    f"🌾 {batch['culture']} • {batch['volume']} т\n"
                    f"💰 Цена партии: {batch['price']:,} ₽/т\n"
                    f"💳 Ожидаемая цена доставки: {data['desired_price']:,} ₽/т\n\n"
                    f"📍 От: {farmer_region}\n"
                    f"📍 Куда: {to_region} ({port_name})\n"
                    f"🚚 Транспорт: {transport_name}\n"
                    f"👤 Фермер: {farmer_user.get('name', '')}\n"
                    f"☎️ {farmer_user.get('phone', '')}\n\n"
                    "Нажмите «ОТКЛИКНУТЬСЯ», если готовы везти."
                )

                keyboard = InlineKeyboardMarkup()
                keyboard.add(
                    InlineKeyboardButton(
                        "✅ ОТКЛИКНУТЬСЯ",
                        callback_data=f"logist_respond_farmer_request:{request_id}",
                    ),
                    InlineKeyboardButton(
                        "📋 ДЕТАЛИ",
                        callback_data=f"view_request:farmer:{request_id}",
                    ),
                )

                await bot.send_message(
                    logist_id, msg, reply_markup=keyboard, parse_mode="HTML"
                )
                logists_count += 1
            except Exception as e:
                logging.error(f"❌ Ошибка уведомления логиста {logist_id}: {e}")

    success_text = (
        "✅ <b>ЗАЯВКА НА ДОСТАВКУ СОЗДАНА!</b>\n\n"
        "━━━━━━━━━━━━━━━━━━━━━━\n"
        f"🎯 <b>ID:</b> #{request_id}\n"
        "📊 <b>Статус:</b> Ожидание откликов\n\n"
        f"🌾 {batch['culture']} - {batch['volume']} т\n"
        f"💰 {batch['price']:,} ₽/т • Итого: {batch['volume'] * batch['price']:,} ₽\n\n"
        f"📍 От: {farmer_region}\n"
        f"📍 Куда: {to_region} ({port_name})\n"
        f"🚚 Транспорт: {transport_name}\n"
        f"💳 Ожидаемая цена доставки: {data['desired_price']:,} ₽/т\n\n"
        f"📢 Уведомлено логистов: {logists_count}\n"
        "📢 Экспедиторы будут уведомлены после назначения логиста\n"
        "━━━━━━━━━━━━━━━━━━━━━━"
    )

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton("📬 МОИ ЗАЯВКИ", callback_data="farmer_my_requests_menu")
    )
    keyboard.add(
        InlineKeyboardButton("🏠 ГЛАВНОЕ МЕНЮ", callback_data="farmer_main_menu")
    )

    await callback.message.edit_text(
        success_text, reply_markup=keyboard, parse_mode="HTML"
    )
    await state.finish()
    await callback.answer("✅ Заявка создана!", show_alert=True)


# ═══════════════════════════════════════════════════════════════════════════
# ЭКСПЕДИТОР: ОТКЛИК НА ЗАЯВКУ ФЕРМЕРА
# ═══════════════════════════════════════════════════════════════════════════
@dp.callback_query_handler(
    lambda c: c.data.startswith("expeditor_respond_farmer_request:"), state="*"
)
async def expeditor_respond_farmer_request(
    callback: types.CallbackQuery, state: FSMContext
):
    """
    Экспедитор начинает отклик на заявку фермера:
    показывает краткие данные заявки и предлагает выбрать транспорт.
    """
    await state.finish()
    expeditor_id = callback.from_user.id

    # Проверяем роль
    if not is_expeditor_role((get_user_by_id(expeditor_id) or {}).get("role")):
        await callback.answer(
            "❌ Эта функция доступна только экспедиторам", show_alert=True
        )
        return

    # Парсим ID заявки
    try:
        request_ref = callback.data.split(":")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return

    _, request = find_farmer_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    request_owner_id = request.get("farmer_id")
    if same_id(request_owner_id, expeditor_id):
        await callback.answer(
            "❌ Нельзя откликнуться на собственную заявку", show_alert=True
        )
        return
    if not is_request_open_for_expeditor(request.get("status")):
        await callback.answer("❌ Заявка уже не принимает отклики", show_alert=True)
        return
    if has_assigned_expeditor(request):
        await callback.answer("❌ По заявке уже назначен экспедитор", show_alert=True)
        return
    if not has_assigned_logist(request):
        await callback.answer(
            "❌ Сначала должен быть назначен логист", show_alert=True
        )
        return

    # Проверяем, не откликался ли уже этот экспедитор
    expeditor_offers = ensure_farmer_expeditor_offer_ids(request)
    if any(
        same_id(o.get("expeditor_id"), expeditor_id)
        and normalize_transition_status(o.get("status") or "pending")
        not in {"rejected", "cancelled", "completed"}
        for o in expeditor_offers
        if isinstance(o, dict)
    ):
        await callback.answer("✅ Вы уже откликнулись на эту заявку", show_alert=True)
        return

    culture = request.get("culture", "Культура")
    volume = request.get("volume", 0)
