@dp.callback_query_handler(
    lambda c: c.data.startswith("expeditor_respond_transport:"), state="*"
)
async def expeditor_respond_transport(callback: types.CallbackQuery, state: FSMContext):
    """
    Экспедитор выбрал транспорт: сохраняем отклик в заявке и уведомляем фермера.
    """
    await state.finish()
    expeditor_id = callback.from_user.id

    # Проверяем роль
    if not is_expeditor_role((get_user_by_id(expeditor_id) or {}).get("role")):
        await callback.answer(
            "❌ Эта функция доступна только экспедиторам", show_alert=True
        )
        return

    # Парсим request_id и тип транспорта
    try:
        _, request_id_str, transport_code = callback.data.split(":", 2)
        request_id = int(request_id_str) if str(request_id_str).isdigit() else request_id_str
    except (ValueError, IndexError):
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return
    transport_map = {"rail": "ЖД", "grain": "Зерновоз", "truck": "Фура"}
    transport_type = transport_map.get(transport_code, transport_code)

    _, request = find_farmer_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    request_owner_id = request.get("farmer_id")
    if same_id(request_owner_id, expeditor_id):
        await callback.answer(
            "❌ Нельзя откликнуться на собственную заявку", show_alert=True
        )
        return
    if not is_request_open_for_expeditor(request.get("status")):
        await callback.answer("❌ Заявка уже не принимает отклики", show_alert=True)
        return
    if has_assigned_expeditor(request):
        await callback.answer("❌ По заявке уже назначен экспедитор", show_alert=True)
        return
    if not has_assigned_logist(request):
        await callback.answer(
            "❌ Сначала должен быть назначен логист", show_alert=True
        )
        return

    # Карточка экспедитора
    card = expeditor_cards.get(expeditor_id, {})
    exp_user = get_user_by_id(expeditor_id) or {}

    if not card and not exp_user:
        await callback.answer(
            "❌ Не найдены данные экспедитора (профиль/карточка)", show_alert=True
        )
        return

    # Инициализируем список откликов
    expeditor_offers = ensure_farmer_expeditor_offer_ids(request)

    # Блокируем повторный отклик
    if any(
        same_id(o.get("expeditor_id"), expeditor_id)
        and normalize_transition_status(o.get("status") or "pending")
        not in {"rejected", "cancelled", "completed"}
        for o in expeditor_offers
        if isinstance(o, dict)
    ):
        await callback.answer("✅ Вы уже откликнулись на эту заявку", show_alert=True)
        return

    # Достаём данные из карточки экспедитора (старая и новая структура)
    services = (
        card.get("services_text")
        or card.get("services")
        or card.get("description")
        or card.get("additional_info")
        or "Не указаны"
    )
    ports = card.get("ports", []) or []
    if isinstance(ports, str):
        ports = [p.strip() for p in ports.split(",") if p.strip()]
    regions = card.get("regions") or ", ".join(ports) or "Не указаны"
    experience = card.get("experience", "Не указан")
    description = card.get("description") or card.get("additional_info") or "Не указано"
    price_info = card.get("price_per_km") or card.get("dt_price") or 0
    company = (
        card.get("company")
        or exp_user.get("company_details")
        or exp_user.get("company_name")
        or exp_user.get("name")
        or "Не указана"
    )

    # Формируем полноразмерный оффер
    offer_data = {
        "id": max(
            (int(o.get("id")) for o in expeditor_offers if isinstance(o, dict) and str(o.get("id")).isdigit()),
            default=0,
        )
        + 1,
        "expeditor_id": expeditor_id,
        "expeditor_name": exp_user.get("name", "Неизвестно"),
        "expeditor_phone": exp_user.get("phone", "Не указан"),
        "expeditor_email": exp_user.get("email", "Не указан"),
        "company": company,
        "transport_type": transport_type,
        "services": services,
        "services_text": services,  # дублируем для совместимости
        "regions": regions,
        "ports": ports,
        "experience": experience,
        "additional_info": description,
        "price_info": price_info,
        "responded_at": datetime.now().strftime("%d.%m.%Y %H:%M"),
        "created_at": datetime.now().strftime("%d.%m.%Y %H:%M"),
        "status": "pending",
    }

    expeditor_offers.append(offer_data)
    request["expeditor_offers_count"] = len(expeditor_offers)

    save_data()
    logging.info(
        f"✅ Экспедитор {expeditor_id} откликнулся на заявку фермера #{request_id} транспортом {transport_type}"
    )

    # ─── Уведомляем фермера ────────────────────────────────────────
    farmer_id = request["farmer_id"]

    culture = request.get("culture", "Культура")
    volume = request.get("volume", 0)
    price_per_ton = request.get("price_per_ton", 0)
    desired_price = request.get("desired_price", 0)
    route_from = request.get("route_from", "Откуда")
    route_to = request.get("route_to", "Куда")

    msg = (
        "📞 <b>ЭКСПЕДИТОР ОТКЛИКНУЛСЯ НА ВАШУ ЗАЯВКУ!</b>\n\n"
        f"🚛 <b>Транспорт по этой заявке:</b> {transport_type}\n\n"
        f"👤 <b>Экспедитор:</b> {exp_user.get('name', 'Неизвестно')}\n"
        f"🏢 <b>Компания:</b> {company}\n"
        f"☎️ <code>{exp_user.get('phone', 'Не указан')}</code>\n"
        f"📧 <code>{exp_user.get('email', 'Не указан')}</code>\n\n"
        f"🛠 <b>Услуги:</b> {services}\n"
        f"⛴️ <b>Регионы/порты:</b> {regions}\n"
        f"💰 <b>Ставка (из карточки):</b> {price_info:,.2f}\n\n"
        f"📊 <b>Заявка #{request_id}:</b>\n"
        f"🌾 {culture} - {volume} т\n"
        f"📍 {route_from} → {route_to}\n"
        f"💰 {price_per_ton:,} ₽/т\n"
        f"💳 Ожидаемая цена доставки: {desired_price:,} ₽/т\n\n"
        f"Всего откликов экспедиторов: {request.get('expeditor_offers_count', 1)}\n\n"
        "Свяжитесь с экспедитором для обсуждения деталей или откройте список "
        "«Отклики экспедиторов», чтобы сравнить все варианты."
    )

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton(
            "📋 Посмотреть заявку", callback_data=f"view_request:farmer:{request_id}"
        )
    )

    try:
        await bot.send_message(farmer_id, msg, reply_markup=keyboard, parse_mode="HTML")
    except Exception as e:
        logging.error(f"❌ Ошибка уведомления фермера об отклике экспедитора: {e}")

    await callback.message.edit_text(
        "✅ <b>Ваш отклик отправлен фермеру!</b>\n\n"
        f"📦 Заявка #{request_id}\n"
        f"🚛 Транспорт: {transport_type}\n\n"
        "Фермер получил ваши контакты и описание услуг.\n"
        "Ожидайте связи.",
        parse_mode="HTML",
    )


@dp.callback_query_handler(
    lambda c: c.data.startswith("farmer_view_expeditor_offers:"), state="*"
)
async def farmer_view_expeditor_offers(callback: types.CallbackQuery):
    """Фермер смотрит все отклики экспедиторов по своей заявке."""
    try:
        request_ref = callback.data.split(":", 1)[1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return

    _, request = find_farmer_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    if has_assigned_expeditor(request):
        await callback.answer("❌ По заявке уже выбран экспедитор", show_alert=True)
        return
    farmer_id = request.get("farmer_id")
    if not same_id(callback.from_user.id, farmer_id):
        await callback.answer("❌ Это не ваша заявка", show_alert=True)
        return
    if not has_assigned_logist(request):
        await callback.answer(
            "❌ Сначала должен быть назначен логист по заявке", show_alert=True
        )
        return

    offers = ensure_farmer_expeditor_offer_ids(request)
    if not offers:
        await callback.answer("Пока нет откликов экспедиторов", show_alert=True)
        return

    text = (
        f"📄 <b>Отклики экспедиторов по заявке #{request_id}</b>\n\n"
        f"🌾 {request.get('culture','—')} • {request.get('volume',0):.0f} т\n"
        f"📍 {request.get('route_from','—')} → {request.get('route_to','—')}\n\n"
        f"Всего откликов: <b>{len(offers)}</b>\n\n"
        "Выберите отклик, чтобы посмотреть детали и при желании выбрать экспедитора:"
    )

    keyboard = InlineKeyboardMarkup(row_width=1)

    for idx, offer in enumerate(offers, 1):
        exp_id = offer.get("expeditor_id")
        offer_id = offer.get("id")
        if offer_id is None:
            continue
        exp_user = get_user_by_id(exp_id) or {}
        name = exp_user.get("name", "Экспедитор")
        company = (
            exp_user.get("company_details")
            or exp_user.get("company_name")
            or offer.get("company", "")
            or ""
        )
        transport = offer.get("transport_type", "Не указан")
        label = f"{idx}. {name}"
        if company:
            label += f" • {company}"
        label += f" • {transport}"

        keyboard.add(
            InlineKeyboardButton(
                label,
                callback_data=f"farmer_view_expeditor_offer:{request_id}:id_{offer_id}",
            )
        )

    keyboard.add(
        InlineKeyboardButton(
            "⬅️ Назад к заявке", callback_data=f"view_request:farmer:{request_id}"
        )
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


