# ФЕРМЕР: МОИ ЗАЯВКИ - просмотр списка заявок
# ═══════════════════════════════════════════════════════════════════════════
@dp.callback_query_handler(text="farmer_my_requests_menu", state="*")
async def farmer_my_requests_menu(callback: types.CallbackQuery, state: FSMContext):
    """МОИ ЗАЯВКИ - просмотр списка"""
    try:
        await state.finish()
        user_id = callback.from_user.id

        # Ищем заявки этого фермера
        my_requests = []
        seen_request_ids = set()
        for req in list(farmer_shipping_requests.values()) + list(
            farmer_logistics_requests.values()
        ):
            if not isinstance(req, dict):
                continue
            if not same_id(req.get("farmer_id"), user_id):
                continue
            req_id = req.get("id")
            dedup_key = str(req_id) if req_id is not None else str(id(req))
            if dedup_key in seen_request_ids:
                continue
            seen_request_ids.add(dedup_key)
            my_requests.append(req)

        if not my_requests:
            await callback.message.edit_text(
                "📬 <b>МОИ ЗАЯВКИ</b>\n\n" "❌ У вас нет заявок на доставку",
                reply_markup=InlineKeyboardMarkup().add(
                    InlineKeyboardButton(
                        "🏠 ГЛАВНОЕ МЕНЮ", callback_data="farmer_main_menu"
                    )
                ),
                parse_mode="HTML",
            )
            await callback.answer()
            return

        # Группируем по статусам
        active = [r for r in my_requests if is_request_open_for_offers(r.get("status"))]
        completed = [
            r
            for r in my_requests
            if normalize_transition_status(r.get("status")) == "completed"
        ]

        text = "📬 <b>МОИ ЗАЯВКИ</b>\n\n"
        text += f"🟢 <b>Активных:</b> {len(active)}\n"
        text += f"✅ <b>Завершённых:</b> {len(completed)}\n\n"

        keyboard = InlineKeyboardMarkup(row_width=1)

        if active:
            text += "━━━━━━ АКТИВНЫЕ ━━━━━━\n"
            for r in active:
                req_offers_count = count_logistic_offers_for_request(
                    r.get("id"), "farmer"
                )
                label = (
                    f"#{r.get('id')} • {r.get('culture', '—')} • {r.get('volume', 0)}т • "
                    f"{req_offers_count} откликов"
                )
                keyboard.add(
                    InlineKeyboardButton(
                        label, callback_data=f"farmer_request_view:{r.get('id')}"
                    )
                )

        if completed:
            text += "━━━━━ ЗАВЕРШЁННЫЕ ━━━━━\n"
            for r in completed:
                label = f"#{r.get('id')} • {r.get('culture', '—')} • {r.get('volume', 0)}т"
                keyboard.add(
                    InlineKeyboardButton(
                        label, callback_data=f"farmer_request_view:{r.get('id')}"
                    )
                )

        keyboard.add(
            InlineKeyboardButton("🏠 ГЛАВНОЕ МЕНЮ", callback_data="farmer_main_menu")
        )

        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        await callback.answer()

    except Exception as e:
        logging.error(f"❌ Ошибка в farmer_my_requests_menu: {e}")
        try:
            await callback.answer(f"⚠️ Ошибка: {str(e)[:50]}", show_alert=True)
        except Exception as answer_error:
            logging.debug(f"Не удалось отправить callback.answer в farmer_my_requests_menu: {answer_error}")


