@dp.callback_query_handler(
    lambda c: c.data.startswith("farmer_request_view:"), state="*"
)
async def farmer_request_view(callback: types.CallbackQuery, state: FSMContext):
    """Просмотр деталей заявки"""
    await state.finish()

    try:
        request_ref = callback.data.split(":")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return

    resolved_request_id, request = find_farmer_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    request_id = resolved_request_id

    user_id = callback.from_user.id

    if not same_id(request.get("farmer_id"), user_id):
        await callback.answer("❌ Это не ваша заявка", show_alert=True)
        return

    display_status = request.get("status", "unknown")
    display_id = request.get("id", request_id)
    offers_count = count_logistic_offers_for_request(display_id, "farmer")
    price_per_ton = safe_float(request.get("price_per_ton", 0), 0.0)
    total_sum = safe_float(request.get("total_sum", 0), 0.0)
    desired_price = safe_float(request.get("desired_price", 0), 0.0)

    text = (
        f"📋 <b>ЗАЯВКА #{display_id}</b>\n\n"
        "━━━━━━━━━━━━━━━━━━━━━━\n"
        f"<b>СТАТУС:</b> {display_status}\n\n"
        f"🌾 <b>Культура:</b> {request.get('culture', 'Не указана')}\n"
        f"📦 <b>Объём:</b> {request.get('volume', 0)} т\n"
        f"💰 <b>Цена:</b> {price_per_ton:,.0f} ₽/т\n"
        f"💵 <b>Итого:</b> {total_sum:,.0f} ₽\n\n"
        f"📍 <b>От:</b> {request.get('farmer_region', request.get('route_from', 'Не указан'))}\n"
        f" <b>Куда:</b> {request.get('port_to', request.get('route_to', 'Не указан'))}\n"
        f"🚚 <b>Транспорт:</b> {request.get('transport_type', 'Не указан')}\n"
        f"💳 <b>Цена доставки:</b> {desired_price:,.0f} ₽/т\n\n"
        f"📞 <b>Откликов:</b> {offers_count}\n"
        f"📅 <b>Создана:</b> {request.get('created_at', 'Не указана')}\n"
        "━━━━━━━━━━━━━━━━━━━━━━"
    )

    keyboard = InlineKeyboardMarkup(row_width=2)

    # Если есть отклики
    if offers_count > 0:
        keyboard.add(
            InlineKeyboardButton(
                f"📞 ОТКЛИКОВ: {offers_count}",
                callback_data=f"farmer_view_offers:{display_id}",
            )
        )
    linked_delivery = next(
        (
            d
            for d in deliveries.values()
            if isinstance(d, dict)
            and same_id(d.get("request_id"), display_id)
            and str(d.get("source") or "farmer").strip().lower() == "farmer"
            and same_id(d.get("farmer_id"), user_id)
            and normalize_transition_status(d.get("status")) != "cancelled"
        ),
        None,
    )
    if isinstance(linked_delivery, dict):
        delivery_id = linked_delivery.get("id")
        if delivery_id is not None:
            keyboard.add(
                InlineKeyboardButton(
                    f"📦 ДОСТАВКА #{delivery_id}",
                    callback_data=f"view_delivery_{delivery_id}",
                )
            )

    # ✅ ДОБАВЛЯЕМ КНОПКИ УПРАВЛЕНИЯ ЗАЯВКОЙ
    keyboard.add(
        InlineKeyboardButton(
            "✏️ Редактировать", callback_data=f"edit_request:{display_id}"
        ),
        InlineKeyboardButton(
            "🗑️ Удалить", callback_data=f"delete_request:{display_id}"
        ),
    )

    keyboard.add(
        InlineKeyboardButton("📬 МОИ ЗАЯВКИ", callback_data="farmer_my_requests_menu")
    )
    keyboard.add(
        InlineKeyboardButton("🏠 ГЛАВНОЕ МЕНЮ", callback_data="farmer_main_menu")
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


def get_choice_keyboard(field, request_id):
    keyboard = InlineKeyboardMarkup(row_width=2)
    if field == "culture":
        for option in CULTURES:
            keyboard.insert(
                InlineKeyboardButton(
                    option,
                    callback_data=f"edit_field_val:{field}:{option}:{request_id}",
                )
            )
    elif field == "transport_type":
        for t, emoji in TRANSPORT_TYPES.items():
            keyboard.insert(
                InlineKeyboardButton(
                    f"{emoji} {t}",
                    callback_data=f"edit_field_val:{field}:{t}:{request_id}",
                )
            )
    elif field == "port_to":
        for port in PORTS:
            keyboard.insert(
                InlineKeyboardButton(
                    port, callback_data=f"edit_field_val:{field}:{port}:{request_id}"
                )
            )
    keyboard.add(
        InlineKeyboardButton(
            "➕ Другое", callback_data=f"edit_field_custom:{field}:{request_id}"
        )
    )
    keyboard.add(
        InlineKeyboardButton("⬅️ Назад", callback_data=f"edit_request:{request_id}")
    )
    return keyboard


@dp.callback_query_handler(lambda c: c.data.startswith("edit_request:"), state="*")
async def edit_request_start(callback: types.CallbackQuery, state: FSMContext):
    request_ref = callback.data.split(":")[-1]
    request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    user_id = callback.from_user.id
    resolved_request_id, request = find_farmer_request_by_id(request_id)
    if not request or not same_id(request.get("farmer_id"), user_id):
        await callback.answer("❌ Заявка не найдена, либо не ваша", show_alert=True)
        return
    request_id = resolved_request_id
    await state.update_data(request_id=request_id)
    text = f"✏️ <b>Редактирование заявки #{request_id}</b>\nВыберите поле для изменения:"
    keyboard = InlineKeyboardMarkup(row_width=2)
    keyboard.add(
        InlineKeyboardButton(
            "🌾 Культура", callback_data=f"edit_req_field:culture:{request_id}"
        ),
        InlineKeyboardButton(
            "📦 Объём", callback_data=f"edit_req_field:volume:{request_id}"
        ),
        InlineKeyboardButton(
            "💰 Цена/т", callback_data=f"edit_req_field:price_per_ton:{request_id}"
        ),
        InlineKeyboardButton(
            "Порт", callback_data=f"edit_req_field:port_to:{request_id}"
        ),
        InlineKeyboardButton(
            "🚚 Транспорт", callback_data=f"edit_req_field:transport_type:{request_id}"
        ),
        InlineKeyboardButton(
            "🗑️ Отмена", callback_data=f"farmer_request_view:{request_id}"
        ),
    )
    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("edit_req_field:"), state="*")
async def edit_req_field_handler(callback: types.CallbackQuery, state: FSMContext):
    _, field, request_id = callback.data.split(":")
    request_id = int(request_id) if str(request_id).isdigit() else request_id
    await state.update_data(edit_field=field, request_id=request_id)
    if field in ["culture", "transport_type", "port_to"]:
        await callback.message.edit_text(
            f"📝 Выберите новое значение для <b>{field}</b>:",
            reply_markup=get_choice_keyboard(field, request_id),
            parse_mode="HTML",
        )
        await EditRequestStates.waiting_for_choice.set()
    elif field in ["volume", "price_per_ton"]:
        await callback.message.edit_text(
            f"📝 Введите новое значение для <b>{field}</b> (только число):",
            parse_mode="HTML",
        )
        await EditRequestStates.waiting_for_number.set()
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("edit_field_val:"),
    state=EditRequestStates.waiting_for_choice,
)
async def edit_field_value_choice(callback: types.CallbackQuery, state: FSMContext):
    _, field, value, request_id = callback.data.split(":")
