@dp.callback_query_handler(
    lambda c: c.data.startswith("logist_respond_farmer_request:"), state="*"
)
async def logist_respond_farmer_request(
    callback: types.CallbackQuery, state: FSMContext
):
    """Legacy callback: редирект в единый процесс make_offer для farmer-заявок."""
    await state.finish()

    logist_id = callback.from_user.id
    if not is_logistic_role((get_user_by_id(logist_id) or {}).get("role")):
        await callback.answer("❌ Доступно только логистам", show_alert=True)
        return

    try:
        request_ref = callback.data.split(":")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return

    _, request = find_farmer_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return

    if not is_request_open_for_offers(request.get("status")):
        await callback.answer("❌ Заявка уже не принимает отклики", show_alert=True)
        return

    callback.data = f"make_offer:farmer:{request_id}"
    await make_offer_start(callback, state)


