@dp.callback_query_handler(
    lambda c: c.data.startswith("select_expeditor_for_pull:"), state="*"
)
async def show_expeditors_for_pull(callback: types.CallbackQuery):
    """Показать список экспедиторов для выбора под пул (по порту и статусу пулла)."""
    try:
        pull_id = parse_callback_id(callback.data)
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return
    if pull_id is None:
        await callback.answer("❌ Ошибка данных пула", show_alert=True)
        return

    resolved_pull_id, pull = find_pull_by_id(pull_id)
    pull_id = resolved_pull_id if resolved_pull_id is not None else pull_id
    if not pull:
        await callback.answer("❌ Пулл не найден", show_alert=True)
        return
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    pull_owner_id = pull.get("exporter_id") or pull.get("creator_id")
    if not (user_role == "admin" or same_id(pull_owner_id, user_id)):
        await callback.answer("❌ Доступно только владельцу пула", show_alert=True)
        return

    status = normalize_transition_status(pull.get("status", ""))
    if status not in {"filled", "closed"}:
        await callback.answer("⚠️ Пулл ещё не собран", show_alert=True)
        return

    port = pull.get("port")
    if not port:
        await callback.answer("❌ У пула не указан порт", show_alert=True)
        return

    # Получаем список экспедиторов по порту из expeditor_cards
    available_expeditors = []

    for exp_id, card in expeditor_cards.items():
        if not isinstance(card, dict):
            continue
        user_data = get_user_by_id(exp_id) or {}
        if not user_data or not is_expeditor_role(user_data.get("role")):
            continue

        ports = card.get("ports", [])
        if isinstance(ports, str):
            ports = [p.strip() for p in ports.split(",") if p.strip()]

        if ports and port not in ports and "Все порты" not in ports:
            continue

        available_expeditors.append((exp_id, card, user_data))

    if not available_expeditors:
        await callback.answer(
            "⚠️ Нет доступных экспедиторов для этого порта\nПопробуйте позже",
            show_alert=True,
        )
        return

    text = f"📄 <b>Выбор экспедитора для пулла #{pull_id}</b>\n\n"
    text += (
        f"🌾 {pull.get('culture', 'Культура')} • {pull.get('target_volume', 0):.1f} т\n"
    )
    text += f"🚢 Порт: {port}\n\n"
    text += f"<b>Доступно экспедиторов: {len(available_expeditors)}</b>\n"

    keyboard = InlineKeyboardMarkup(row_width=1)

    for exp_id, exp_card, exp_user in available_expeditors:
        company = (
            exp_card.get("company")
            or exp_user.get("company_name")
            or exp_user.get("company_details")
            or exp_user.get("name")
            or "Экспедитор"
        )
        btn_text = f"📄 {company}"

        keyboard.add(
            InlineKeyboardButton(
                btn_text, callback_data=f"view_expeditor_card:{pull_id}:{exp_id}"
            )
        )

    keyboard.add(InlineKeyboardButton("❌ Отмена", callback_data="cancel_action"))

    await callback.message.edit_text(text, parse_mode="HTML", reply_markup=keyboard)
    await callback.answer()


