@dp.callback_query_handler(lambda c: c.data.startswith("confirmdeletepull_"), state="*")
async def deletepullconfirmed_callback(
    callback: types.CallbackQuery, state: FSMContext
):
    """Финальное удаление пула после подтверждения"""
    await state.finish()

    try:
        pullid = parse_callback_id(callback.data)
    except (IndexError, ValueError) as e:
        await callback.answer("❌ Ошибка: некорректный ID пула", show_alert=True)
        logging.error(f"Ошибка парсинга при подтверждении: {e}, data: {callback.data}")
        return
    if pullid is None:
        await callback.answer("❌ Ошибка: некорректный ID пула", show_alert=True)
        return

    userid = callback.from_user.id

    resolved_pull_id, pull = find_pull_by_id(pullid)
    pullid = resolved_pull_id if resolved_pull_id is not None else pullid

    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        return

    if not same_id(pull.get("exporter_id"), userid):
        await callback.answer(
            "❌ У вас нет прав на удаление этого пула", show_alert=True
        )
        return

    # Сохраняем данные для логирования
    pull_culture = pull.get("culture", "Н/Д")
    pull_volume = pull.get("target_volume", 0)
    pull_price = pull.get("price", 0)

    # Сохраняем ID партий участников, чтобы снять резерв после удаления пула.
    participant_batch_ids = set()
    participants_for_pull = (pullparticipants.get(pullid) or []) + (
        pullparticipants.get(str(pullid)) or []
    )
    for participant in participants_for_pull:
        if not isinstance(participant, dict):
            continue
        participant_batch_id = participant.get("batch_id")
        if participant_batch_id is None:
            continue
        participant_batch_ids.add(str(participant_batch_id))
    for raw_batch_id in pull.get("batch_ids", []):
        if raw_batch_id is None:
            continue
        participant_batch_ids.add(str(raw_batch_id))

    # ========== УДАЛЕНИЕ СВЯЗАННЫХ ДАННЫХ ==========

    # 1. Удаляем все матчи
    matches_to_delete = [
        mid
        for mid, m in matches.items()
        if same_id(m.get("pull_id"), pullid) or same_id(m.get("pullid"), pullid)
    ]
    for mid in matches_to_delete:
        del matches[mid]

    # 2. ✅ ИСПРАВЛЕНО: Получаем участников ИЗ ГЛОБАЛЬНОЙ ПЕРЕМЕННОЙ
    # Подсчитываем количество участников для логирования
    participants_count = 0
    if pullid in pullparticipants:
        participants_count += len(pullparticipants[pullid])
        del pullparticipants[pullid]
        logging.info(
            f"🗑️ Удалено {participants_count} участников из pullparticipants[{pullid}]"
        )

    if str(pullid) in pullparticipants:
        participants_count += len(pullparticipants[str(pullid)])
        del pullparticipants[str(pullid)]
        logging.info(
            f"🗑️ Удалено {participants_count} участников из pullparticipants[{str(pullid)}]"
        )

    # 3. ✅ ИСПРАВЛЕНО: Удаляем сам пул из pulls['pulls']
    all_pulls = pulls.get("pulls", {}) if isinstance(pulls, dict) else {}
    if pullid in all_pulls:
        del all_pulls[pullid]
    if str(pullid) in all_pulls:
        del all_pulls[str(pullid)]

    # 4. Сохраняем изменения
    save_pulls_to_pickle()

    # 4.1 Снимаем резерв с партий удалённого пула (кроме уже проданных).
    touched_batches = False
    for participant_batch_id in participant_batch_ids:
        _, batch_obj = find_batch_by_id(participant_batch_id)
        if not isinstance(batch_obj, dict):
            continue
        batch_status_norm = normalize_transition_status(batch_obj.get("status"))
        if batch_status_norm in {
            "completed",
            "sold",
            "продана",
            "завершена",
            "завершен",
            "завершено",
        }:
            continue
        if batch_status_norm != "active":
            batch_obj["status"] = "active"
            batch_obj["released_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            touched_batches = True
    if touched_batches:
        save_batches_to_pickle()

    # ========== СИНХРОНИЗАЦИЯ С GOOGLE SHEETS ==========
    if gs and gs.spreadsheet:
        try:
            worksheet = gs.spreadsheet.worksheet("Pulls")
            all_values = worksheet.get_all_values()

            rows_to_delete = []
            for i, row in enumerate(all_values[1:], start=2):
                if row and len(row) > 0:
                    try:
                        if int(row[0]) == pullid:
                            rows_to_delete.append(i)
                    except (ValueError, IndexError):
                        continue

            for row_num in reversed(rows_to_delete):
                worksheet.delete_rows(row_num)

            logging.info(f"Пул {pullid} удалён из Google Sheets")
        except Exception as e:
            logging.error(f"Ошибка удаления из Google Sheets: {e}")

    # ========== УВЕДОМЛЕНИЯ ==========

    # Уведомляем участников
    farmer_ids = pull.get("farmer_ids", [])
    for farmer_id in farmer_ids:
        try:
            await bot.send_message(
                farmer_id,
                f"<b>🗑 Пул №{pullid} был удалён</b>\n\n"
                "Экспортёр отменил пул:\n"
                f"🌾 {pull_culture}\n"
                f"📦 {pull_volume:.1f} т\n"
                f"💰 ₽{pull_price:,.0f}/т\n\n"
                'Ваша партия возвращена в статус "Активна"',
                parse_mode="HTML",
            )
        except Exception as e:
            logging.warning(f"⚠️ Уведомление фермеру {farmer_id}: {e}")

    # ✅ ДОБАВЛЕНА ОДНА СТРОКА - создание клавиатуры
    keyboard = InlineKeyboardMarkup().add(
        InlineKeyboardButton("⬅️ Назад", callback_data="back_to_pulls")
    )

    # Уведомляем экспортёра
    await callback.message.edit_text(
        "✅ <b>Пул удалён</b>\n\n"
        "🗑️ <b>Удалено:</b>\n"
        f"🌾 Культура: {pull_culture}\n"
        f"📦 Объём: {pull_volume:.1f} т\n"
        f"💰 Цена: ₽{pull_price:,.0f}/т\n"
        f"🆔 ID: {pullid}\n\n"
        f"🔔 Участников уведомлено: {len(farmer_ids)}\n"
        f"🗑️ Матчей удалено: {len(matches_to_delete)}",
        reply_markup=keyboard,
        parse_mode="HTML",
    )
    logging.info(
        f"✅ Пул {pullid} удалён пользователем {userid}. Участников: {participants_count}, матчей: {len(matches_to_delete)}"
    )

    await callback.answer("✅ Пул удалён")


# ==================== ОТМЕНА УДАЛЕНИЯ ====================
@dp.callback_query_handler(lambda c: c.data == "canceldeletepull", state="*")
async def canceldeletepull_callback(callback: types.CallbackQuery, state: FSMContext):
    """✅ Отмена процесса удаления пула - ИСПРАВЛЕНО"""

    # ✅ Получаем pull_id из state
    user_data = await state.get_data()
    pull_id = user_data.get("delete_pull_id")

    # ✅ Очищаем state
    await state.finish()

    # ✅ Если pull_id есть - возвращаемся к деталям пула
    if pull_id:
        all_pulls = pulls.get("pulls", {})
        pull = all_pulls.get(pull_id) or all_pulls.get(str(pull_id))

        if pull:
            # Показываем детали пула
            keyboard = InlineKeyboardMarkup(row_width=2)
            keyboard.add(
                InlineKeyboardButton(
                    "✏️ Редактировать", callback_data=f"editpull_{pull_id}"
                ),
                InlineKeyboardButton(
                    "🗑 Удалить", callback_data=f"deletepull_{pull_id}"
                ),
            )
            keyboard.add(
                InlineKeyboardButton("◀️ Назад", callback_data="back_to_my_pulls")
            )

            text = f"""📦 <b>Пул #{pull_id}</b>

❌ <i>Удаление отменено</i>

🌾 <b>Культура:</b> {pull.get('culture', '?')}
📦 <b>Объём:</b> {pull.get('current_volume', 0):.0f}/{pull.get('target_volume', 0):.0f} т
💰 <b>Цена FOB:</b> ₽{pull.get('price', 0):,.0f}/т
"""

            await callback.message.edit_text(
                text, reply_markup=keyboard, parse_mode="HTML"
            )
        else:
            await callback.message.edit_text("❌ Пул не найден")
    else:
        # Если нет pull_id - просто показываем сообщение
        await callback.message.edit_text("❌ Удаление отменено")

    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("close_pull:"), state="*")
async def close_pull_confirm(callback: types.CallbackQuery):
    """Подтверждение закрытия пула (НОВАЯ ФУНКЦИЯ)"""
    try:
        pull_id = int(callback.data.split(":")[1])
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка обработки данных", show_alert=True)
        return

    _, pull = find_pull_by_id(pull_id)
    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        return
    user_id = callback.from_user.id

    # Проверяем право на закрытие
    pull_owner_id = pull.get("exporter_id") or pull.get("creator_id")
    if not same_id(pull_owner_id, user_id):
        await callback.answer("⚠️ Только владелец может закрыть пул", show_alert=True)
        return

    current_volume = pull.get("current_volume", 0)
    target_volume = pull.get("target_volume", 0)
    percent = (current_volume / target_volume * 100) if target_volume > 0 else 0

    text = (
        f"🔒 <b>Закрыть пул #{pull_id}?</b>\n\n"
        f"🌾 {pull.get('culture', 'Культура')}\n"
        f"📊 Заполнено: {current_volume:.0f}/{target_volume:.0f} т ({percent:.0f}%)\n\n"
        "После закрытия:\n"
        "✅ Можно создать заявку на логистику\n"
        "❌ Фермеры не смогут присоединяться\n"
        "📢 Уведомления получат связанные участники\n\n"
        "Вы уверены?"
    )

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton(
            "✅ Да, закрыть", callback_data=f"confirmclosepull_{pull_id}"
        ),
        InlineKeyboardButton("❌ Отмена", callback_data=f"pull_logistics:{pull_id}"),
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("confirmclosepull_"), state="*")
async def confirm_close_pull_callback(callback_query: types.CallbackQuery):
    """Совместимость: закрытие пула через единый обработчик статусов."""
    try:
        pull_id = int(callback_query.data.split("_")[1])
    except (IndexError, ValueError):
        await callback_query.answer("❌ Ошибка: неверный ID пула", show_alert=True)
        return

    callback_query.data = f"confirm_pull_status:{pull_id}:closed"
    await confirm_pull_status(callback_query)


