@dp.callback_query_handler(lambda c: c.data == "get_partner_contacts", state="*")
async def get_partner_contacts_handler(callback: types.CallbackQuery):
    """Получение контактов партнёра по сделке"""
    user_id = callback.from_user.id
    partner_info = None

    # Ищем сделку, где пользователь участвует
    for deal_id, deal in deals.items():
        if not isinstance(deal, dict):
            continue
        if same_id(deal.get("logistic_id"), user_id):
            # Логист - получаем контакты экспортёра
            exporter_id = deal.get("exporter_id")
            exporter = get_user_by_id(exporter_id) or {}
            if exporter:
                partner_info = "📦 <b>Контакты экспортёра:</b>\n\n"
                partner_info += f"📝 {exporter.get('name', 'Неизвестно')}\n"
                partner_info += f"📱 {exporter.get('phone', 'Не указан')}\n"
                partner_info += f"📧 {exporter.get('email', 'Не указан')}\n"
                partner_info += f"📍 {exporter.get('region', 'Не указан')}\n"
                break

        elif same_id(deal.get("expeditor_id"), user_id):
            # Экспедитор - получаем контакты экспортёра
            exporter_id = deal.get("exporter_id")
            exporter = get_user_by_id(exporter_id) or {}
            if exporter:
                partner_info = "📦 <b>Контакты экспортёра:</b>\n\n"
                partner_info += f"📝 {exporter.get('name', 'Неизвестно')}\n"
                partner_info += f"📱 {exporter.get('phone', 'Не указан')}\n"
                partner_info += f"📧 {exporter.get('email', 'Не указан')}\n"
                partner_info += f"📍 {exporter.get('region', 'Не указан')}\n"
                break

    if not partner_info:
        await callback.answer("🤷‍♂️ Контакты не найдены", show_alert=True)
        return

    await callback.message.answer(partner_info, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("contact_partner:"), state="*")
async def contact_partner_by_deal(callback: types.CallbackQuery):
    """Показать контакты участников конкретной сделки."""
    deal_id = parse_callback_id(callback.data)
    if deal_id is None:
        await callback.answer("❌ Ошибка данных сделки", show_alert=True)
        return

    resolved_deal_id, deal = find_deal_by_id(deal_id)
    if not deal:
        await callback.answer("❌ Сделка не найдена", show_alert=True)
        return
    deal_id = resolved_deal_id
    user_id = callback.from_user.id
    farmer_ids = deal.get("farmer_ids", [])
    is_farmer_participant = any(same_id(user_id, farmer_id) for farmer_id in farmer_ids)
    role = (get_user_by_id(user_id) or {}).get("role")
    is_participant = (
        same_id(user_id, deal.get("exporter_id"))
        or is_farmer_participant
        or same_id(user_id, deal.get("logistic_id"))
        or same_id(user_id, deal.get("expeditor_id"))
    )
    if not (is_participant or role == "admin"):
        await callback.answer("❌ Нет доступа к контактам сделки", show_alert=True)
        return

    participant_ids = []
    if deal.get("exporter_id"):
        participant_ids.append(deal["exporter_id"])
    participant_ids.extend(deal.get("farmer_ids", []))
    if deal.get("logistic_id"):
        participant_ids.append(deal["logistic_id"])
    if deal.get("expeditor_id"):
        participant_ids.append(deal["expeditor_id"])

    partner_ids = [pid for pid in participant_ids if not same_id(pid, user_id)]
    if not partner_ids:
        await callback.answer("ℹ️ Партнёры пока не назначены", show_alert=True)
        return

    lines = [f"📞 <b>Контакты партнёров по сделке #{deal_id}</b>", ""]
    for pid in partner_ids:
        u = get_user_by_id(pid) or {}
        lines.append(
            f"👤 <b>{u.get('name', 'Неизвестно')}</b>\n"
            f"🎭 {u.get('role', '—')}\n"
            f"📱 <code>{u.get('phone', 'Не указан')}</code>\n"
            f"📧 {u.get('email', 'Не указан')}\n"
        )

    await callback.message.answer("\n".join(lines), parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("complete_deal:"), state="*")
async def complete_deal(callback: types.CallbackQuery):
    """Завершение сделки"""
    deal_id = parse_callback_id(callback.data)
