@dp.callback_query_handler(
    lambda c: c.data.startswith("confirm_complete_deal:"), state="*"
)
async def confirm_complete_deal(callback: types.CallbackQuery):
    """Подтверждение завершения сделки"""
    deal_id = parse_callback_id(callback.data)
    if deal_id is None:
        await callback.answer("❌ Ошибка данных сделки", show_alert=True)
        return

    resolved_deal_id, deal = find_deal_by_id(deal_id)
    if not deal:
        await callback.answer("❌ Сделка не найдена", show_alert=True)
        return
    deal_id = resolved_deal_id
    user_id = callback.from_user.id
    farmer_ids = deal.get("farmer_ids", [])
    can_complete = same_id(user_id, deal.get("exporter_id")) or any(
        same_id(user_id, farmer_id) for farmer_id in farmer_ids
    )
    if not can_complete:
        await callback.answer(
            "⚠️ Только участники сделки могут её завершить", show_alert=True
        )
        return
    if normalize_transition_status(deal.get("status")) in {"completed", "cancelled"}:
        await callback.answer("ℹ️ Сделка уже закрыта", show_alert=True)
        return

    deal["status"] = "completed"
    deal["completed_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    save_deals_to_pickle()
    await notify_deal_participants(deal_id, "✅ Сделка завершена!")

    await callback.message.edit_text(
        f"🎉 <b>Сделка #{deal_id} завершена!</b>\n\n"
        "Все участники уведомлены о завершении сделки.\n"
        "Спасибо за использование платформы Exportum!",
        parse_mode="HTML",
    )
    await callback.answer("✅ Сделка завершена")


