@dp.callback_query_handler(
    lambda c: c.data in ["cancel_complete_deal", "cancel_cancel_deal"], state="*"
)
async def cancel_deal_action(callback: types.CallbackQuery):
    """Отмена действия со сделкой"""
    await callback.message.edit_text("❌ Действие отменено")
    await callback.answer()


async def notify_deal_participants(deal_id: int, message: str):
    """Уведомление всех участников сделки"""
    _, deal = find_deal_by_id(deal_id)
    if not deal:
        return

    participants = []
    if deal.get("exporter_id"):
        participants.append(deal["exporter_id"])
    if deal.get("farmer_ids"):
        participants.extend(deal["farmer_ids"])
    if deal.get("logistic_id"):
        participants.append(deal["logistic_id"])
    if deal.get("expeditor_id"):
        participants.append(deal["expeditor_id"])
    seen_participants = set()
    for user_id in participants:
        if user_id is None:
            continue
        participant_key = str(user_id)
        if participant_key in seen_participants:
            continue
        seen_participants.add(participant_key)
        try:
            await bot.send_message(
                user_id,
                f"📋 <b>Уведомление по сделке #{deal_id}</b>\n\n{message}",
                parse_mode="HTML",
            )
            await asyncio.sleep(0.1)  # Задержка между отправками
        except Exception as e:
            logging.error(f"❌ Ошибка уведомления пользователя {user_id}: {e}")


@dp.callback_query_handler(lambda c: c.data.startswith("logistics:"), state="*")
async def deal_logistics(callback: types.CallbackQuery):
    """Управление логистикой для сделки"""
    deal_id = parse_callback_id(callback.data)
    if deal_id is None:
        await callback.answer("❌ Ошибка данных сделки", show_alert=True)
        return

    resolved_deal_id, deal = find_deal_by_id(deal_id)
    if not deal:
        await callback.answer("❌ Сделка не найдена", show_alert=True)
        return
    deal_id = resolved_deal_id

    text = f"🚚 <b>Логистика сделки #{deal_id}</b>\n\n"

    if deal.get("logistic_id"):
        logistic = get_user_by_id(deal["logistic_id"]) or {}
        if logistic:
            text += "✅ <b>Логист назначен:</b>\n"
            text += f"👤 {logistic.get('name', 'Неизвестно')}\n"
            text += f"🏢 {logistic.get('company_details', 'Не указана')}\n"
            text += f"📋 ИНН: <code>{logistic.get('inn', 'Не указан')}</code>\n"
            text += f"📋 ОГРН: <code>{logistic.get('ogrn', 'Не указан')}</code>\n"
            text += f"📱 {logistic.get('phone', 'Не указан')}\n"
            text += f"📧 {logistic.get('email', 'Не указан')}\n"
        else:
            text += "❌ Логист не найден в системе\n"
    else:
        text += "🤷‍♂️ <b>Логист не назначен</b>\n\n"
        text += "Для назначения логиста создайте заявку на логистику.\n"

    if deal.get("expeditor_id"):
        expeditor = get_user_by_id(deal["expeditor_id"]) or {}
        if expeditor:
            text += "\n✅ <b>Экспедитор назначен:</b>\n"
            text += f"👤 {expeditor.get('name', 'Неизвестно')}\n"
            text += f"🏢 {expeditor.get('company_details', 'Не указана')}\n"
            text += f"📋 ИНН: <code>{expeditor.get('inn', 'Не указан')}</code>\n"
            text += f"📋 ОГРН: <code>{expeditor.get('ogrn', 'Не указан')}</code>\n"
            text += f"📱 {expeditor.get('phone', 'Не указан')}\n"
            text += f"📧 {expeditor.get('email', 'Не указан')}\n"
        else:
            text += "\n❌ Экспедитор не найден в системе\n"
    else:
        text += "\n🤷‍♂️ <b>Экспедитор не назначен</b>\n\n"
        text += "Для назначения экспедитора создайте заявку на оформление документов.\n"

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton("◀️ Назад к сделке", callback_data=f"view_deal:{deal_id}")
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("pullparticipants:"), state="*")
async def show_pullparticipants(callback: types.CallbackQuery):
    """Показать участников пула с ДЕТАЛЬНОЙ бизнес-информацией"""
    try:
        pull_id = parse_callback_id(callback.data)
    except (IndexError, ValueError) as e:
        logging.error(f"❌ Ошибка парсинга callback_data: {e}")
        await callback.answer("❌ Ошибка обработки данных", show_alert=True)
        return
    if pull_id is None:
        await callback.answer("❌ Ошибка данных пула", show_alert=True)
        return

    all_pulls = pulls.get("pulls", {})
    # Универсальный get для ключа
    pull = (
        all_pulls.get(pull_id)
        or all_pulls.get(str(pull_id))
        or all_pulls.get(
            int(pull_id) if isinstance(pull_id, str) and pull_id.isdigit() else None
        )
    )

    if not pull:
        logging.warning(
            f"⚠️ Пул {pull_id} не найден. Доступные ключи: {list(all_pulls.keys())}"
        )
        await callback.answer("❌ Пул не найден", show_alert=True)
        return

    participants = (
        pullparticipants.get(pull_id)
        or pullparticipants.get(str(pull_id))
        or pullparticipants.get(
            int(pull_id) if isinstance(pull_id, str) and pull_id.isdigit() else None
        )
        or []
    )
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    pull_owner_id = pull.get("exporter_id") or pull.get("creator_id")
    is_participant = any(
        isinstance(p, dict) and same_id(p.get("farmer_id"), user_id)
        for p in participants
    )
    if not (user_role == "admin" or same_id(pull_owner_id, user_id) or is_participant):
        await callback.answer("❌ Нет доступа к участникам этого пула", show_alert=True)
        return
    can_view_full_contacts = user_role == "admin" or same_id(pull_owner_id, user_id)

    text = f"👥 <b>Участники пула #{pull.get('id', pull_id)}</b>\n\n"
    text += f"🌾 {pull.get('culture', '?')} • {pull.get('target_volume', 0)} т\n\n"

    if not participants:
        text += "🤷‍♂️ У пула пока нет участников"
    else:
        total_participant_volume = 0
        for i, participant in enumerate(participants, 1):
            farmer_id = participant.get("farmer_id")
            farmer = get_user_by_id(farmer_id) or {}
            batch_id = participant.get("batch_id")
            volume = participant.get("volume", 0)
            total_participant_volume += volume

            farmer_name = farmer.get("name", "Неизвестно")
            farmer_region = farmer.get("region", "Не указан")
            farmer_phone = farmer.get("phone", "Не указан")
            farmer_company = (
                farmer.get("company")
                or farmer.get("company_name")
                or farmer.get("company_details")
                or "Не указана"
            )
            batch_obj = None

            # Пробуем найти объект партии для расширенной информации
            all_user_batches = batches.get(farmer_id, [])
            for b in all_user_batches:
                if same_id(b.get("id"), batch_id):
                    batch_obj = b
                    break

            batch_culture = (
                batch_obj.get("culture") if batch_obj else pull.get("culture", "?")
            )
            batch_status = batch_obj.get("status") if batch_obj else "Не указано"
            batch_price = batch_obj.get("price") if batch_obj else "?"
            batch_storage = batch_obj.get("storage") if batch_obj else "?"

            text += (
                f"{i}. 👤 <b>{farmer_name}</b>\n"
                f"   🏢 Компания: {farmer_company}\n"
                f"   📍 Регион: {farmer_region}\n"
                f"   📦 Партия #{batch_id}: {volume} т | {batch_culture}\n"
                f"   💰 Цена: {batch_price} ₽/т\n"
                f"   🏷 Статус: {batch_status}\n"
                f"   🏬 Хранение: {batch_storage}\n\n"
            )
            if can_view_full_contacts or same_id(farmer_id, user_id):
                text += f"   📞 Телефон: <code>{farmer_phone}</code>\n\n"
            else:
                text += "   📞 Телефон: <i>скрыт</i>\n\n"

        target_volume = pull.get("target_volume", 1)
        fill_percentage = (
            (total_participant_volume / target_volume * 100) if target_volume > 0 else 0
        )
        text += f"📊 <b>Итого:</b> {total_participant_volume:.0f}/{target_volume:.0f} т ({fill_percentage:.1f}%)"

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton("◀️ Назад к пулу", callback_data=f"view_pull:{pull_id}")
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("pull_logistics:"), state="*")
async def pull_logistics_menu(callback: types.CallbackQuery):
    """Меню логистики для пула"""
    try:
        pull_id = parse_callback_id(callback.data)
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка обработки данных", show_alert=True)
        return
    if pull_id is None:
        await callback.answer("❌ Ошибка данных пула", show_alert=True)
        return

    _, pull = find_pull_by_id(pull_id)
    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        return
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    pull_owner_id = pull.get("exporter_id") or pull.get("creator_id")
    if not (user_role == "admin" or same_id(pull_owner_id, user_id)):
        await callback.answer("❌ Нет доступа к логистике этого пула", show_alert=True)
        return

    # ✅ ПРОВЕРКА: Пул должен быть готов для логистики
    status = pull.get("status", "active")
    status_norm = normalize_transition_status(status)
    current_volume = pull.get("current_volume", 0)
    target_volume = pull.get("target_volume", 0)

    if status_norm in {"cancelled", "sold", "completed"}:
        await callback.answer(
            "❌ Для закрытого/завершённого пула нельзя создавать новую заявку",
            show_alert=True,
        )
        return

    is_closed = status_norm == "closed"
    is_full = current_volume >= target_volume and target_volume > 0
    is_ready = is_closed or is_full

    # Формируем текст
    text = f"🚚 <b>Логистика пула #{pull_id}</b>\n\n"
    text += (
        f"🌾 {pull.get('culture', 'Культура')} • "
        f"{safe_float(pull.get('target_volume', 0), 0.0):.0f} т • "
        f"{pull.get('port', 'Не указан')}\n"
    )
    text += f"📊 Заполнено: {current_volume}/{target_volume} т ({(current_volume/target_volume*100) if target_volume > 0 else 0:.0f}%)\n"
    text += f"🔒 Статус: {'Закрыт' if status_norm == 'closed' else 'Активен'}\n\n"

    keyboard = InlineKeyboardMarkup(row_width=1)

    if is_ready:
        # ✅ Пул готов - показываем кнопку создания заявки
        text += "✅ <b>Пул готов для создания заявки на логистику</b>"
        keyboard.add(
            InlineKeyboardButton(
                "📋 Создать заявку на логистику",
                callback_data=f"create_shipping:{pull_id}",
            )
        )
    else:
        # ❌ Пул не готов - показываем предупреждение
        text += "⏳ <b>Пул ещё не готов для логистики</b>\n\n"
        text += "Для создания заявки необходимо:\n"
        text += "• Закрыть пул вручную\n"
        text += "• Или заполнить на 100%"
        keyboard.add(
            InlineKeyboardButton(
                "🔒 Закрыть пул", callback_data=f"close_pull:{pull_id}"
            )
        )

    # Общие кнопки (всегда доступны)
    keyboard.add(
        InlineKeyboardButton(
            "👀 Активные заявки", callback_data=f"view_shipping_requests:{pull_id}"
        ),
        InlineKeyboardButton(
            "📞 Контакты логистов", callback_data="view_logistics_contacts"
        ),
    )
    keyboard.add(
        InlineKeyboardButton("◀️ Назад к пулу", callback_data=f"view_pull:{pull_id}")
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("create_shipping:"), state="*")
async def create_shipping_from_pull(callback: types.CallbackQuery, state: FSMContext):
    """Создание заявки на логистику из пула"""
    try:
        pull_id = int(callback.data.split(":")[1])
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка обработки данных", show_alert=True)
        return

    _, pull = find_pull_by_id(pull_id)
    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        return
    user_id = callback.from_user.id
    role = (get_user_by_id(user_id) or {}).get("role")
    if not (
        role == "admin"
        or same_id(pull.get("exporter_id"), user_id)
        or same_id(pull.get("creator_id"), user_id)
    ):
        await callback.answer("❌ Нет доступа к этому пулу", show_alert=True)
        return

    # ✅ ДВОЙНАЯ ПРОВЕРКА: Пул должен быть готов
    status = pull.get("status", "active")
    status_norm = normalize_transition_status(status)
    current_volume = pull.get("current_volume", 0)
    target_volume = pull.get("target_volume", 0)

    is_closed = status_norm == "closed"
    is_full = current_volume >= target_volume and target_volume > 0

    if not (is_closed or is_full):
        # ❌ Пул не готов - отклоняем создание заявки
        await callback.answer(
            "❌ Пул не готов для логистики!\n"
            f"Заполнено: {current_volume}/{target_volume} т\n"
            f"Статус: {status}",
            show_alert=True,
        )
        return

    pull_owner_id = pull.get("exporter_id") or pull.get("creator_id")
    has_open_request_for_pull = any(
        isinstance(req, dict)
        and same_id(req.get("pull_id"), pull_id)
        and (pull_owner_id is None or same_id(req.get("exporter_id"), pull_owner_id))
        and str(req.get("source") or "").strip().lower() in {"", "exporter"}
        and normalize_transition_status(req.get("status")) not in {"completed", "cancelled", "rejected"}
        for req in shipping_requests.values()
    )
    if has_open_request_for_pull:
        await callback.answer(
            "❌ По этому пулу уже есть активная заявка на логистику",
            show_alert=True,
        )
        return

    # ✅ Пул готов - продолжаем создание заявки
    await state.update_data(pull_id=pull_id)

    await callback.message.edit_text(
        f"🚚 <b>Заявка на логистику для пула #{pull_id}</b>\n\n"
        f"🌾 {pull.get('culture', '')} • {pull.get('current_volume', 0):.0f} т • {pull.get('port', '')}\n\n"
        "<b>Шаг 1 из 5</b>\n\n"
        "Введите пункт отправки (город/регион):",
        parse_mode="HTML",
    )

    await ShippingRequestStatesGroup.route_from.set()
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data == "view_logistics_contacts", state="*")
async def view_logistics_contacts(callback: types.CallbackQuery):
    """Показать контакты логистов с реквизитами"""
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if not (user_role == "admin" or user_role == "exporter"):
        await callback.answer("❌ Нет доступа к разделу", show_alert=True)
        return

    logistics_users = [user for user in users.values() if is_logistic_role(user.get("role"))]

    if not logistics_users:
        await callback.answer("🤷‍♂️ В системе пока нет логистов", show_alert=True)
        return

    text = "<b>🚚 ЛОГИСТЫ НА ПЛАТФОРМЕ</b>\n\n"

    for i, logistic in enumerate(logistics_users[:10], 1):
        name = logistic.get("name", "Неизвестно")
        phone = logistic.get("phone", "Не указан")
        email = logistic.get("email", "Не указан")
        region = logistic.get("region", "Не указан")

        inn = logistic.get("inn", "Не указан")
        ogrn = logistic.get("ogrn", "Не указан")
        company = logistic.get("company_details", "Не указана")

        text += f"{i}. 👤 <b>{name}</b>\n"
        text += f"   🏢 {company}\n"
        text += f"   📋 ИНН: <code>{inn}</code>\n"
        text += f"   📋 ОГРН: <code>{ogrn}</code>\n"
        text += f"   📱 <code>{phone}</code>\n"

        if email != "Не указан":
            text += f"   📧 <code>{email}</code>\n"

        text += f"   📍 {region}\n\n"

    if len(logistics_users) > 10:
        text += f"\n<i>ℹ️ Ещё {len(logistics_users) - 10} логистов на платформе</i>"

    text += "\n\n💡 <b>Свяжитесь с логистами для обсуждения условий перевозки.</b>"

    keyboard = InlineKeyboardMarkup()
    keyboard.add(InlineKeyboardButton("⬅️ Назад", callback_data="back_to_main"))

    await callback.message.edit_text(text, parse_mode="HTML", reply_markup=keyboard)
    await callback.answer()


@dp.message_handler(
    lambda m: m.text in ["🚚 Моя карточка", "🚛 Моя карточка"], state="*"
)
async def show_logistics_card(message: types.Message):
    """Показать карточку логиста/экспедитора"""
    user_id = message.from_user.id

    if not get_user_by_id(user_id):
        await message.answer(
            "❌ Пользователь не найден. Пройдите регистрацию командой /start"
        )
        return

    user = get_user_by_id(user_id) or {}
    role = user.get("role")

    if not (is_logistic_role(role) or is_expeditor_role(role)):
        await message.answer("❌ Эта функция доступна только логистам и экспедиторам")
        return

    # Формируем карточку
    role_emoji = "🚚" if is_logistic_role(role) else "🚛"
    role_name = "Логист" if is_logistic_role(role) else "Экспедитор"

    text = f"{role_emoji} <b>Моя карточка ({role_name})</b>\n\n"
    text += f"👤 Имя: {user.get('name', 'Не указано')}\n"
    text += f"📞 Телефон: <code>{user.get('phone', 'Не указан')}</code>\n"
    text += f"📧 Email: {user.get('email', 'Не указан')}\n"
    text += f"📍 Регион: {user.get('region', 'Не указан')}\n\n"

    if user.get("inn"):
        text += f"🏢 ИНН: <code>{user['inn']}</code>\n"

    if user.get("company_details"):
        text += f"📋 О компании:\n{user['company_details'][:300]}\n\n"

    # Статистика
    if is_logistic_role(role):
        # Считаем заявки логиста по всем источникам
        logist_assigned_requests = [
            req
            for req in shipping_requests.values()
            if same_id(get_assigned_logist_id(req), user_id)
        ]
        logist_assigned_requests.extend(
            [
                req
                for req in farmer_logistics_requests.values()
                if same_id(get_assigned_logist_id(req), user_id)
            ]
        )
        logist_assigned_requests.extend(
            [
                req
                for req in logistics_requests.values()
                if same_id(get_assigned_logist_id(req), user_id)
            ]
        )
        active_requests = [
            req
            for req in logist_assigned_requests
            if normalize_transition_status(req.get("status"))
            not in {"completed", "cancelled", "rejected"}
        ]
        text += "📊 <b>Статистика:</b>\n"
        text += f"  • Всего заявок: {len(logist_assigned_requests)}\n"
        text += f"   • Активных: {len(active_requests)}\n"
    else:  # expeditor
        # Статистика экспедитора
        my_request_offers = [
            o
            for o in expeditor_request_offers.values()
            if isinstance(o, dict) and same_id(o.get("expeditor_id"), user_id)
        ]
        my_pull_offers = [
            o
            for o in expeditor_pull_offers.values()
            if isinstance(o, dict) and same_id(o.get("expeditor_id"), user_id)
        ]
        my_deliveries = [
            d
            for d in deliveries.values()
            if isinstance(d, dict) and same_id(get_assigned_expeditor_id(d), user_id)
        ]
        active_request_offers = sum(
            1
            for o in my_request_offers
            if normalize_transition_status(o.get("status") or "pending")
            in {"pending", "active", "accepted", "assigned", "in_progress"}
        )
        active_pull_offers = sum(
            1
            for o in my_pull_offers
            if normalize_transition_status(o.get("status") or "pending")
            in {"pending", "active", "accepted", "assigned", "in_progress"}
        )
        in_progress_deliveries = sum(
            1
            for d in my_deliveries
            if normalize_transition_status(d.get("status")) in {"in_progress", "expeditor_selected"}
        )
        completed_deliveries = sum(
            1
            for d in my_deliveries
            if normalize_transition_status(d.get("status")) == "completed"
        )
        text += "📊 <b>Статистика:</b>\n"
        text += f"  • Офферов по заявкам: {len(my_request_offers)}\n"
        text += f"  • Офферов по пулам: {len(my_pull_offers)}\n"
        text += f"  • Активных офферов: {active_request_offers + active_pull_offers}\n"
        text += f"  • Доставок в работе: {in_progress_deliveries}\n"
        text += f"  • Завершённых доставок: {completed_deliveries}\n"

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton("✏️ Редактировать профиль", callback_data="edit_profile")
    )

    await message.answer(text, parse_mode="HTML", reply_markup=keyboard)


@dp.message_handler(lambda m: m.text == "🚚 Активные заявки", state="*")
async def show_active_requests(message: types.Message, state: FSMContext):
    """Показать активные заявки на доставку - ОБЪЕДИНЁННО для логиста/экспортёра/экспедитора"""
    await state.finish()
    user_id = message.from_user.id

    if not get_user_by_id(user_id):
        await message.answer(
            "❌ Пользователь не найден. Пройдите регистрацию командой /start"
        )
        return

    user = get_user_by_id(user_id) or {}
    role = user.get("role")

    # ─────────────────────────────────────────────────────────
    # 👇 ВЕТКА ЛОГИСТА
    # ─────────────────────────────────────────────────────────
    if is_logistic_role(role):
        all_requests = []
        exporter_count = 0
        farmer_count = 0
        logistics_count = 0
        seen_exporter_request_ids = set()
        seen_farmer_request_ids = set()
        seen_logistics_request_ids = set()

        # Заявки от экспортёров (shipping_requests)
        for req_id, req in shipping_requests.items():
            if not isinstance(req, dict):
                continue
            status = req.get("status", "pending")
            assigned_logist = get_assigned_logist_id(req)
            # Показываем только свободные заявки в открытых статусах
            if not is_request_open_for_offers(status) or assigned_logist:
                continue
            canonical_id = req.get("id", req_id)
            canonical_key = str(canonical_id)
            if canonical_key in seen_exporter_request_ids:
                continue
            seen_exporter_request_ids.add(canonical_key)

            all_requests.append(
                {
                    "id": canonical_id,
                    "source": "exporter",
                    "culture": req.get("culture", "—"),
                    "volume": req.get("volume", 0) or 0,
                    "route_from": req.get("route_from") or req.get("from_city", "—"),
                    "route_to": req.get("route_to") or req.get("to_city", "—"),
                }
            )
            exporter_count += 1

        # Заявки от фермеров (farmer_shipping_requests + farmer_logistics_requests)
        for req_id, req in farmer_shipping_requests.items():
            if not isinstance(req, dict):
                continue
            status = req.get("status", "active")
            if not is_request_open_for_offers(status):
                continue
            canonical_id = req.get("id", req_id)
            canonical_key = str(canonical_id)
            if canonical_key in seen_farmer_request_ids:
                continue
            seen_farmer_request_ids.add(canonical_key)

            all_requests.append(
                {
                    "id": canonical_id,
                    "source": "farmer",
                    "culture": req.get("culture", "—"),
                    "volume": req.get("volume", 0) or 0,
                    "route_from": req.get("route_from", "—"),
                    "route_to": req.get("route_to", "—"),
                }
            )
            farmer_count += 1

        for req_id, req in farmer_logistics_requests.items():
            if not isinstance(req, dict):
                continue
            status = req.get("status", "active")
            if not is_request_open_for_offers(status):
                continue
            canonical_id = req.get("id", req_id)
            canonical_key = str(canonical_id)
            if canonical_key in seen_farmer_request_ids:
                continue
            seen_farmer_request_ids.add(canonical_key)

            all_requests.append(
                {
                    "id": canonical_id,
                    "source": "farmer",
                    "culture": req.get("culture", "—"),
                    "volume": req.get("volume", 0) or 0,
                    "route_from": req.get("route_from", "—"),
                    "route_to": req.get("route_to", "—"),
                }
            )
            farmer_count += 1

        # Заявки логистики экспортёров (logistics_requests)
        for req_id, req in logistics_requests.items():
            if not isinstance(req, dict):
                continue
            status = req.get("status", "active")
            assigned_logist = get_assigned_logist_id(req)
            if not is_request_open_for_offers(status) or assigned_logist:
                continue
            canonical_id = req.get("id", req_id)
            canonical_key = str(canonical_id)
            if canonical_key in seen_logistics_request_ids:
                continue
            seen_logistics_request_ids.add(canonical_key)

            all_requests.append(
                {
                    "id": canonical_id,
                    "source": "logistics",
                    "culture": req.get("culture", "—"),
                    "volume": req.get("volume", 0) or 0,
                    "route_from": req.get("route_from") or req.get("from_city", "—"),
                    "route_to": req.get("route_to") or req.get("to_city", "—"),
                }
            )
            logistics_count += 1

        total = len(all_requests)

        if not total:
            await message.answer(
                "🚚 <b>Активные заявки</b>\n\n"
                "❌ На данный момент нет активных заявок.\n\n"
                "Как только экспортёры или фермеры создадут заявки на доставку, "
                "они появятся здесь, и вы получите уведомление.",
                reply_markup=logistic_keyboard(),
                parse_mode="HTML",
            )
            return

        text = (
            "🚚 <b>Активные заявки</b>\n\n"
            f"📋 Всего заявок: <b>{total}</b>\n"
            f"🚛 От экспортёров: <b>{exporter_count}</b>\n"
            f"🌾 От фермеров: <b>{farmer_count}</b>\n"
            f"📦 Логистические заявки экспортёров: <b>{logistics_count}</b>\n\n"
            "Выберите заявку для просмотра деталей и создания предложения:"
        )

        keyboard = InlineKeyboardMarkup(row_width=1)

        for req in all_requests:
            req_source = req.get("source")
            if req_source == "exporter":
                emoji = "🚛"
            elif req_source == "farmer":
                emoji = "🌾"
            else:
                emoji = "📦"
            label = (
                f"{emoji} {req['culture']} • {req['volume']:.0f}т "
                f"({req['route_from']}→{req['route_to']})"
            )
            if req_source == "logistics":
                keyboard.add(
                    InlineKeyboardButton(
                        label, callback_data=f"view_logistics_req:{req['id']}"
                    )
                )
            else:
                keyboard.add(
                    InlineKeyboardButton(
                        label,
                        callback_data=f"view_request:{req_source}:{req['id']}",
                    )
                )

        await message.answer(text, reply_markup=keyboard, parse_mode="HTML")
        return

    # ─────────────────────────────────────────────────────────
    # 👇 ВЕТКИ ЭКСПОРТЁРА / ЭКСПЕДИТОРА — БЕЗ ИЗМЕНЕНИЙ
    # ─────────────────────────────────────────────────────────
    if role == "exporter":
        user_requests = []
        seen_request_ids = set()
        for req_id, req in shipping_requests.items():
            if not isinstance(req, dict):
                continue
            if not same_id(req.get("exporter_id"), user_id):
                continue
            canonical_id = req.get("id", req_id)
            canonical_key = f"exporter:{canonical_id}"
            if canonical_key in seen_request_ids:
                continue
            seen_request_ids.add(canonical_key)
