# ЛОГИСТ: FSM СОЗДАНИЯ ПРЕДЛОЖЕНИЯ
# ============================================================================
@dp.callback_query_handler(lambda c: c.data.startswith("make_offer:"), state="*")
async def make_offer_start(callback: types.CallbackQuery, state: FSMContext):
    """Начало создания предложения логистом"""
    await state.finish()

    user_id = callback.from_user.id

    # Проверяем, что это логист
    if not is_logistic_role((get_user_by_id(user_id) or {}).get("role")):
        await callback.answer(
            "❌ Эта функция доступна только логистам", show_alert=True
        )
        return

    try:
        parts = callback.data.split(":")
        source = parts[1]  # exporter или farmer
        if source == "logistic":
            source = "logistics"
        req_id_raw = parts[2]
        req_id = int(req_id_raw) if str(req_id_raw).isdigit() else req_id_raw

        logging.info(f"✅ HANDLER TRIGGERED: source={source}, req_id={req_id}")
    except (IndexError, ValueError) as e:
        logging.error(f"❌ PARSE ERROR: {e}, data={callback.data}")
        await callback.answer("❌ Ошибка обработки данных", show_alert=True)
        return

    if source not in {"exporter", "farmer", "logistics"}:
        await callback.answer("❌ Неподдерживаемый источник заявки", show_alert=True)
        return

    # ПРОВЕРЯЕМ ЗАЯВКУ в нужном словаре
    if source == "exporter":
        resolved_req_id, request = find_shipping_request_by_id(req_id)
        if not request:
            logging.error(f"❌ REQUEST NOT FOUND (exporter): {req_id}")
            await callback.answer("❌ Заявка не найдена", show_alert=True)
            return
        req_id = resolved_req_id
    elif source == "logistics":
        request = logistics_requests.get(req_id) or logistics_requests.get(str(req_id))
        if not isinstance(request, dict):
            logging.error(f"❌ REQUEST NOT FOUND (logistics): {req_id}")
            await callback.answer("❌ Заявка не найдена", show_alert=True)
            return
        req_id = request.get("id", req_id)
    else:
        resolved_req_id, request = find_farmer_request_by_id(req_id)
        if not request:
            logging.error(f"❌ REQUEST NOT FOUND (farmer): {req_id}")
            await callback.answer("❌ Заявка не найдена", show_alert=True)
            return
        req_id = resolved_req_id

    request_owner_id = (
        request.get("customer_id")
        or request.get("created_by")
        or request.get("exporter_id")
        or request.get("farmer_id")
        or request.get("logist_id")
    )
    if same_id(request_owner_id, user_id):
        await callback.answer(
            "❌ Нельзя откликнуться на собственную заявку", show_alert=True
        )
        return

    if not is_request_open_for_offers(request.get("status")):
        await callback.answer("❌ Заявка уже не принимает отклики", show_alert=True)
        return
    if get_assigned_logist_id(request):
        await callback.answer("❌ По заявке уже назначен логист", show_alert=True)
        return

    # Проверяем, что логист ещё не делал оффер по этой заявке
    closed_statuses = {
        "cancelled",
        "canceled",
        "rejected",
        "completed",
        "filled",
        "sold",
        "closed",
        "delivered",
    }
    existing_offer = any(
        logistic_offer_matches_request(o, req_id, source)
        and same_id((o.get("logist_id") or o.get("logistic_id")), user_id)
        and normalize_transition_status(o.get("status")) not in closed_statuses
        for o in logistic_offers.values()
    )

    if existing_offer:
        logging.warning(
            f"⚠️ DUPLICATE OFFER: user {user_id} already has offer for request {req_id}"
        )
        await callback.answer(
            "❌ Вы уже сделали предложение по этой заявке", show_alert=True
        )
        return

    # Сохраняем ID заявки и источник
    await state.update_data(request_id=req_id, source=source)

    # Информация о заявке
    pull_id = request.get("pull_id")
    all_pulls = pulls.get("pulls", {})
    pull_info = all_pulls.get(pull_id, {}) if pull_id is not None else {}

    expected_price = request.get("desired_price", "Не указана")

    route_from = request.get("route_from") or request.get("from_city") or "—"
    route_to = request.get("route_to") or request.get("to_city") or "—"

    text = f"""✅ <b>СОЗДАНИЕ ПРЕДЛОЖЕНИЯ</b>

📦 Заявка #{req_id}
🌾 Культура: {pull_info.get('culture', request.get('culture', 'Не указана'))}
📊 Объём: {request.get('volume', 0):.1f} т
📍 Маршрут: {route_from} → {route_to}
💰 Ожидаемая цена: <code>{expected_price}</code> ₽/т

━━━━━━━━━━━━━━━━━━━━

<b>Шаг 1/4: Выберите тип транспорта</b>"""

    keyboard = InlineKeyboardMarkup(row_width=2)

    vehicles = [
        ("🚂 ЖД", "vehicle_wagon"),
        ("🚚 Зерновоз", "vehicle_grain"),
        ("🚛 Фура", "vehicle_truck"),
    ]

    for label, cb in vehicles:
        keyboard.add(InlineKeyboardButton(label, callback_data=cb))

    keyboard.add(InlineKeyboardButton("❌ Отмена", callback_data="cancel_offer"))

    try:
        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        logging.info(f"✅ MESSAGE EDITED for request {req_id}")
    except Exception as e:
        logging.error(f"❌ EDIT ERROR: {e}")
        await callback.message.answer(text, reply_markup=keyboard, parse_mode="HTML")

    await LogisticOfferStatesGroup.vehicle_type.set()
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("vehicle_"), state=LogisticOfferStatesGroup.vehicle_type
)
async def offer_vehicle_selected(callback: types.CallbackQuery, state: FSMContext):
    """Выбор типа транспорта"""
    vehicle_type = callback.data.replace("vehicle_", "")

    vehicles_display = {
        "wagon": "🚂 ЖД",
        "grain": "🚚 Зерновоз",
        "truck": "🚛 Фура",
    }
    transport_display = vehicles_display.get(vehicle_type, "Неизвестный транспорт")

    await state.update_data(vehicle_type=vehicle_type)

    data = await state.get_data()
    request_id = data.get("request_id")
    source = data.get("source", "exporter")

    if source == "exporter":
        _, request = find_shipping_request_by_id(request_id)
        request = request or {}
    elif source == "logistics":
        request = logistics_requests.get(request_id) or logistics_requests.get(
            str(request_id)
        )
        request = request if isinstance(request, dict) else {}
    else:
        _, request = find_farmer_request_by_id(request_id)
        request = request or {}

    volume = request.get("volume", 0)

    text = f"""✅ <b>СОЗДАНИЕ ПРЕДЛОЖЕНИЯ</b>

✓ Транспорт: <b>{transport_display}</b>

━━━━━━━━━━━━━━━━━━━━

<b>Шаг 2/4: Укажите стоимость доставки</b>

Объём груза: <b>{volume:.1f} т</b>

Введите стоимость доставки в рублях:
<i>(например: 50000)</i>"""

    keyboard = InlineKeyboardMarkup()
    keyboard.add(InlineKeyboardButton("❌ Отмена", callback_data="cancel_offer"))

    try:
        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        logging.info(f"✅ VEHICLE SELECTED: {vehicle_type}")
    except Exception as e:
        logging.error(f"❌ EDIT ERROR: {e}")
        await callback.message.answer(text, reply_markup=keyboard, parse_mode="HTML")

    await LogisticOfferStatesGroup.price.set()
    await callback.answer()


@dp.message_handler(state=LogisticOfferStatesGroup.price)
async def offer_price_entered(message: types.Message, state: FSMContext):
    """Ввод цены"""
    try:
        price_str = (
            message.text.strip().replace(" ", "").replace(",", "").replace("₽", "")
        )
        price = float(price_str)

        if price <= 0:
            await message.answer(
                "❌ Цена должна быть больше нуля!\n\nПопробуйте ещё раз:"
            )
            return

        if price > 10_000_000:
            await message.answer(
                "❌ Цена слишком большая (максимум 10 млн ₽)!\n\nПопробуйте ещё раз:"
            )
            return

    except ValueError:
        await message.answer(
            "❌ Неправильный формат цены!\n\nВведите число (например: 50000):"
        )
        return

    await state.update_data(price=price)

    data = await state.get_data()
    vehicle_type = data.get("vehicle_type")

    vehicles_display = {
        "wagon": "🚂 ЖД",
        "grain": "🚚 Зерновоз",
        "truck": "🚛 Фура",
    }
    transport = vehicles_display.get(vehicle_type, "Неизвестный транспорт")

    text = f"""✅ <b>СОЗДАНИЕ ПРЕДЛОЖЕНИЯ</b>

✓ Транспорт: <b>{transport}</b>
✓ Стоимость: <b>{price:,.0f} ₽</b>

━━━━━━━━━━━━━━━━━━━━

<b>Шаг 3/4: Укажите дату доставки</b>

Введите дату доставки в формате ДД.ММ.ГГГГ:
<i>(например: 15.11.2025)</i>"""

    keyboard = InlineKeyboardMarkup()
    keyboard.add(InlineKeyboardButton("❌ Отмена", callback_data="cancel_offer"))

    await message.answer(text, reply_markup=keyboard, parse_mode="HTML")
    await LogisticOfferStatesGroup.delivery_date.set()


@dp.message_handler(state=LogisticOfferStatesGroup.delivery_date)
async def offer_date_entered(message: types.Message, state: FSMContext):
    """Ввод даты доставки"""
    date_str = message.text.strip()

    try:
        delivery_date = datetime.strptime(date_str, "%d.%m.%Y")
        today = datetime.now().replace(hour=0, minute=0, second=0, microsecond=0)

        if delivery_date < today:
            await message.answer(
                "❌ Дата доставки не может быть в прошлом!\n\n"
                "Введите дату не ранее сегодняшнего дня:"
            )
            return

        max_date = today + timedelta(days=365)
        if delivery_date > max_date:
            await message.answer(
                "❌ Дата доставки слишком далеко (максимум 1 год)!\n\n"
                "Попробуйте ещё раз:"
            )
            return

    except ValueError:
        await message.answer(
            "❌ Неправильный формат даты!\n\n"
            "Используйте формат ДД.ММ.ГГГГ (например: 15.11.2025):"
        )
        return

    await state.update_data(delivery_date=date_str)

    try:
        await show_offer_confirmation(message, state, user_id=message.from_user.id)
    except Exception as e:
        logging.error(f"❌ Ошибка в show_offer_confirmation: {e}")
        await message.answer("❌ Произошла ошибка. Попробуйте ещё раз.")


@dp.callback_query_handler(
    lambda c: c.data == "skip_additional_info",
    state=LogisticOfferStatesGroup.additional_info,
)
async def offer_skip_additional_info(callback: types.CallbackQuery, state: FSMContext):
    """Пропуск дополнительной информации"""
    await state.update_data(additional_info="")
    await show_offer_confirmation(
        callback.message, state, user_id=callback.from_user.id, is_callback=True
    )
    await callback.answer()


@dp.message_handler(state=LogisticOfferStatesGroup.additional_info)
async def offer_additional_info_entered(message: types.Message, state: FSMContext):
    """Ввод дополнительной информации"""
    additional_info = message.text.strip()

    if len(additional_info) > 500:
        await message.answer(
            "❌ Слишком длинное сообщение (максимум 500 символов)!\n\n"
            "Сократите текст:"
        )
        return

    await state.update_data(additional_info=additional_info)
    await show_offer_confirmation(message, state, user_id=message.from_user.id)


async def show_offer_confirmation(
    message_or_callback, state: FSMContext, user_id: int, is_callback: bool = False
):
    """Показать подтверждение предложения"""
    data = await state.get_data()

    request_id = data.get("request_id")
    source = data.get("source", "exporter")

    if source == "exporter":
        _, request = find_shipping_request_by_id(request_id)
        request = request or {}
        pull_id = request.get("pull_id")
        all_pulls = pulls.get("pulls", {})
        pull_info = (
            (all_pulls.get(pull_id) or all_pulls.get(str(pull_id), {}))
            if pull_id is not None
            else {}
        )
    elif source == "logistics":
        request = logistics_requests.get(request_id) or logistics_requests.get(
            str(request_id)
        )
        request = request if isinstance(request, dict) else {}
        pull_id = request.get("pull_id")
        all_pulls = pulls.get("pulls", {})
        pull_info = (
            (all_pulls.get(pull_id) or all_pulls.get(str(pull_id), {}))
            if pull_id is not None
            else {}
        )
    else:
        _, request = find_farmer_request_by_id(request_id)
        request = request or {}
        pull_info = {}

    vehicle_type = data.get("vehicle_type")
    price = data.get("price")
    delivery_date = data.get("delivery_date")
    additional_info = data.get("additional_info", "")

    vehicles_display = {
        "truck": "🚛 Фура",
        "wagon": "🚂 Ж/д вагон",
        "grain": "🚚 Зерновоз",
    }
    transport = vehicles_display.get(vehicle_type, "Неизвестный транспорт")

    culture = request.get("culture", pull_info.get("culture", "Не указана"))

    route_from = (
        request.get("route_from") or request.get("from_city") or request.get("from") or "—"
    )
    route_to = request.get("route_to") or request.get("to_city") or request.get("to") or "—"

    text = f"""📋 <b>ПОДТВЕРЖДЕНИЕ ПРЕДЛОЖЕНИЯ</b>

📦 <b>ЗАЯВКА #{request_id}</b>
🌾 Культура: {culture}
📦 Объём: {request.get('volume', 0):.1f} т
📍 Маршрут: {route_from} → {route_to}"""

    if pull_info.get("port"):
        text += f"\n🚢 Порт: {pull_info.get('port')}"

    text += f"""

━━━━━━━━━━━━━━━━━━━━

<b>ВАШЕ ПРЕДЛОЖЕНИЕ:</b>

🚛 Транспорт: <b>{transport}</b>
💰 Стоимость: <b>{price:,.0f} ₽</b>
📅 Дата доставки: <b>{delivery_date}</b>"""

    if additional_info:
        text += f"\n\nℹ️ Дополнительно:\n{additional_info}"

    text += "\n\n━━━━━━━━━━━━━━━━━━━━\n\n✅ Подтвердите отправку предложения"

    keyboard = InlineKeyboardMarkup(row_width=2)
    keyboard.add(
        InlineKeyboardButton("✅ Отправить", callback_data="confirm_offer"),
        InlineKeyboardButton("❌ Отмена", callback_data="cancel_offer"),
    )

    if is_callback:
        await message_or_callback.edit_text(
            text, reply_markup=keyboard, parse_mode="HTML"
        )
    else:
        await message_or_callback.answer(text, reply_markup=keyboard, parse_mode="HTML")

    await LogisticOfferStatesGroup.confirm.set()


@dp.callback_query_handler(
    lambda c: c.data == "confirm_offer", state=LogisticOfferStatesGroup.confirm
)
async def offer_confirmed(callback: types.CallbackQuery, state: FSMContext):
    """Подтверждение и создание предложения"""
    try:
        user_id = callback.from_user.id
        user_role = (get_user_by_id(user_id) or {}).get("role")
        if not (is_logistic_role(user_role) or user_role == "admin"):
            await callback.answer(
                "❌ Создание предложения доступно только логистам", show_alert=True
            )
            await state.finish()
            return
        data = await state.get_data()

        request_id = data.get("request_id")
        source = data.get("source", "exporter")
        vehicle_type = data.get("vehicle_type")
        price = data.get("price")
        delivery_date = data.get("delivery_date")
        additional_info = data.get("additional_info", "")

        if not all([request_id, vehicle_type, price, delivery_date]):
            await callback.answer(
                "❌ Ошибка: отсутствуют обязательные данные", show_alert=True
            )
            return

        # Повторная серверная валидация, чтобы избежать гонок между стартом и confirm.
        if source == "exporter":
            _, request = find_shipping_request_by_id(request_id)
        elif source == "logistics":
            request = logistics_requests.get(request_id) or logistics_requests.get(
                str(request_id)
            )
        else:
            _, request = find_farmer_request_by_id(request_id)
        request = request if isinstance(request, dict) else {}

        if not request:
            await callback.answer("❌ Заявка больше не доступна", show_alert=True)
            await state.finish()
            return
        if not is_request_open_for_offers(request.get("status")):
            await callback.answer("❌ Заявка уже не принимает отклики", show_alert=True)
            await state.finish()
            return
        if has_assigned_logist(request):
            await callback.answer("❌ По заявке уже назначен логист", show_alert=True)
            await state.finish()
            return

        vehicles_display = {
            "truck": "🚛 Фура",
            "railway": "🚂 Ж/д вагон",
            "wagon": "🚂 Ж/д вагон",
            "grain": "🚚 Зерновоз",
        }
        transport = vehicles_display.get(vehicle_type, "Неизвестный транспорт")

        # ===== 1. Гасим все незакрытые офферы этого логиста по этой заявке =====
        CLOSED_STATUSES = {
            "cancelled",
            "canceled",
            "rejected",
            "completed",
            "filled",
            "sold",
            "closed",
            "delivered",
        }

        now_str = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        closed_before_new = 0

        for o in logistic_offers.values():
            if not isinstance(o, dict):
                continue
            if logistic_offer_matches_request(o, request_id, source) and same_id(
                (o.get("logist_id") or o.get("logistic_id")), user_id
            ):
                status_norm = normalize_transition_status(o.get("status"))
                if status_norm not in CLOSED_STATUSES:
                    o["status"] = "cancelled"
                    o["cancelled_at"] = now_str
                    closed_before_new += 1

        if closed_before_new:
            logging.info(
                "[LOGISTIC OFFER] Before creating new offer: "
                f"closed {closed_before_new} active offers for request {request_id}, logist {user_id}"
            )

        # ===== 2. Создаём новый оффер =====
        offer_id = next_numeric_id(logistic_offers)

        offer = {
            "id": offer_id,
            "request_id": request_id,
            "logist_id": user_id,
            "vehicle_type": vehicle_type,
            "price": price,
            "delivery_date": delivery_date,
            "additional_info": additional_info,
            "status": "pending",
            "created_at": now_str,
            "source": source,
        }

        logistic_offers[offer_id] = offer
        save_logistic_offers()
        logging.info(f"✅ Предложение #{offer_id} создано и сохранено")

        # ===== 3. Определяем заказчика и синхронизируем статус заявки =====
        if source == "exporter":
            receiver_id = request.get("exporter_id")
            receiver_role_label = "экспортёру"
        elif source == "logistics":
            receiver_id = (
                request.get("customer_id")
                or request.get("created_by")
                or request.get("exporter_id")
                or request.get("logist_id")
            )
            receiver_role_label = "заказчику"
        else:
            receiver_id = request.get("farmer_id")
            receiver_role_label = "фермеру"

        if request:
            request["offers_count"] = count_logistic_offers_for_request(
                request_id, source
            )
            if is_request_open_for_offers(request.get("status")):
                request["status"] = "has_offers"

            if source == "exporter":
                save_shipping_requests()
            elif source == "logistics":
                save_logistics_requests_to_pickle()
            else:
                save_farmers_logistics()

        logist_name = (
            (get_user_by_id(user_id) or {}).get("company_name")
            or (get_user_by_id(user_id) or {}).get("name")
            or "Логист"
        )

        text = f"""✅ <b>ПРЕДЛОЖЕНИЕ ОТПРАВЛЕНО!</b>


📦 Заявка #{request_id}
🚛 Транспорт: <b>{transport}</b>
💰 Стоимость: <b>{price:,.0f} ₽</b>
📅 Дата: <b>{delivery_date}</b>


Ваше предложение #{offer_id} отправлено {receiver_role_label}.
Вы получите уведомление, когда заказчик примет решение."""

        keyboard = InlineKeyboardMarkup(row_width=1)
        keyboard.add(
            InlineKeyboardButton("💼 Мои предложения", callback_data="my_offers"),
            InlineKeyboardButton("🔙 Главное меню", callback_data="back_to_main"),
        )

        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")

        # ===== 4. Уведомление заказчику =====
        if receiver_id:
            try:
                receiver_text = f"""🔔 <b>НОВОЕ ПРЕДЛОЖЕНИЕ ПО ВАШЕЙ ЗАЯВКЕ!</b>


📦 <b>Заявка #{request_id}</b>
👤 От: <b>{logist_name}</b>
🚛 Транспорт: <b>{transport}</b>
💰 Стоимость: <b>{price:,.0f} ₽</b>
📅 Дата доставки: <b>{delivery_date}</b>"""

                if additional_info:
                    receiver_text += f"\n\nℹ️ Дополнительно:\n{additional_info}"

                receiver_keyboard = InlineKeyboardMarkup()
                if source == "exporter":
                    receiver_keyboard.add(
                        InlineKeyboardButton(
                            "👁 Посмотреть", callback_data=f"view_offer_details_{offer_id}"
                        )
                    )
                elif source == "farmer":
                    receiver_keyboard.add(
                        InlineKeyboardButton(
                            "👁 Посмотреть заявку",
                            callback_data=f"view_request:farmer:{request_id}",
                        )
                    )
                else:
                    receiver_keyboard.add(
                        InlineKeyboardButton(
                            "👁 Посмотреть заявку",
                            callback_data=f"view_logistics_req:{request_id}",
                        )
                    )

                await bot.send_message(
                    receiver_id,
                    receiver_text,
                    reply_markup=receiver_keyboard,
                    parse_mode="HTML",
                )
                logging.info(
                    f"📧 Уведомление отправлено заказчику {receiver_id} по заявке #{request_id}"
                )
            except Exception as e:
                logging.error(
                    f"❌ Ошибка отправки уведомления заказчику {receiver_id}: {e}",
                    exc_info=True,
                )
        else:
            logging.warning(
                f"⚠️ Заказчик не найден для заявки #{request_id}, source={source}"
            )

        await state.finish()
        await callback.answer("✅ Предложение отправлено!")

        logging.info(
            f"✅ Логист {user_id} создал предложение #{offer_id} для заявки #{request_id} ({source})"
        )

    except Exception as e:
        logging.error(f"❌ Критическая ошибка в offer_confirmed: {e}", exc_info=True)
        await callback.answer(f"❌ Ошибка: {str(e)}", show_alert=True)
        await callback.message.answer(
            "❌ <b>ОШИБКА ПРИ СОЗДАНИИ ПРЕДЛОЖЕНИЯ</b>\n\n"
            "Попробуйте ещё раз или свяжитесь с поддержкой.",
            parse_mode="HTML",
        )


# ============================================================================
# ЛОГИСТ: УПРАВЛЕНИЕ ПРЕДЛОЖЕНИЯМИ
# ============================================================================
@dp.message_handler(
    lambda m: m.text == "💼 Мои предложения"
    and is_logistic_role((get_user_by_id(m.from_user.id) or {}).get("role")),
    state="*",
)
async def logistic_my_offers_text_button(message: types.Message, state: FSMContext):
    """Логист нажал на ТЕКСТОВУЮ кнопку '💼 Мои предложения'"""

    logger.info(
        f"✅ ТЕКСТОВАЯ КНОПКА: 💼 Мои предложения | User: {message.from_user.id}"
    )

    user_id = message.from_user.id

    try:
        await state.finish()

        my_offers = [
            (offer_id, offer)
            for offer_id, offer in logistic_offers.items()
            if same_id(get_offer_logist_id(offer), user_id)
        ]

        logger.info(f"[{user_id}] 📦 Найдено предложений: {len(my_offers)}")

        if not my_offers:
            text = "📋 <b>МОИ ПРЕДЛОЖЕНИЯ</b>\n\n❌ У вас нет предложений"
            keyboard = InlineKeyboardMarkup()
            keyboard.add(
                InlineKeyboardButton(
                    "📦 К заявкам", callback_data="logistic_requests_list"
                )
            )
            keyboard.add(InlineKeyboardButton("🔙 Меню", callback_data="back_to_main"))

            await message.answer(text, reply_markup=keyboard, parse_mode="HTML")
            return

        # Группировка по статусам
        by_status: dict[str, list[tuple[int, dict]]] = {}
        for offer_id, offer in my_offers:
            status = normalize_transition_status(offer.get("status", "pending"))
            if status in {"active", "new", "open"}:
                status = "pending"
            elif status in {"assigned", "in_progress", "completed", "accepted"}:
                status = "accepted"
            elif status in {"cancelled", "canceled"}:
                status = "cancelled"
            elif status in {"filled", "sold", "closed", "delivered"}:
                status = "rejected"
            logger.info(f"[{user_id}] 📌 Предложение #{offer_id}: статус = '{status}'")
            if status not in by_status:
                by_status[status] = []
            by_status[status].append((offer_id, offer))

        logger.info(
            f"[{user_id}] 📊 Все статусы: "
            f"{dict((k, len(v)) for k, v in by_status.items())}"
        )

        text = f"📋 <b>МОИ ПРЕДЛОЖЕНИЯ</b> ({len(my_offers)} шт)\n\n"
        text += f"🕐 Ожидают: {len(by_status.get('pending', []))}\n"
        text += f"✅ Приняты: {len(by_status.get('accepted', []))}\n"
        text += f"❌ Отклонены: {len(by_status.get('rejected', []))}\n"
        text += f"⛔ Отменены: {len(by_status.get('cancelled', []))}\n\n"

        keyboard = InlineKeyboardMarkup(row_width=1)
        button_count = 0

        # Добавляем кнопки по статусам (до 10 штук суммарно)
        for status_key, emoji in [
            ("pending", "🕐"),
            ("accepted", "✅"),
            ("rejected", "❌"),
            ("cancelled", "⛔"),
        ]:
            for offer_id, offer in by_status.get(status_key, [])[:5]:
                if button_count >= 10:
                    break
                price = offer.get("price", 0)
                button_text = f"{emoji} #{offer_id} | {price:,.0f}₽".replace(",", " ")
                keyboard.add(
                    InlineKeyboardButton(
                        button_text, callback_data=f"view_my_offer_{offer_id}"
                    )
                )
                button_count += 1

        keyboard.add(InlineKeyboardButton("🔙 Меню", callback_data="back_to_main"))

        await message.answer(text, reply_markup=keyboard, parse_mode="HTML")
        logger.info(f"[{user_id}] ✅ УСПЕХ! Показано {button_count} кнопок")

    except Exception as e:
        logger.error(f"[{user_id}] ❌ ОШИБКА: {e}", exc_info=True)
        await message.answer("❌ Ошибка загрузки", parse_mode="HTML")


