# ПРОСМОТР ДЕТАЛЕЙ ДОСТАВКИ
# ═══════════════════════════════════════════════════════════════════════════
@dp.callback_query_handler(
    lambda c: c.data.startswith("view_delivery_")
    and not c.data.startswith("view_delivery_by_request_"),
    state="*",
)
async def view_delivery_details(callback: types.CallbackQuery, state: FSMContext):
    """Детальный просмотр доставки экспортёром по delivery_id"""
    await state.finish()

    try:
        delivery_ref = callback.data.split("_")[-1]
        delivery_id = int(delivery_ref) if str(delivery_ref).isdigit() else delivery_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка ID доставки", show_alert=True)
        return

    resolved_delivery_id, delivery = find_delivery_by_id(delivery_id)
    if not delivery:
        await callback.answer("❌ Доставка не найдена", show_alert=True)
        return
    delivery_id = resolved_delivery_id
    user_id = callback.from_user.id
    role = (get_user_by_id(user_id) or {}).get("role")

    request_id = delivery.get("request_id")
    delivery_source = str(delivery.get("source") or "").strip().lower()
    if delivery_source == "logistic":
        delivery_source = "logistics"
    if delivery_source not in {"exporter", "farmer", "logistics"}:
        source_candidates = set()
        request_key = request_id if isinstance(request_id, str) else str(request_id)
        if request_id in shipping_requests or request_key in shipping_requests:
            source_candidates.add("exporter")
        if request_id in logistics_requests or request_key in logistics_requests:
            source_candidates.add("logistics")
        if (
            request_id in farmer_shipping_requests
            or request_key in farmer_shipping_requests
            or request_id in farmer_logistics_requests
            or request_key in farmer_logistics_requests
        ):
            source_candidates.add("farmer")
        if len(source_candidates) == 1:
            delivery_source = next(iter(source_candidates))
        else:
            inferred_source = infer_logistic_offer_source(request_id)
            if (
                inferred_source in {"exporter", "farmer", "logistics"}
                and (not source_candidates or inferred_source in source_candidates)
            ):
                delivery_source = inferred_source
            else:
                await callback.answer(
                    "❌ Не удалось определить источник доставки",
                    show_alert=True,
                )
                return

    if delivery_source == "farmer":
        _, request = find_farmer_request_by_id(request_id)
    elif delivery_source == "logistics":
        request = logistics_requests.get(request_id) or logistics_requests.get(
            str(request_id)
        )
    else:
        _, request = find_shipping_request_by_id(request_id)
    request = request if isinstance(request, dict) else {}

    exporter_owner_id = request.get("exporter_id")
    logistics_owner_id = (
        request.get("customer_id")
        or request.get("created_by")
        or request.get("logist_id")
        or exporter_owner_id
    )
    exporter_access = (
        same_id(delivery.get("exporter_id"), user_id)
        or (
            delivery_source == "exporter"
            and same_id(exporter_owner_id, user_id)
        )
        or (
            delivery_source == "logistics"
            and same_id(logistics_owner_id, user_id)
        )
    )
    farmer_access = same_id(delivery.get("farmer_id"), user_id) or (
        delivery_source == "farmer" and same_id(request.get("farmer_id"), user_id)
    )
    logistic_access = (
        same_id(get_assigned_logist_id(delivery), user_id)
        or same_id(get_assigned_logist_id(request), user_id)
    )
    expeditor_access = (
        same_id(get_assigned_expeditor_id(delivery), user_id)
        or same_id(get_assigned_expeditor_id(request), user_id)
    )
    is_admin = role == "admin"
    if not (
        is_admin
        or exporter_access
        or farmer_access
        or logistic_access
        or expeditor_access
    ):
        await callback.answer("❌ Нет доступа к этой доставке", show_alert=True)
        return

    pull_id = delivery.get("pull_id") or request.get("pull_id")
    all_pulls = pulls.get("pulls", {}) if isinstance(pulls, dict) else {}
    pull = (
        (all_pulls.get(pull_id) or all_pulls.get(str(pull_id), {}))
        if pull_id is not None
        else {}
    )

    logist_id = get_assigned_logist_id(delivery) or get_assigned_logist_id(request)
    logist = get_user_by_id(logist_id) or {}

    status = normalize_transition_status(delivery.get("status", "pending"))
    status_text = {
        "pending": "🕐 Ожидает начала",
        "in_progress": "🚚 В пути",
        "completed": "✅ Завершена",
        "cancelled": "🚫 Отменена",
    }.get(status, status)

    culture = pull.get("culture") or request.get("culture", "Не указана")
    volume = delivery.get("volume", request.get("volume", 0))
    route_from = (
        delivery.get("route_from")
        or request.get("route_from")
        or request.get("from_city")
        or request.get("from")
        or "Не указано"
    )
    route_to = (
        delivery.get("route_to")
        or request.get("route_to")
        or request.get("to_city")
        or request.get("to")
        or "Не указано"
    )
    price = delivery.get("price", 0)
    vehicle_type = delivery.get("vehicle_type", "Не указан")
    delivery_date = delivery.get("delivery_date", "Не указана")

    company = (
        logist.get("company_name")
        or logist.get("company_details")
        or logist.get("name")
        or f"Логист #{logist_id}"
    )

    text = (
        f"📦 <b>ДОСТАВКА #{delivery_id}</b>\n\n"
        f"📊 Статус: {status_text}\n"
        f"📅 Создана: {delivery.get('created_at', 'Н/Д')}\n\n"
        "<b>📦 ГРУЗ:</b>\n"
        f"🌾 Культура: {culture}\n"
        f"⚖️ Объём: {volume:.1f} т\n"
        f"📍 Маршрут: {route_from} → {route_to}\n"
        f"🚢 Порт: {pull.get('port', 'Не указан')}\n\n"
        "<b>🚚 ЛОГИСТ:</b>\n"
        f"🏢 Компания: {company}\n"
        f"👤 Имя: {logist.get('name', 'Не указано')}\n"
        f"📞 Телефон: <code>{logist.get('phone', 'Не указан')}</code>\n"
        f"📧 Email: <code>{logist.get('email', 'Не указан')}</code>\n\n"
        "<b>💰 УСЛОВИЯ:</b>\n"
        f"💰 Стоимость: {price:,.0f} ₽\n"
        f"🚛 Транспорт: {vehicle_type}\n"
        f"📅 Дата доставки: {delivery_date}\n"
    ).replace(",0 ₽", " ₽")

    # Рейтинг / отзыв
    if delivery.get("rated"):
        text += "\n<b>⭐ ВАША ОЦЕНКА:</b>\n"
        rating = delivery.get("rating", 0)
        stars = "⭐" * int(rating)
        text += f"{stars} ({rating}/5)\n"
        if delivery.get("review"):
            text += f"💬 Отзыв:\n<i>{delivery['review']}</i>\n"

    keyboard = InlineKeyboardMarkup(row_width=1)

    # Управление статусом доставки для логиста через единый обработчик.
    if logistic_access and is_logistic_role(role):
        has_expeditor = bool(
            get_assigned_expeditor_id(delivery) or get_assigned_expeditor_id(request)
        )
        status_ref = f"delivery_{delivery_id}"
        if not has_expeditor:
            if status in {"pending", "assigned", "new", "open", ""}:
                keyboard.add(
                    InlineKeyboardButton(
                        "🚚 Начать доставку",
                        callback_data=f"change_logist_status:{status_ref}:in_progress",
                    )
                )
                keyboard.add(
                    InlineKeyboardButton(
                        "❌ Отменить доставку",
                        callback_data=f"change_logist_status:{status_ref}:cancelled",
                    )
                )
            elif status == "in_progress":
                keyboard.add(
                    InlineKeyboardButton(
                        "✅ Завершить доставку",
                        callback_data=f"change_logist_status:{status_ref}:completed",
                    )
                )
                keyboard.add(
                    InlineKeyboardButton(
                        "⏸ Вернуть в ожидание",
                        callback_data=f"change_logist_status:{status_ref}:pending",
                    )
                )

    # Кнопки связи с логистом
    if logist.get("phone"):
        keyboard.add(
            InlineKeyboardButton(
                "📞 Позвонить логисту", url=f"tel:{logist.get('phone')}"
            )
        )
    if logist_id:
        keyboard.add(
            InlineKeyboardButton(
                "💬 Написать в Telegram", url=f"tg://user?id={logist_id}"
            )
        )

    # Кнопка оценки логиста — только для заказчика, не для исполнителя
    can_rate_logistic = (
        status == "completed"
        and not delivery.get("rated")
        and (exporter_access or farmer_access)
        and not same_id(logist_id, user_id)
        and not is_logistic_role(role)
        and not is_expeditor_role(role)
    )
    if can_rate_logistic:
        keyboard.add(
            InlineKeyboardButton(
                "⭐ Оценить логиста", callback_data=f"rate_logistic_{delivery_id}"
            )
        )

    if logistic_access and is_logistic_role(role):
        keyboard.add(
            InlineKeyboardButton("📦 Мои доставки", callback_data="back_to_deliveries")
        )
    elif expeditor_access and is_expeditor_role(role):
        keyboard.add(
            InlineKeyboardButton("📦 Мои доставки", callback_data="back_to_exp_deliveries")
        )
    elif farmer_access:
        keyboard.add(
            InlineKeyboardButton(
                "📬 Мои заявки", callback_data="farmer_my_requests_menu"
            )
        )
    elif exporter_access:
        keyboard.add(
            InlineKeyboardButton("📦 Мои доставки", callback_data="exporter_deliveries")
        )
    else:
        keyboard.add(InlineKeyboardButton("🔙 Назад", callback_data="back_to_main"))
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("complete_delivery:"), state="*")
async def complete_delivery(callback: types.CallbackQuery):
    """Legacy-совместимость: завершение доставки через старый callback."""
    try:
        offer_ref = callback.data.split(":", 1)[1]
        offer_id = int(offer_ref) if str(offer_ref).isdigit() else offer_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return

    resolved_offer_id, offer = find_logistic_offer_by_id(offer_id)
    if not offer:
        await callback.answer("❌ Доставка не найдена", show_alert=True)
        return
    offer_id = resolved_offer_id
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")

    # Основной путь: перенаправляем в единый обработчик смены статуса логиста.
    # Это сохраняет согласованность request/delivery/offer/deal синхронизации.
    if is_logistic_role(user_role) and (
        same_id(get_offer_logist_id(offer), user_id)
        or same_id(offer.get("logistic_id"), user_id)
    ):
        linked_delivery = next(
            (
                d
                for d in deliveries.values()
                if isinstance(d, dict)
                and (
                    same_id(d.get("offer_id"), offer_id)
                    or same_id(d.get("logistic_offer_id"), offer_id)
                )
            ),
            None,
        )
        if linked_delivery is None:
            req_id = offer.get("request_id")
            offer_source = str(offer.get("source") or "").strip().lower()
            if offer_source == "logistic":
                offer_source = "logistics"
            if offer_source not in {"exporter", "farmer", "logistics"}:
                source_candidates = set()
                request_key = req_id if isinstance(req_id, str) else str(req_id)
                if req_id in shipping_requests or request_key in shipping_requests:
                    source_candidates.add("exporter")
                if req_id in logistics_requests or request_key in logistics_requests:
                    source_candidates.add("logistics")
                if (
                    req_id in farmer_shipping_requests
                    or request_key in farmer_shipping_requests
                    or req_id in farmer_logistics_requests
                    or request_key in farmer_logistics_requests
                ):
                    source_candidates.add("farmer")
                if len(source_candidates) == 1:
                    offer_source = next(iter(source_candidates))
                else:
                    inferred_source = infer_logistic_offer_source(req_id)
                    if (
                        inferred_source in {"exporter", "farmer", "logistics"}
                        and (not source_candidates or inferred_source in source_candidates)
                    ):
                        offer_source = inferred_source
                    else:
                        offer_source = None
            linked_delivery = next(
                (
                    d
                    for d in deliveries.values()
                    if isinstance(d, dict)
                    and same_id(d.get("request_id"), req_id)
                    and (
                        str(d.get("source") or "").strip().lower()
                        in {"", offer_source, "logistic" if offer_source == "logistics" else offer_source}
                    )
                ),
                None,
            )
        if isinstance(linked_delivery, dict) and linked_delivery.get("id") is not None:
            callback.data = (
                f"change_logist_status:delivery_{linked_delivery.get('id')}:completed"
            )
            await change_logist_delivery_status(callback)
            return

    if not (
        user_role == "admin"
        or same_id(get_offer_logist_id(offer), user_id)
        or same_id(offer.get("logistic_id"), user_id)
    ):
        await callback.answer("❌ Нет доступа к этой доставке", show_alert=True)
        return
    if normalize_transition_status(offer.get("status")) == "completed":
        await callback.answer("ℹ️ Доставка уже завершена", show_alert=True)
        return
    allowed_to_complete = {
        "accepted",
        "assigned",
        "in_progress",
        "active",
        "open",
        "selected",
        "reserved",
        "expeditor_selected",
    }
    if normalize_transition_status(offer.get("status")) not in allowed_to_complete:
        await callback.answer(
            "❌ Нельзя завершить доставку в текущем статусе", show_alert=True
        )
        return

    # Проверяем связанную заявку до изменения статусов
    request_id = offer.get("request_id")
    offer_source = str(offer.get("source") or "").strip().lower()
    if offer_source == "logistic":
        offer_source = "logistics"
    if offer_source not in {"exporter", "farmer", "logistics"}:
        source_candidates = set()
        request_key = request_id if isinstance(request_id, str) else str(request_id)
        if request_id in shipping_requests or request_key in shipping_requests:
            source_candidates.add("exporter")
        if request_id in logistics_requests or request_key in logistics_requests:
            source_candidates.add("logistics")
        if (
            request_id in farmer_shipping_requests
            or request_key in farmer_shipping_requests
            or request_id in farmer_logistics_requests
            or request_key in farmer_logistics_requests
        ):
            source_candidates.add("farmer")
        if len(source_candidates) == 1:
            offer_source = next(iter(source_candidates))
        else:
            inferred_source = infer_logistic_offer_source(request_id)
            if (
                inferred_source in {"exporter", "farmer", "logistics"}
                and (not source_candidates or inferred_source in source_candidates)
            ):
                offer_source = inferred_source
            else:
                await callback.answer(
                    "❌ Не удалось определить тип заявки для предложения",
                    show_alert=True,
                )
                return

    if offer_source == "farmer":
        _, request = find_farmer_request_by_id(request_id)
    elif offer_source == "logistics":
        request = logistics_requests.get(request_id) or logistics_requests.get(str(request_id))
    else:
        _, request = find_shipping_request_by_id(request_id)
    if not isinstance(request, dict):
        await callback.answer("❌ Связанная заявка не найдена", show_alert=True)
        return
    if not logistic_offer_matches_request(offer, request_id, offer_source):
        await callback.answer("❌ Предложение не относится к выбранной заявке", show_alert=True)
        return
    if offer_source == "farmer":
        request_owner_id = request.get("farmer_id")
    elif offer_source == "logistics":
        request_owner_id = (
            request.get("customer_id")
            or request.get("created_by")
            or request.get("exporter_id")
            or request.get("logist_id")
        )
    else:
        request_owner_id = request.get("exporter_id")
    if normalize_transition_status(request.get("status")) == "cancelled":
        await callback.answer(
            "❌ Нельзя завершить доставку по отменённой заявке", show_alert=True
        )
        return
    if get_assigned_expeditor_id(request):
        await callback.answer(
            "❌ По этой заявке назначен экспедитор. Завершение выполняет экспедитор.",
            show_alert=True,
        )
        return

    now_sql = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    # Обновляем статус
    offer["status"] = "completed"
    offer["completed_at"] = now_sql

    # Закрываем остальные активные офферы по этой заявке.
    for other_offer_id, other_offer in logistic_offers.items():
        if not isinstance(other_offer, dict):
            continue
        if same_id(other_offer_id, offer_id):
            continue
        if not logistic_offer_matches_request(other_offer, request_id, offer_source):
            continue
        other_status = normalize_transition_status(other_offer.get("status"))
        if other_status not in {"pending", "active"}:
            continue
        other_offer["status"] = "rejected"
        other_offer["rejected_at"] = now_sql
        other_offer["rejection_reason"] = "Заявка завершена исполнителем"

    save_logistic_offers()
    if normalize_transition_status(request.get("status")) != "cancelled":
        request["status"] = "completed"
        request["completed_at"] = now_sql
        if offer_source == "farmer":
            save_farmers_logistics()
        elif offer_source == "logistics":
            save_logistics_requests_to_pickle()
        else:
            save_shipping_requests()

    for delivery in deliveries.values():
        if not isinstance(delivery, dict):
            continue
        if not (
            same_id(delivery.get("offer_id"), offer_id)
            or same_id(delivery.get("request_id"), request_id)
        ):
            continue
        delivery_source = str(delivery.get("source") or "").strip().lower()
        if delivery_source == "logistic":
            delivery_source = "logistics"
        if delivery_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
            request_key = request_id if isinstance(request_id, str) else str(request_id)
            if request_id in shipping_requests or request_key in shipping_requests:
                source_candidates.add("exporter")
            if request_id in logistics_requests or request_key in logistics_requests:
                source_candidates.add("logistics")
            if (
                request_id in farmer_shipping_requests
                or request_key in farmer_shipping_requests
                or request_id in farmer_logistics_requests
                or request_key in farmer_logistics_requests
            ):
                source_candidates.add("farmer")
            if len(source_candidates) == 1:
                delivery_source = next(iter(source_candidates))
            else:
                inferred_source = infer_logistic_offer_source(request_id)
                if (
                    inferred_source in {"exporter", "farmer", "logistics"}
                    and (not source_candidates or inferred_source in source_candidates)
                ):
                    delivery_source = inferred_source
                else:
                    continue
        if delivery_source != offer_source:
            continue
        if offer_source in {"exporter", "logistics"} and request_owner_id:
            if offer_source == "logistics":
                delivery_owner_id = (
                    delivery.get("customer_id")
                    or delivery.get("created_by")
                    or delivery.get("exporter_id")
                    or delivery.get("logist_id")
                )
            else:
                delivery_owner_id = delivery.get("exporter_id")
            if not same_id(delivery_owner_id, request_owner_id):
                continue
        if offer_source == "farmer" and request_owner_id and not same_id(
            delivery.get("farmer_id"), request_owner_id
        ):
            continue
        if delivery.get("expeditor_id"):
            continue
        if normalize_transition_status(delivery.get("status")) == "cancelled":
            continue
        delivery["status"] = "completed"
        delivery["completed_at"] = now_sql
    save_deliveries()

    completed_deals = 0
    for deal in deals.values():
        if not isinstance(deal, dict):
            continue
        if not same_id(deal.get("request_id"), request_id):
            continue
        deal_source = str(deal.get("source") or "").strip().lower()
        if deal_source == "logistic":
            deal_source = "logistics"
        if deal_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
            request_key = request_id if isinstance(request_id, str) else str(request_id)
            if request_id in shipping_requests or request_key in shipping_requests:
                source_candidates.add("exporter")
            if request_id in logistics_requests or request_key in logistics_requests:
                source_candidates.add("logistics")
            if (
                request_id in farmer_shipping_requests
                or request_key in farmer_shipping_requests
                or request_id in farmer_logistics_requests
                or request_key in farmer_logistics_requests
            ):
                source_candidates.add("farmer")
            if len(source_candidates) == 1:
                deal_source = next(iter(source_candidates))
            else:
                inferred_source = infer_logistic_offer_source(request_id)
                if (
                    inferred_source in {"exporter", "farmer", "logistics"}
                    and (not source_candidates or inferred_source in source_candidates)
                ):
                    deal_source = inferred_source
                else:
                    continue
        if deal_source != offer_source:
            continue
        if offer_source in {"exporter", "logistics"} and request_owner_id:
            if offer_source == "logistics":
                deal_owner_id = (
                    deal.get("customer_id")
                    or deal.get("created_by")
                    or deal.get("exporter_id")
                    or deal.get("logist_id")
                )
            else:
                deal_owner_id = deal.get("exporter_id")
            if not same_id(deal_owner_id, request_owner_id):
                continue
        if offer_source == "farmer" and request_owner_id and not same_id(
            deal.get("farmer_id"), request_owner_id
        ):
            continue
        if normalize_transition_status(deal.get("status")) in {
            "completed",
            "cancelled",
        }:
            continue
        deal["status"] = "completed"
        deal["completed_at"] = now_sql
        completed_deals += 1
    if completed_deals:
        save_deals_to_pickle()

    if request_owner_id:
        try:
            await bot.send_message(
                request_owner_id,
                "✅ <b>Доставка завершена!</b>\n\n"
                f"Логист завершил доставку по заявке #{request_id}.\n"
                f"Груз доставлен: {request.get('route_to', 'пункт назначения')}.",
                parse_mode="HTML",
            )
            logging.info(
                f"✅ Уведомление заказчику {request_owner_id} о завершении доставки #{offer_id}"
            )
        except Exception as e:
            logging.error(f"❌ Ошибка уведомления заказчика: {e}")

    await callback.answer("✅ Доставка завершена!", show_alert=True)

    # Обновляем сообщение
    text = (
        f"✅ <b>Доставка #{offer_id} завершена!</b>\n\n"
        "Спасибо за работу! \n"
        "Доставка отмечена как выполненная.\n\n"
        f"💰 Заработано: {offer.get('price', 0):,} ₽"
    )

    keyboard = InlineKeyboardMarkup(row_width=1)
    keyboard.add(
        InlineKeyboardButton("🔙 К списку доставок", callback_data="back_to_deliveries")
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")


@dp.callback_query_handler(
    lambda c: c.data in ["back_to_deliveries", "refresh_deliveries"], state="*"
)
async def back_to_deliveries_handler(callback: types.CallbackQuery, state: FSMContext):
    """Вернуться к списку доставок"""
    await show_my_deliveries(callback, state)


@dp.message_handler(
    lambda m: m.text in ["💼 Мои логистических услуги", "💼 Мои логистических услуг"],
    state="*",
)
async def logistics_services_stats_handler(message: types.Message, state: FSMContext):
    await state.finish()
    user_id = message.from_user.id

    if not is_logistic_role((get_user_by_id(user_id) or {}).get("role")):
        await message.answer("❌ Доступно только для логистов")
        return

    await message.answer(
        "💼 <b>Статистика услуг</b>\n\n"
        "📊 <b>Перевозки:</b> 0\n"
        "💰 <b>Заработано:</b> 0 ₽\n"
        "⭐ <b>Рейтинг:</b> нет отзывов\n\n"
        "Данные обновляются автоматически",
        parse_mode="HTML",
    )


