# СИСТЕМА ЛОГИСТИЧЕСКИХ ЗАЯВОК
# ============================================================================
# -------------------- ЭКСПОРТЁР: СОЗДАНИЕ ЗАЯВКИ --------------------
@dp.message_handler(
    lambda m: m.text == "🚚 Заявка на логистику", state="*"
)  # ← ИСПРАВЛЕНО!
async def create_logistics_request_start(message: types.Message, state: FSMContext):
    """Создание заявки на логистику - с проверкой готовности пула"""
    await state.finish()
    user_id = message.from_user.id

    if (get_user_by_id(user_id) or {}).get("role") != "exporter":
        await message.answer("❌ Эта функция доступна только экспортёрам")
        return

    # Получаем правильную структуру пулов
    true_pulls = None
    if (
        isinstance(pulls, dict)
        and "pulls" in pulls
        and isinstance(pulls["pulls"], dict)
    ):
        true_pulls = pulls["pulls"]
    elif isinstance(pulls, dict):
        true_pulls = pulls
    else:
        true_pulls = {}

    logging.info("=" * 50)
    logging.info(f"USER {user_id} requested logistics")
    logging.info(f"ALL PULLS IN SYSTEM: {len(true_pulls)}")

    # ✅ ДОБАВЛЯЕМ ПРОВЕРКУ ГОТОВНОСТИ!
    exporter_pulls = {}

    for pid, p in true_pulls.items():
        if not isinstance(p, dict):
            continue
        exp_id = p.get("exporter_id")

        if same_id(exp_id, user_id):
            logging.info(
                f"  Pull #{pid}: exporter_id={exp_id}, status={p.get('status')}, culture={p.get('culture')}"
            )

            # ✅ ПРОВЕРКА ГОТОВНОСТИ ПУЛА
            status = p.get("status", "active")
            status_norm = normalize_transition_status(status)
            current_volume = p.get("current_volume", 0)
            target_volume = p.get("target_volume", 0)

            is_closed = status_norm == "closed"
            is_full = current_volume >= target_volume and target_volume > 0

            if is_closed or is_full:
                logging.info(
                    f"  ✅ Pull #{pid} READY: closed={is_closed}, full={is_full} ({current_volume}/{target_volume})"
                )
                exporter_pulls[pid] = p
            else:
                logging.info(
                    f"  ⏳ Pull #{pid} NOT READY: status={status}, volume={current_volume}/{target_volume}"
                )

    logging.info("=" * 50)
    logging.info(f"FOUND {len(exporter_pulls)} READY pulls for logistics")

    if not exporter_pulls:
        # Показываем информацию о неготовых пулах
        text = (
            "❌ <b>Нет готовых пулов для создания заявки на логистику</b>\n\n"
            "Чтобы создать заявку на логистику, пул должен быть:\n"
            "-  Закрыт вручную (статус 'Закрыт')\n"
            "-  Или заполнен на 100% (набран весь объём)\n\n"
            "💡 <b>Ваши пулы:</b>\n"
        )

        # Показываем все пулы экспортёра с их статусом
        all_user_pulls = [
            p
            for p in true_pulls.values()
            if isinstance(p, dict) and same_id(p.get("exporter_id"), user_id)
        ]

        if all_user_pulls:
            for pull in all_user_pulls:
                pull_id = pull.get("id")
                culture = pull.get("culture", "Неизвестно")
                status = pull.get("status", "active")
                current = pull.get("current_volume", 0)
                target = pull.get("target_volume", 0)
                percent = (current / target * 100) if target > 0 else 0

                status_emoji = "🔓" if is_pull_open_status(status) else "🔒"
                text += f"{status_emoji} Пул #{pull_id}: {culture} — {percent:.0f}% ({current:.0f}/{target:.0f} т)\n"

                # Добавляем кнопку перехода к пулу
                text += "   → Перейдите в пул чтобы закрыть его\n\n"
        else:
            text += "У вас пока нет пулов.\n"

        text += "\n💡 Совет: перейдите в 'Мои пулы' → выберите пул → 'Логистика' → 'Закрыть пул'"

        await message.answer(text, parse_mode="HTML", reply_markup=exporter_keyboard())
        return

    # Если есть готовые пулы — показываем их для выбора
    keyboard = InlineKeyboardMarkup(row_width=1)

    for pull_id, pull in list(exporter_pulls.items())[:10]:
        culture = pull.get("culture", "Неизвестно")
        current_vol = pull.get("current_volume", 0) or 0

        btn_text = f"📦 Пул #{pull_id}: {culture} ({current_vol:.0f}т)"
        keyboard.add(
            InlineKeyboardButton(btn_text, callback_data=f"create_logistic_req:{pull_id}")
        )

    await message.answer(
        "🚚 <b>Выберите пул для создания заявки на логистику</b>\n\n"
        f"Готовых пулов: <b>{len(exporter_pulls)}</b>\n",
        reply_markup=keyboard,
        parse_mode="HTML",
    )


@dp.callback_query_handler(
    lambda c: c.data.startswith("create_logistic_req:"), state="*"
)
async def select_pull_for_logistics(callback: types.CallbackQuery, state: FSMContext):
    """Выбор пула для заявки"""
    try:
        pull_id = parse_callback_id(callback.data)
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return
    if pull_id is None:
        await callback.answer("❌ Ошибка данных пула", show_alert=True)
        return

    _, pull = find_pull_by_id(pull_id)
    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        return
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if not (user_role == "admin" or user_role == "exporter"):
        await callback.answer("❌ Доступно только экспортёрам", show_alert=True)
        return
    pull_owner_id = pull.get("exporter_id") or pull.get("creator_id")
    if user_role != "admin" and not same_id(pull_owner_id, user_id):
        await callback.answer("❌ Нет доступа к этому пулу", show_alert=True)
        return

    pull_status = normalize_transition_status(pull.get("status", "active"))
    current_volume = pull.get("current_volume", 0) or 0
    target_volume = pull.get("target_volume", 0) or 0
    is_closed = pull_status == "closed"
    is_full = target_volume > 0 and current_volume >= target_volume
    if not (is_closed or is_full):
        await callback.answer(
            "❌ Пул ещё не готов для логистики (должен быть закрыт или заполнен)",
            show_alert=True,
        )
        return

    await state.update_data(
        pull_id=pull_id,
        culture=pull.get("culture", "Культура"),
        volume=pull.get("current_volume", 0),
        port=pull.get("port", ""),
    )

    await callback.message.edit_text(
        "🚚 <b>Заявка на логистику</b>\n\n"
        "<b>Шаг 1 из 4</b>\n\n"
        f"Пул: #{pull_id} • {pull.get('culture', 'Культура')} • {pull.get('current_volume', 0):.0f} т\n"
        f"Порт: {pull.get('port', '')}\n\n"
        "Откуда (регион/город погрузки):",
        parse_mode="HTML",
    )

    await CreateLogisticRequestStatesGroup.route_from.set()
    await callback.answer()


@dp.message_handler(state=CreateLogisticRequestStatesGroup.route_from)
async def logistics_request_from(message: types.Message, state: FSMContext):
    """Место погрузки"""
    route_from = message.text.strip()
    await state.update_data(route_from=route_from)

    data = await state.get_data()

    await message.answer(
        "🚚 <b>Заявка на логистику</b>\n\n"
        "<b>Шаг 2 из 4</b>\n\n"
        f"Откуда: <b>{route_from}</b>\n"
        f"Куда: <b>{data.get('port', '')}</b>\n\n"
        "Желаемая дата погрузки (ДД.ММ.ГГГГ):",
        parse_mode="HTML",
    )

    await CreateLogisticRequestStatesGroup.loading_date.set()


@dp.message_handler(state=CreateLogisticRequestStatesGroup.loading_date)
async def logistics_request_date(message: types.Message, state: FSMContext):
    """Дата погрузки"""
    loading_date = message.text.strip()

    if not validate_date(loading_date):
        await message.answer(
            "❌ Неверный формат даты. Используйте ДД.ММ.ГГГГ (например: 15.12.2025)"
        )
        return

    await state.update_data(loading_date=loading_date)

    # ✅ НОВЫЙ ШАГ: ОЖИДАЕМАЯ ЦЕНА
    data = await state.get_data()

    await message.answer(
        "🚚 <b>Заявка на логистику</b>\n\n"
        "<b>Шаг 3 из 4</b>\n\n"
        f"Откуда: <b>{data.get('route_from', '')}</b>\n"
        f"Куда: <b>{data.get('port', '')}</b>\n"
        f"Дата: <b>{loading_date}</b>\n\n"
        "Ожидаемая цена доставки за тонну (₽/т):\n"
        "<i>Например: 500 или 1200.5</i>",
        parse_mode="HTML",
    )

    await CreateLogisticRequestStatesGroup.desired_price.set()


@dp.message_handler(state=CreateLogisticRequestStatesGroup.desired_price)
async def logistics_request_desired_price(message: types.Message, state: FSMContext):
    """Ожидаемая цена доставки"""
    try:
        desired_price = float(message.text.replace(",", ".").replace(" ", ""))

        if desired_price <= 0:
            raise ValueError("Цена должна быть больше 0")

        await state.update_data(desired_price=desired_price)

        await message.answer(
            "🚚 <b>Заявка на логистику</b>\n\n"
            "<b>Шаг 4 из 4</b>\n\n"
            "Дополнительные требования (или /skip для пропуска):",
            parse_mode="HTML",
        )

        await CreateLogisticRequestStatesGroup.notes.set()

    except (ValueError, Exception):
        await message.answer(
            "❌ Неверный формат цены. Укажите число (например: 700 или 750.5)"
        )


@dp.message_handler(
    lambda m: m.text == "/skip", state=CreateLogisticRequestStatesGroup.notes
)
@dp.message_handler(state=CreateLogisticRequestStatesGroup.notes)
async def logistics_request_finish(message: types.Message, state: FSMContext):
    """Завершение создания заявки"""
    global logistics_request_counter

    notes = "" if message.text == "/skip" else message.text.strip()
    data = await state.get_data()
    user_id = message.from_user.id

    pull_id = data["pull_id"]

    _, pull = find_pull_by_id(pull_id)
    if not pull:
        await message.answer("❌ Пул не найден. Создание заявки отменено.")
        await state.finish()
        return
    user_role = (get_user_by_id(user_id) or {}).get("role")
    pull_owner_id = pull.get("exporter_id") or pull.get("creator_id")
    if not pull_owner_id:
        await message.answer("❌ Не удалось определить владельца пула.")
        await state.finish()
        return
    exporter = get_user_by_id(pull_owner_id) or {}
    if user_role != "admin" and not same_id(pull_owner_id, user_id):
        await message.answer("❌ Нет доступа к выбранному пулу.")
        await state.finish()
        return
    pull_status = normalize_transition_status(pull.get("status", "active"))
    current_volume = pull.get("current_volume", 0) or 0
    target_volume = pull.get("target_volume", 0) or 0
    is_closed = pull_status == "closed"
    is_full = target_volume > 0 and current_volume >= target_volume
    if not (is_closed or is_full):
        await message.answer(
            "❌ Пул больше не готов для логистики. Обновите данные и попробуйте снова."
        )
        await state.finish()
        return

    has_open_logistics_request = any(
        isinstance(req, dict)
        and same_id(req.get("pull_id"), pull_id)
        and same_id(req.get("exporter_id"), pull_owner_id)
        and normalize_transition_status(req.get("status")) not in {"completed", "cancelled", "rejected"}
        for req in logistics_requests.values()
    )
    if has_open_logistics_request:
        await message.answer(
            "❌ По этому пулу уже есть активная заявка на логистику."
        )
        await state.finish()
        return

    logistics_request_counter += 1

    # ✅ СОЗДАЁМ ЗАЯВКУ С ПОЛЕМ desired_price
    request = {
        "id": logistics_request_counter,
        "exporter_id": pull_owner_id,
        "exporter_name": exporter.get("name", ""),
        "exporter_phone": exporter.get("phone", "Не указан"),
        "exporter_email": exporter.get("email", "Не указан"),
        "pull_id": pull_id,
        "culture": data["culture"],
        "volume": data["volume"],
        "route_from": data["route_from"],
        "route_to": data.get("port", ""),
        "loading_date": data["loading_date"],
        "desired_price": data.get("desired_price", 0),  # ← НОВОЕ!
        "notes": notes,
        "status": "active",
        "offers_count": 0,
        "selected_offer_id": None,
        "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
    }

    logistics_requests[logistics_request_counter] = request
    save_logistics_requests_to_pickle()

    await state.finish()

    # ✅ ПОКАЗЫВАЕМ ОЖИДАЕМУЮ ЦЕНУ В ИТОГЕ
    exporter_inn = exporter.get("inn", "Не указан")
    exporter_ogrn = exporter.get("ogrn", "Не указан")
    exporter_phone = exporter.get("phone", "Не указан")
    exporter_email = exporter.get("email", "Не указан")

    summary = (
        f"✅ <b>Заявка на логистику #{logistics_request_counter} создана!</b>\n\n"
        f"📦 Пул: #{pull_id}\n"
        f"🌾 Культура: {data['culture']}\n"
        f"📦 Объем: {data['volume']:.0f} т\n"
        f"📍 Маршрут: {data['route_from']} → {request['route_to']}\n"
        f"📅 Дата: {data['loading_date']}\n"
        f"💰 Ожидаемая цена: <code>{data.get('desired_price', 0):,.0f}</code> ₽/т\n"
    )

    if notes:
        summary += f"📝 Примечания: {notes}\n"

    summary += (
        f"\n👤 Контакт: {exporter.get('name', '')}\n"
        f"📋 ИНН: <code>{exporter_inn}</code>\n"
        f"📋 ОГРН: <code>{exporter_ogrn}</code>\n"
        f"📞 Телефон: <code>{exporter_phone}</code>\n"
        f"📧 Email: <code>{exporter_email}</code>\n\n"
        "🔔 Логисты получат уведомление о вашей заявке"
    )

    await message.answer(summary, parse_mode="HTML", reply_markup=exporter_keyboard())

    # Уведомляем логистов
    await notify_logistics_about_new_request(request)

    logging.info(
        f"✅ Logistics request {logistics_request_counter} created by exporter {user_id} "
        f"with desired_price {data.get('desired_price', 0)}"
    )


@dp.callback_query_handler(
    lambda c: c.data.startswith("view_logistics_req:"), state="*"
)
async def view_logistics_request_details(
    callback: types.CallbackQuery, state: FSMContext
):
    """Просмотр деталей заявки логиста"""

    await state.finish()

    try:
        req_id = parse_callback_id(callback.data)
    except ValueError as e:
        await callback.answer(f"❌ Ошибка: {e}", show_alert=True)
        return
    if req_id is None:
        await callback.answer("❌ Ошибка данных заявки", show_alert=True)
        return

    # Проверяем наличие заявки (int/str ключи)
    req = logistics_requests.get(req_id) or logistics_requests.get(str(req_id))
    if not isinstance(req, dict):
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    owner_id = (
        req.get("customer_id")
        or req.get("created_by")
        or req.get("exporter_id")
        or req.get("farmer_id")
        or req.get("logist_id")
    )

    if not (
        user_role == "admin"
        or is_logistic_role(user_role)
        or is_expeditor_role(user_role)
        or same_id(owner_id, user_id)
    ):
        await callback.answer("❌ Нет доступа к заявке", show_alert=True)
        return

    if is_logistic_role(user_role):
        req_status_norm = normalize_transition_status(req.get("status"))
        assigned_logist_id = get_assigned_logist_id(req)
        if (
            req_status_norm in {"assigned", "in_progress", "completed", "expeditor_selected"}
            and assigned_logist_id
            and not same_id(assigned_logist_id, user_id)
        ):
            await callback.answer("❌ Нет доступа к этой перевозке", show_alert=True)
            return
    if is_expeditor_role(user_role):
        req_status_norm = normalize_transition_status(req.get("status"))
        assigned_expeditor_id = get_assigned_expeditor_id(req)
        if not has_assigned_logist(req) and not same_id(assigned_expeditor_id, user_id):
            await callback.answer(
                "❌ По заявке ещё не назначен логист", show_alert=True
            )
            return
        if not assigned_expeditor_id:
            if not is_request_open_for_expeditor(req_status_norm):
                await callback.answer("❌ Нет доступа к этой заявке", show_alert=True)
                return
        if (
            req_status_norm in {"expeditor_selected", "in_progress", "completed"}
            and assigned_expeditor_id
            and not same_id(assigned_expeditor_id, user_id)
        ):
            await callback.answer("❌ Нет доступа к этой перевозке", show_alert=True)
            return
    # Проверяем, есть ли у логиста незакрытый оффер по этой заявке
    closed_offer_statuses = {
        "cancelled",
        "canceled",
        "rejected",
        "completed",
        "filled",
        "sold",
        "closed",
        "delivered",
    }
    already_offered = any(
        same_id((o.get("logist_id") or o.get("logistic_id")), user_id)
        and normalize_transition_status(o.get("status")) not in closed_offer_statuses
        for o in logistic_offers.values()
        if logistic_offer_matches_request(o, req_id, "logistics")
    )

    # ✅ ПОЛНАЯ ИНФОРМАЦИЯ О ЗАЯВКЕ
    msg = f"""
📋 <b>ЗАЯВКА #{req_id}</b>

<b>🌾 Информация о грузе:</b>
Культура: {req.get('culture', 'Не указана')}
Объем: {req.get('volume', 0):.0f} т

<b>📍 Маршрут доставки:</b>
От: {req.get('route_from', 'Не указано')}
До: {req.get('route_to', 'Не указано')}

<b>📅 Сроки:</b>
Дата погрузки: {req.get('loading_date', 'Не указана')}
Срок доставки: {req.get('delivery_date', 'Не указан')}

<b>💼 Статистика:</b>
Откликов получено: {count_logistic_offers_for_request(req_id, 'logistics')}
Статус: {req.get('status', 'active')}
"""

    if req.get("notes"):
        msg += f"\n<b>📝 Дополнительно:</b>\n{req['notes']}"

    # Информация о заказчике
    customer_id = (
        req.get("customer_id")
        or req.get("created_by")
        or req.get("farmer_id")
        or req.get("exporter_id")
        or req.get("logist_id")
    )
    customer = (get_user_by_id(customer_id) or {}) if customer_id else {}
    if customer:
        msg += f"""

<b>👨‍🌾 Заказчик:</b>
Имя: {customer.get('name', req.get('exporter_name', 'Не указано'))}
Телефон: <code>{customer.get('phone', req.get('exporter_phone', 'Не указан'))}</code>
Email: <code>{customer.get('email', req.get('exporter_email', 'Не указан'))}</code>
Регион: {customer.get('region', 'Не указан')}
"""
    else:
        msg += f"""

<b>👨‍🌾 Заказчик:</b>
Имя: {req.get('exporter_name', 'Не указано')}
Телефон: <code>{req.get('exporter_phone', 'Не указан')}</code>
Email: <code>{req.get('exporter_email', 'Не указан')}</code>
"""

    keyboard = InlineKeyboardMarkup(row_width=1)

    offers_for_request = [
        (offer_id, offer)
        for offer_id, offer in logistic_offers.items()
        if logistic_offer_matches_request(offer, req_id, "logistics")
    ]
    pending_offers = [
        (offer_id, offer)
        for offer_id, offer in offers_for_request
        if normalize_transition_status(offer.get("status")) in {"pending", "active"}
    ]

    # Кнопка отклика (единый поток: make_offer -> logistic_offers)
    if (
        is_logistic_role(user_role)
        and not already_offered
        and is_request_open_for_offers(req.get("status"))
        and not same_id(owner_id, user_id)
    ):
        keyboard.add(
            InlineKeyboardButton(
                "✅ Откликнуться на заявку",
                callback_data=f"make_offer:logistics:{req_id}",
            )
        )
    elif is_logistic_role(user_role) and already_offered:
        keyboard.add(
            InlineKeyboardButton("✔️ Вы уже откликнулись", callback_data="noop")
        )
    elif (same_id(owner_id, user_id) or user_role == "admin") and not is_expeditor_role(
        user_role
    ):
        msg += (
            "\n\n<b>📬 Отклики логистов:</b>\n"
            f"Всего: {len(offers_for_request)} | "
            f"Ожидают решения: {len(pending_offers)}"
        )
        for offer_id, offer in pending_offers[:5]:
            price = offer.get("price", 0)
            vehicle = offer.get("vehicle_type", "—")
            keyboard.add(
                InlineKeyboardButton(
                    f"💰 {price:,.0f} ₽ | {vehicle}",
                    callback_data=f"view_offer_details_{offer_id}",
                )
            )

    if (
        is_expeditor_role(user_role)
        and is_request_open_for_expeditor(req.get("status"))
        and not has_assigned_expeditor(req)
        and has_assigned_logist(req)
    ):
        keyboard.add(
            InlineKeyboardButton(
                "💼 Откликнуться как экспедитор",
                callback_data=f"expeditor_respond_exporter_request:logistics:{req_id}",
            )
        )

    # Кнопка контакта (если это не ваша заявка)
    if customer_id and not same_id(customer_id, user_id):
        keyboard.add(
            InlineKeyboardButton(
                "📞 Позвонить заказчику",
                url=f"tel:{(get_user_by_id(customer_id) or {}).get('phone', req.get('exporter_phone', ''))}",
            )
        )
        keyboard.add(
            InlineKeyboardButton(
                "💬 Написать в Telegram", url=f"tg://user?id={customer_id}"
            )
        )

    if same_id(owner_id, user_id) or user_role == "admin":
        expeditor_offers_count = count_open_expeditor_request_offers_for_request(
            req_id, "logistics"
        )
        keyboard.add(
            InlineKeyboardButton(
                f"📄 Отклики экспедиторов ({expeditor_offers_count})",
                callback_data=f"view_expeditor_offers_for_request:logistics:{req_id}",
            )
        )
        req_status_norm = normalize_transition_status(req.get("status"))
        if req_status_norm in {
            "pending",
            "active",
            "has_offers",
            "new",
            "open",
            "assigned",
            "expeditor_selected",
            "in_progress",
        }:
            keyboard.add(
                InlineKeyboardButton(
                    "❌ Отменить заявку",
                    callback_data=f"cancel_logistics_request:{req_id}",
                )
            )
        if req_status_norm in {"assigned", "in_progress", "completed", "expeditor_selected"}:
            linked_delivery = None
            for d in deliveries.values():
                if not isinstance(d, dict):
                    continue
                if not same_id(d.get("request_id"), req_id):
                    continue
                delivery_source = str(d.get("source") or "").strip().lower()
                if delivery_source == "logistic":
                    delivery_source = "logistics"
                if delivery_source not in {"exporter", "farmer", "logistics"}:
                    source_candidates = set()
                    request_key = req_id if isinstance(req_id, str) else str(req_id)
                    if req_id in shipping_requests or request_key in shipping_requests:
                        source_candidates.add("exporter")
                    if req_id in logistics_requests or request_key in logistics_requests:
                        source_candidates.add("logistics")
                    if (
                        req_id in farmer_shipping_requests
                        or request_key in farmer_shipping_requests
                        or req_id in farmer_logistics_requests
                        or request_key in farmer_logistics_requests
                    ):
                        source_candidates.add("farmer")
                    if len(source_candidates) == 1:
                        delivery_source = next(iter(source_candidates))
                    else:
                        inferred_source = infer_logistic_offer_source(req_id)
                        if (
                            inferred_source in {"exporter", "farmer", "logistics"}
                            and (not source_candidates or inferred_source in source_candidates)
                        ):
                            delivery_source = inferred_source
                        else:
                            continue
                if delivery_source != "logistics":
                    continue
                delivery_owner_id = (
                    d.get("customer_id")
                    or d.get("created_by")
                    or d.get("exporter_id")
                    or d.get("logist_id")
                )
                if owner_id is not None and not same_id(delivery_owner_id, owner_id):
                    continue
                linked_delivery = d
                break
            if isinstance(linked_delivery, dict):
                delivery_id = linked_delivery.get("id")
                if delivery_id is not None:
                    keyboard.add(
                        InlineKeyboardButton(
                            f"📦 Доставка #{delivery_id}",
                            callback_data=f"view_delivery_{delivery_id}",
                        )
                    )

    back_callback = "back_to_logistics_requests"
    if same_id(owner_id, user_id):
        if user_role == "exporter":
            back_callback = "my_shipping_requests"
        elif is_logistic_role(user_role):
            back_callback = "logist_main_menu"
        else:
            back_callback = "back_to_main"
    elif is_expeditor_role(user_role):
        back_callback = "back_to_exp_requests"
    elif not is_logistic_role(user_role):
        back_callback = "back_to_main"
    keyboard.add(
        InlineKeyboardButton("◀️ Назад к заявкам", callback_data=back_callback)
    )

    await callback.message.edit_text(msg, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("respond_logistics:"), state="*")
async def respond_to_logistics_request(
    callback: types.CallbackQuery, state: FSMContext
):
    """Совместимость: перенаправление старого callback в единый make_offer-поток."""

    try:
        req_id = parse_callback_id(callback.data)
        parts = callback.data.split(":")
        source_hint = parts[1].strip().lower() if len(parts) >= 3 else ""
        if source_hint == "logistic":
            source_hint = "logistics"
        if source_hint not in {"exporter", "farmer", "logistics"}:
            source_hint = ""
    except ValueError:
        await callback.answer("❌ Ошибка", show_alert=True)
        return
    if req_id is None:
        await callback.answer("❌ Ошибка данных заявки", show_alert=True)
        return

    user_id = callback.from_user.id
    if not is_logistic_role((get_user_by_id(user_id) or {}).get("role")):
        await callback.answer("❌ Отклик доступен только логистам", show_alert=True)
        return

    # Ищем заявку в поддерживаемых хранилищах и определяем source
    req = None
    source = ""
    if source_hint == "logistics":
        req = logistics_requests.get(req_id) or logistics_requests.get(str(req_id))
        source = "logistics" if isinstance(req, dict) else ""
    elif source_hint == "exporter":
        _, req = find_shipping_request_by_id(req_id)
        source = "exporter" if isinstance(req, dict) else ""
    elif source_hint == "farmer":
        _, req = find_farmer_request_by_id(req_id)
        source = "farmer" if isinstance(req, dict) else ""

    if not isinstance(req, dict):
        req = logistics_requests.get(req_id) or logistics_requests.get(str(req_id))
        source = "logistics" if isinstance(req, dict) else source
    if not isinstance(req, dict):
        _, req = find_shipping_request_by_id(req_id)
        source = "exporter" if isinstance(req, dict) else source
    if not isinstance(req, dict):
        _, req = find_farmer_request_by_id(req_id)
        source = "farmer" if isinstance(req, dict) else source

    if not isinstance(req, dict):
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    req_id = req.get("id", req_id)
    if not is_request_open_for_offers(req.get("status")):
        await callback.answer("❌ Заявка уже не принимает отклики", show_alert=True)
        return
    if get_assigned_logist_id(req):
        await callback.answer("❌ По заявке уже назначен логист", show_alert=True)
        return

    # Делегируем в единый поток создания оффера
    callback.data = f"make_offer:{source}:{req_id}"
    await make_offer_start(callback, state)


@dp.message_handler(state=LogisticOfferStates.price)
async def logistics_offer_price(message: types.Message, state: FSMContext):
    """Цена за перевозку"""
    try:
        price = float(message.text.strip().replace(",", ".").replace(" ", ""))
        if price <= 0:
            raise ValueError

        await state.update_data(price=price)

        await message.answer(
            "💼 <b>Отклик на заявку</b>\n\n"
            "<b>Шаг 2 из 4</b>\n\n"
            f"Цена: <b>{price:,.0f} ₽/т</b>\n\n"
            "Тип транспорта (например: Фура 20т, Зерновоз):",
            parse_mode="HTML",
        )

        await LogisticOfferStates.vehicle_type.set()

    except ValueError:
        await message.answer("❌ Некорректная цена. Введите положительное число.")


@dp.message_handler(state=LogisticOfferStates.vehicle_type)
async def logistics_offer_vehicle(message: types.Message, state: FSMContext):
    """Тип транспорта"""
    vehicle_type = message.text.strip()
    await state.update_data(vehicle_type=vehicle_type)

    await message.answer(
        "💼 <b>Отклик на заявку</b>\n\n"
        "<b>Шаг 3 из 4</b>\n\n"
        f"Транспорт: <b>{vehicle_type}</b>\n\n"
        "Срок доставки (дней):",
        parse_mode="HTML",
    )

    await LogisticOfferStates.delivery_date.set()


@dp.message_handler(state=LogisticOfferStates.delivery_date)
async def logistics_offer_days(message: types.Message, state: FSMContext):
    """Срок доставки"""
    try:
        delivery_days = int(message.text.strip())
        if delivery_days <= 0:
            raise ValueError

        await state.update_data(delivery_days=delivery_days)

        await message.answer(
            "💼 <b>Отклик на заявку</b>\n\n"
            "<b>Шаг 4 из 4</b>\n\n"
            f"Срок: <b>{delivery_days} дней</b>\n\n"
            "Дополнительная информация (или /skip):",
            parse_mode="HTML",
        )

        await LogisticOfferStates.additional_info.set()

    except ValueError:
        await message.answer("❌ Некорректный срок. Введите целое число дней.")


# ============================================================================
# 🚛 ЗАВЕРШЕНИЕ ОТКЛИКА ЛОГИСТА НА ЗАЯВКУ
# ============================================================================


@dp.message_handler(
    lambda m: m.text == "/skip", state=LogisticOfferStates.additional_info
)
@dp.message_handler(state=LogisticOfferStates.additional_info)
async def logistics_offer_finish(message: types.Message, state: FSMContext):
    """Завершение отклика логиста"""
    global logistics_offer_counter

    notes = "" if message.text == "/skip" else message.text.strip()
    data = await state.get_data()
    user_id = message.from_user.id

    req_id = data.get("request_id")
    if req_id is None:
        await message.answer(
            "❌ Не удалось определить заявку. Откройте её снова из списка и повторите отклик."
        )
        await state.finish()
        return
    req = logistics_requests.get(req_id) or logistics_requests.get(str(req_id))
    logist_user = get_user_by_id(user_id) or {}

    if not isinstance(req, dict):
        await message.answer("❌ Заявка не найдена. Попробуйте ещё раз.")
        await state.finish()
        return
    if not is_request_open_for_offers(req.get("status")):
        await message.answer("❌ Заявка уже не принимает отклики.")
        await state.finish()
        return
    if get_assigned_logist_id(req):
        await message.answer("❌ По заявке уже назначен логист.")
        await state.finish()
        return

    duplicate_offer = next(
        (
            o
            for o in logistic_offers.values()
            if logistic_offer_matches_request(o, req_id, "logistics")
            and same_id((o.get("logist_id") or o.get("logistic_id")), user_id)
            and normalize_transition_status(o.get("status"))
            not in {"cancelled", "canceled", "rejected", "completed"}
        ),
        None,
    )
    if duplicate_offer:
        await message.answer("❌ У вас уже есть активный отклик по этой заявке.")
        await state.finish()
        return

    offer_id = next_numeric_id(logistic_offers)
    logistics_offer_counter = max(logistics_offer_counter, offer_id)

    offer = {
        "id": offer_id,
        "request_id": req_id,
        "logist_id": user_id,
        "logist_name": logist_user.get("name", "N/A"),
        "logist_phone": logist_user.get("phone", "N/A"),
        "logist_email": logist_user.get("email", "N/A"),
        "price": data["price"],
        "vehicle_type": data["vehicle_type"],
        "delivery_days": data["delivery_days"],
        "notes": notes,
        "status": "pending",
        "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "source": "logistics",
    }

    logistic_offers[offer_id] = offer

    # Обновляем счётчик откликов в заявке
    req["offers_count"] = count_logistic_offers_for_request(req_id, "logistics")
    if is_request_open_for_offers(req.get("status")):
        req["status"] = "has_offers"

    save_logistics_requests_to_pickle()
    save_logistics_offers_to_pickle()

    await state.finish()

    # РАСЧЁТ ИТОГОВОЙ СУММЫ
    total_price = data["price"] * req["volume"]

    # ИТОГОВОЕ СООБЩЕНИЕ ЛОГИСТУ
    summary = (
        "✅ <b>Отклик отправлен!</b>\n\n"
        f"📋 Заявка: #{req_id}\n"
        f"🌾 {req['culture']} • {req['volume']:.0f} т\n"
        f"📍 {req['route_from']} → {req['route_to']}\n\n"
        f"💰 <b>Ваша цена:</b> <code>{data['price']:,.0f}</code> ₽/т\n"
        f"💵 <b>Общая сумма:</b> <code>{total_price:,.0f}</code> ₽\n"
        f"🚛 <b>Транспорт:</b> {data['vehicle_type']}\n"
        f"⏱ <b>Срок:</b> {data['delivery_days']} дн.\n\n"
        f"👤 Логист: {logist_user.get('name', 'N/A')}\n"
        f"☎️ <code>{logist_user.get('phone', 'N/A')}</code>\n"
        f"📧 <code>{logist_user.get('email', 'N/A')}</code>\n\n"
        "Экспортёр получит уведомление о вашем отклике."
    )

    await message.answer(summary, parse_mode="HTML", reply_markup=logistic_keyboard())

    # Уведомляем экспортёра
    await notify_exporter_about_offer(req, offer)

    logging.info(
        f"✅ Logistics offer {offer_id} created by logist {user_id}"
    )


# ============================================================================
# 🔔 ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ УВЕДОМЛЕНИЙ
# ============================================================================
async def notify_logistics_about_new_request(request: dict):
    """Уведомление логистов о новой заявке на логистику от экспортёра."""
    logistics_users = []
    seen_logist_ids = set()
    for uid, u in users.items():
        if not isinstance(u, dict):
            continue
        if not is_logistic_role(u.get("role")):
            continue
        normalized_uid = int(uid) if str(uid).isdigit() else uid
        uid_key = str(normalized_uid)
        if uid_key in seen_logist_ids:
            continue
        seen_logist_ids.add(uid_key)
        logistics_users.append(normalized_uid)

    desired_date = (
        request.get("loading_date")
        or request.get("desired_date")
        or "Не указана"
    )
    culture = request.get("culture", "—")
    volume = request.get("volume", 0) or 0
    route_from = request.get("route_from", "—")
    route_to = request.get("route_to", "—")
    desired_price = request.get("desired_price", 0) or 0

    msg = (
        f"✅ <b>Заявка на логистику #{request.get('id','-')}</b>\n\n"
        f"📦 Пул: #{request.get('pull_id','-')}\n"
        f"🌾 Культура: {culture}\n"
        f"📊 Объём: {volume:.0f} т\n"
        f"📍 Маршрут: {route_from} → {route_to}\n"
        f"📅 Дата погрузки: {desired_date}\n"
        f"💰 Ожидаемая цена: {desired_price:,.0f} ₽/т\n\n"
        f"👤 Экспортёр: {request.get('exporter_name','-')}\n"
        f"☎️ <code>{request.get('exporter_phone','-')}</code>\n"
        f"📧 <code>{request.get('exporter_email','Не указан')}</code>\n\n"
        "💼 Откликнитесь через меню <b>«Активные заявки»</b>."
    )

    for logist_id in logistics_users:
        try:
            await bot.send_message(logist_id, msg, parse_mode="HTML")
            logging.info(
                f"✅ Notified logist {logist_id} about request #{request.get('id','-')}"
            )
        except Exception as e:
            logging.error(f"❌ Error notifying logist {logist_id}: {e}")


async def notify_exporter_about_offer(request: dict, offer: dict):
    """Уведомление экспортёра о новом отклике логиста на заявку (расширенное)."""
    exporter_id = request.get("exporter_id")
    if not exporter_id:
        logging.warning("notify_exporter_about_offer: exporter_id is missing")
        return

    # Параметры заявки
    req_id = request.get("id", "-")
    pull_id = request.get("pull_id", "-")
    culture = request.get("culture", "—")
    volume = request.get("volume", 0) or 0
    route_from = request.get("route_from", "—")
    route_to = request.get("route_to", "—")
    desired_date = request.get("loading_date") or request.get("desired_date") or "Не указана"
    desired_price = request.get("desired_price", 0) or 0

    # Параметры предложения логиста
    price = offer.get("price", 0) or 0
    total_price = price * volume
    vehicle_type = offer.get("vehicle_type", "-")
    delivery_days = offer.get("delivery_days") or offer.get("delivery_date") or "-"
    notes = offer.get("notes") or offer.get("additional_info") or ""

    # Контакты логиста из offer
    logist_name = offer.get("logist_name", "-")
    logist_phone = offer.get("logist_phone", "-")
    logist_email = offer.get("logist_email", "-")
    logist_id = get_offer_logist_id(offer)

    # Реквизиты логиста из users
    company = "Не указана"
    inn = "Не указан"
    ogrn = "Не указан"
    username = None
    if get_user_by_id(logist_id):
        lu = get_user_by_id(logist_id) or {}
        company = lu.get("company_details") or lu.get("company_name") or company
        inn = lu.get("inn", inn)
        ogrn = lu.get("ogrn", ogrn)
        username = lu.get("username")

    msg = (
        "📬 <b>Новый отклик логиста на вашу заявку</b>\n\n"
        f"📦 <b>Заявка #{req_id}</b>\n"
        f"Пул: <b>#{pull_id}</b>\n"
        f"🌾 Культура: <b>{culture}</b>\n"
        f"📊 Объём: <b>{volume:.0f} т</b>\n"
        f"📍 Маршрут: <b>{route_from} → {route_to}</b>\n"
        f"📅 Желаемая дата погрузки: <b>{desired_date}</b>\n"
        f"💰 Ваша ожидаемая цена: <b>{desired_price:,.0f} ₽/т</b>\n\n"
        "🚚 <b>Предложение логиста</b>\n"
        f"   • Цена доставки: <b>{price:,.0f} ₽/т</b>\n"
        f"   • Сумма логистики: <b>{total_price:,.0f} ₽</b>\n"
        f"   • Транспорт: <b>{vehicle_type}</b>\n"
        f"   • Срок доставки: <b>{delivery_days} дн.</b>\n"
    )

    if notes:
        msg += f"   • Условия: <b>{notes}</b>\n"

    msg += (
        "\n👤 <b>Логист</b>\n"
        f"   • Имя: <b>{logist_name}</b>\n"
        f"   • Компания: <b>{company}</b>\n"
        f"   • ИНН: <code>{inn}</code>\n"
        f"   • ОГРН: <code>{ogrn}</code>\n"
        f"   • Телефон: <code>{logist_phone}</code>\n"
        f"   • Email: <code>{logist_email}</code>\n"
    )
    if username:
        msg += f"   • Telegram: @{username}\n"

    msg += (
        "\n💡 Откройте раздел <b>Мои заявки</b>, чтобы сравнить все предложения "
        "и выбрать логиста."
    )

    try:
        await bot.send_message(exporter_id, msg, parse_mode="HTML")
        logging.info(
            f"✅ Notified exporter {exporter_id} about offer #{offer.get('id','-')}"
        )
    except Exception as e:
        logging.error(f"❌ Error notifying exporter {exporter_id}: {e}")


