@dp.callback_query_handler(lambda c: c.data == "back_to_logistics_requests", state="*")
async def back_to_logistics_requests_handler(
    callback: types.CallbackQuery, state: FSMContext
):
    """Возврат к списку активных заявок"""
    await state.finish()
    user_role = (get_user_by_id(callback.from_user.id) or {}).get("role")
    if is_logistic_role(user_role) or user_role == "admin":
        await show_logistic_requests_list(callback, state)
    else:
        await callback.answer("❌ Раздел доступен только логистам", show_alert=True)
    return


@dp.callback_query_handler(lambda c: c.data == "noop", state="*")
async def noop_handler(callback: types.CallbackQuery):
    """Пустой обработчик для кнопок без действия"""
    await callback.answer()


