@dp.message_handler(state=CreateLogisticCardStates.additional_info)
async def save_logistic_card(message: types.Message, state: FSMContext):
    """Финальный шаг — сохранение карточки логиста в logistics_cards."""
    additional_raw = (message.text or "").strip()
    additional = "" if additional_raw.lower() == "нет" else additional_raw

    await state.update_data(additional_info=additional)
    data = await state.get_data()

    user_id = message.from_user.id
    user_data = get_user_by_id(user_id) or {}

    # Собираем карточку в единый формат
    routes = data.get("routes", "")
    price_per_km = safe_float(data.get("price_per_km", 0))
    price_per_ton = safe_float(data.get("price_per_ton", 0))
    min_volume = safe_float(data.get("min_volume", 0))
    transport_type = data.get("transport_type", "Не указано")
    ports = data.get("ports", [])
    additional_info = data.get("additional_info", "")

    logistics_cards[user_id] = {
        # Основные данные карточки
        "user_id": user_id,
        "routes": routes,
        "price_per_km": price_per_km,
        "price_per_ton": price_per_ton,
        "min_volume": min_volume,
        "transport_type": transport_type,
        "ports": ports,  # список портов
        "additional_info": additional_info,
        # Метаданные карточки
        "status": "active",
        "created_at": datetime.now().strftime("%d.%m.%Y %H:%M"),
        "views": 0,
        # Контакты пользователя
        "name": user_data.get("name", "Не указано"),
        "username": user_data.get("username", ""),
        "phone": user_data.get("phone", "Не указан"),
        "email": user_data.get("email", "Не указан"),
        # Реквизиты компании
        "company": user_data.get("company_details", "Не указана"),
        "inn": user_data.get("inn", "Не указан"),
        "ogrn": user_data.get("ogrn", "Не указан"),
        "region": user_data.get("region", "Не указан"),
        # Роль (для удобства фильтрации)
        "role": user_data.get("role", "logistic"),
    }

    save_logistics_cards_to_pickle()

    await state.finish()
    await message.answer(
        "✅ <b>Карточка логиста создана!</b>\n\n"
        "Теперь экспортёры будут получать вашу карточку при закрытии пулов.",
        parse_mode="HTML",
    )

    logging.info(f"✅ Logistic card created for user {user_id}")


