# ====================================================================
@dp.callback_query_handler(lambda c: c.data.startswith("select_logistic_"))
async def select_logistic_handler(callback: types.CallbackQuery):
    """Выбор логиста для сделки (legacy-сценарий после закрытия пула),
    с полными контактами логиста и экспортёра.
    """
    try:
        parts = callback.data.split("_")
        logistic_id = int(parts[2])
        deal_id = int(parts[3])

        resolved_deal_id, deal = find_deal_by_id(deal_id)
        if not deal:
            await callback.answer("❌ Сделка не найдена", show_alert=True)
            return
        deal_id = resolved_deal_id
        user_id = callback.from_user.id
        user_role = (get_user_by_id(user_id) or {}).get("role")
        if not (user_role == "admin" or same_id(deal.get("exporter_id"), user_id)):
            await callback.answer("❌ Нет доступа", show_alert=True)
            return
        deal_status = normalize_transition_status(deal.get("status"))
        if deal_status in {"completed", "cancelled", "canceled"}:
            await callback.answer("❌ Сделка уже закрыта", show_alert=True)
            return
        if not is_logistic_role((get_user_by_id(logistic_id) or {}).get("role")):
            await callback.answer("❌ Пользователь не является логистом", show_alert=True)
            return
        if deal.get("logistic_id"):
            await callback.answer("❌ По сделке уже выбран логист", show_alert=True)
            return

        deal["logistic_id"] = logistic_id
        deal["logistic_selected_at"] = datetime.now().strftime(
            "%Y-%m-%d %H:%M:%S"
        )
        save_deals_to_pickle()

        # --- карточка для экспортёра ---
        logistic = get_user_by_id(logistic_id) or {}
        inn = logistic.get("inn", "Не указано")
        ogrn = logistic.get("ogrn", "Не указано")
        company = (
            logistic.get("company_details")
            or logistic.get("company_name")
            or logistic.get("company")
            or "Не указано"
        )
        phone = logistic.get("phone", "Не указано")
        email = logistic.get("email", "Не указано")
        username = logistic.get("username")

        text = (
            "✅ <b>Логист выбран!</b>\n\n"
            f"👤 Контакт: {logistic.get('name', 'Не указано')}\n"
            f"🏢 Компания: {company}\n"
            f"📋 ИНН: <code>{inn}</code>\n"
            f"📋 ОГРН: <code>{ogrn}</code>\n"
            f"📞 Телефон: <code>{phone}</code>\n"
            f"📧 Email: <code>{email}</code>\n"
        )
        if username:
            text += f"💬 Telegram: @{username}\n"

        await callback.message.edit_text(text, parse_mode="HTML")

        # --- уведомление логисту с контактами экспортёра ---
        pull_id = deal.get("pull_id")
        all_pulls = pulls.get("pulls", {}) if isinstance(pulls, dict) else {}
        pull = all_pulls.get(pull_id) or all_pulls.get(str(pull_id), {})

        exporter_id = deal.get("exporter_id") or pull.get("exporter_id")
        exporter = (get_user_by_id(exporter_id) or {}) if exporter_id else {}
        exporter_name = exporter.get("name", "Не указано")
        exporter_phone = exporter.get("phone", "Не указан")
        exporter_email = exporter.get("email", "Не указан")
        exporter_username = exporter.get("username")

        try:
            msg = (
                "🎉 <b>ВЫ ВЫБРАНЫ ЛОГИСТОМ ПО СДЕЛКЕ!</b>\n\n"
                f"📦 Сделка #{deal_id}\n"
                f"🌾 Культура: {pull.get('culture', 'Н/Д')}\n"
                f"🎯 Объём: {pull.get('current_volume', 0)} т\n"
                f"🚢 Порт: {pull.get('port', 'Не указано')}\n\n"
                f"👤 <b>Экспортёр:</b> {exporter_name}\n"
                f"📞 Телефон: <code>{exporter_phone}</code>\n"
                f"📧 Email: <code>{exporter_email}</code>\n"
            )
            if exporter_username:
                msg += f"💬 Telegram: @{exporter_username}\n"

            await bot.send_message(logistic_id, msg, parse_mode="HTML")
            logging.info(
                f"✅ Логист {logistic_id} уведомлён о выборе для сделки {deal_id}"
            )
        except Exception as e:
            logging.error(f"Ошибка при отправке уведомления логисту {logistic_id}: {e}")

        logging.info(f"✅ Логист {logistic_id} выбран для сделки {deal_id}")
        await callback.answer("✅ Логист выбран")

    except Exception as e:
        logging.error(f"Ошибка при выборе логиста: {e}")
        await callback.answer("❌ Ошибка", show_alert=True)


