@dp.callback_query_handler(
    lambda c: c.data.startswith("select_expeditor_")
    and not c.data.startswith("select_expeditor_for_pull:")
)
async def select_expeditor_handler(callback: types.CallbackQuery):
    """Выбор экспедитора для сделки (legacy-сценарий после закрытия пула),
    с полными контактами экспедитора и экспортёра.
    """
    try:
        parts = callback.data.split("_")
        expeditor_id = int(parts[2])
        deal_id = int(parts[3])

        resolved_deal_id, deal = find_deal_by_id(deal_id)
        if not deal:
            await callback.answer("❌ Сделка не найдена", show_alert=True)
            return
        deal_id = resolved_deal_id
        user_id = callback.from_user.id
        user_role = (get_user_by_id(user_id) or {}).get("role")
        if not (user_role == "admin" or same_id(deal.get("exporter_id"), user_id)):
            await callback.answer("❌ Нет доступа", show_alert=True)
            return
        deal_status = normalize_transition_status(deal.get("status"))
        if deal_status in {"completed", "cancelled", "canceled"}:
            await callback.answer("❌ Сделка уже закрыта", show_alert=True)
            return
        if not is_expeditor_role((get_user_by_id(expeditor_id) or {}).get("role")):
            await callback.answer(
                "❌ Пользователь не является экспедитором", show_alert=True
            )
            return
        if deal.get("expeditor_id"):
            await callback.answer("❌ По сделке уже выбран экспедитор", show_alert=True)
            return

        deal["expeditor_id"] = expeditor_id
        deal["expeditor_selected_at"] = datetime.now().strftime(
            "%Y-%m-%d %H:%M:%S"
        )
        save_deals_to_pickle()

        # --- карточка для экспортёра ---
        expeditor = get_user_by_id(expeditor_id) or {}
        company = (
            expeditor.get("company_details")
            or expeditor.get("company_name")
            or expeditor.get("company")
            or expeditor.get("name")
            or "Не указано"
        )
        phone = expeditor.get("phone", "Не указано")
        email = expeditor.get("email", "Не указано")
        username = expeditor.get("username")

        text = (
            "✅ <b>Экспедитор выбран!</b>\n\n"
            f"📜 Компания: {company}\n"
            f"👤 Контакт: {expeditor.get('name', 'Не указано')}\n"
            f"📞 Телефон: <code>{phone}</code>\n"
            f"📧 Email: <code>{email}</code>\n"
        )
        if username:
            text += f"💬 Telegram: @{username}\n"

        await callback.message.edit_text(text, parse_mode="HTML")

        # --- уведомление экспедитору с контактами экспортёра ---
        pull_id = deal.get("pull_id")
        all_pulls = pulls.get("pulls", {}) if isinstance(pulls, dict) else {}
        pull = all_pulls.get(pull_id) or all_pulls.get(str(pull_id), {})

        exporter_id = deal.get("exporter_id") or pull.get("exporter_id")
        exporter = (get_user_by_id(exporter_id) or {}) if exporter_id else {}
        exporter_name = exporter.get("name", "Не указано")
        exporter_phone = exporter.get("phone", "Не указан")
        exporter_email = exporter.get("email", "Не указан")
        exporter_username = exporter.get("username")

        try:
            msg = (
                "🎉 <b>ВЫ ВЫБРАНЫ ЭКСПЕДИТОРОМ ПО СДЕЛКЕ!</b>\n\n"
                f"📦 Сделка #{deal_id}\n"
                f"🌾 Культура: {pull.get('culture', 'Н/Д')}\n"
                f"🎯 Объём: {pull.get('current_volume', 0)} т\n"
                f"🚢 Порт: {pull.get('port', 'Не указано')}\n\n"
                f"👤 <b>Экспортёр:</b> {exporter_name}\n"
                f"📞 Телефон: <code>{exporter_phone}</code>\n"
                f"📧 Email: <code>{exporter_email}</code>\n"
            )
            if exporter_username:
                msg += f"💬 Telegram: @{exporter_username}\n"

            await bot.send_message(expeditor_id, msg, parse_mode="HTML")
        except Exception as e:
            logging.error(f"Ошибка уведомления экспедитора {expeditor_id}: {e}")

        logging.info(f"✅ Expeditor {expeditor_id} selected for deal {deal_id}")
        await callback.answer("✅ Экспедитор выбран")

    except Exception as e:
        logging.error(f"Error selecting expeditor: {e}")
        await callback.answer("❌ Ошибка", show_alert=True)


