@dp.callback_query_handler(lambda c: c.data.startswith("viewoffer:"), state="*")
async def view_offer_details_callback(callback: types.CallbackQuery, state: FSMContext):
    """Legacy-роут: перенаправляет на актуальный экран деталей своего предложения."""
    await state.finish()

    try:
        offer_ref = callback.data.split(":", 1)[1]
        offer_id = int(offer_ref) if str(offer_ref).isdigit() else offer_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return

    resolved_offer_id, offer = find_logistic_offer_by_id(offer_id)
    if not offer:
        await callback.answer("❌ Предложение не найдено", show_alert=True)
        return
    offer_id = resolved_offer_id
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if not (
        user_role == "admin"
        or same_id(get_offer_logist_id(offer), user_id)
        or same_id(offer.get("logistic_id"), user_id)
    ):
        await callback.answer("❌ Нет доступа к предложению", show_alert=True)
        return

    # Единый экран уже покрывает exporter/farmer/logistics и все актуальные статусы.
    callback.data = f"view_my_offer_{offer_id}"
    await view_my_offer_details(callback, state)


