@dp.message_handler(state=EditCardStates.description, content_types=["text"])
async def save_edit_description(message: types.Message, state: FSMContext):
    """Сохранить новое описание компании"""
    user_id = message.from_user.id
    description_text = message.text.strip()

    if user_id not in logistics_cards:
        await message.answer(
            "❌ <b>Карточка не найдена</b>\n\nПожалуйста, создайте карточку заново",
            parse_mode="HTML",
        )
        await state.finish()
        return

    try:
        if len(description_text) < 10:
            await message.answer(
                "❌ <b>Описание слишком короткое</b>\n\n"
                f"Введено: <b>{len(description_text)}</b> символов\n"
                "Требуется: минимум <b>10</b> символов",
                parse_mode="HTML",
            )
            return

        if len(description_text) > 1000:
            await message.answer(
                "❌ <b>Описание слишком длинное</b>\n\n"
                f"Введено: <b>{len(description_text)}</b> символов\n"
                "Максимум: <b>1000</b> символов",
                parse_mode="HTML",
            )
            return

        forbidden_chars = ["<script", "<?php", "javascript:", "onclick", "onerror"]
        dl = description_text.lower()
        for fch in forbidden_chars:
            if fch in dl:
                await message.answer(
                    "❌ <b>Описание содержит недопустимые конструкции</b>\n\n"
                    "Пожалуйста, используйте только текст",
                    parse_mode="HTML",
                )
                return

        old_description = logistics_cards[user_id].get(
            "description"
        ) or logistics_cards[user_id].get("additional_info", "не установлено")

        description_cleaned = " ".join(description_text.split())

        logistics_cards[user_id]["description"] = description_cleaned
        logistics_cards[user_id]["updated_at"] = datetime.now().strftime(
            "%d.%m.%Y %H:%M:%S"
        )
        save_logistics_cards_to_pickle()

        preview_old = (
            old_description[:80] + "..."
            if len(str(old_description)) > 80
            else old_description
        )
        preview_new = (
            description_cleaned[:80] + "..."
            if len(description_cleaned) > 80
            else description_cleaned
        )

        text = (
            "✅ <b>Описание обновлено</b>\n\n"
            "<b>📊 Статистика:</b>\n"
            f"📝 Символов: <b>{len(description_cleaned)}</b>\n"
            f"📄 Слов: <b>{len(description_cleaned.split())}</b>\n\n"
            "<b>Новое описание:</b>\n"
            f"<i>{preview_new}</i>\n\n"
            f"⏰ Обновлено: <i>{logistics_cards[user_id]['updated_at']}</i>"
        )

        keyboard = InlineKeyboardMarkup()
        keyboard.add(
            InlineKeyboardButton(
                "✏️ Редактировать ещё", callback_data="edit_logistic_card"
            ),
            InlineKeyboardButton("📋 К карточке", callback_data="refresh_card"),
        )

        await message.answer(text, reply_markup=keyboard, parse_mode="HTML")

        logging.info(
            f"Логист {user_id} обновил описание: '{preview_old}' → '{preview_new}'"
        )

        await state.finish()

    except Exception as e:
        logging.error(f"Ошибка при сохранении описания: {e}", exc_info=True)
        await message.answer(
            "❌ <b>Ошибка при сохранении</b>\n\nПопробуйте ещё раз",
            parse_mode="HTML",
        )


# ============================================================================
# 🎫 ПОКАЗ КАРТОЧКИ ПОСЛЕ РЕДАКТИРОВАНИЯ
# ============================================================================
async def show_card_after_edit(message: types.Message, user_id: int):
    """
    Показать карточку логиста - краткая версия
    """
    if user_id not in logistics_cards:
        keyboard = InlineKeyboardMarkup()
        keyboard.add(
            InlineKeyboardButton("➕ Создать", callback_data="create_logistic_card")
        )

        await message.answer(
            "❌ Карточка не найдена", reply_markup=keyboard, parse_mode="HTML"
        )
        return

    card = logistics_cards[user_id]

    vehicle_map = {
        "truck": ("🚛", "Фура"),
        "grain": ("🚚", "Зерновоз"),
        "wagon": ("🚂", "Ж/д вагон"),
    }

    code = card.get("vehicle_type") or card.get("transport_type_code", "truck")
    emoji, vehicle_name = vehicle_map.get(
        code, ("🚛", card.get("transport_type", "Не указан"))
    )

    capacity = card.get("capacity", 0)
    if isinstance(capacity, (int, float)) and capacity > 0:
        capacity_text = f"{capacity} т"
    else:
        capacity_text = "❓"

    # Регионы/маршруты: сначала regions, иначе routes
    if card.get("regions"):
        regions_text = ", ".join(card.get("regions", []))
    else:
        # routes может быть строкой или списком
        routes = card.get("routes", "")
        if isinstance(routes, list):
            regions_text = ", ".join(routes) if routes else "❓"
        else:
            regions_text = routes or "❓"

    ports = ", ".join(card.get("ports", [])) if card.get("ports") else "❓"

    price = safe_float(card.get("price_per_km", 0))
    price_text = f"{price:.2f} ₽/км" if price > 0 else "❓"

    description = card.get("description") or card.get("additional_info", "Не указано")

    text = (
        "🎫 <b>Карточка логиста</b>\n\n"
        f"{emoji} <b>{vehicle_name}</b>\n"
        f"📦 {capacity_text}\n"
        f"📍 Регионы/маршруты: {regions_text}\n"
        f"🚢 Порты: {ports}\n"
        f"💰 {price_text}\n\n"
        f"{description}\n\n"
        f"👁 Просмотров: {card.get('views', 0)}\n"
        f"✅ Завершено: {card.get('completed_deals', 0)}"
    )

    keyboard = InlineKeyboardMarkup(row_width=2)
    keyboard.add(
        InlineKeyboardButton("✏️ Редактировать", callback_data="edit_logistic_card"),
        InlineKeyboardButton("🗑 Удалить", callback_data="delete_logistic_card"),
    )

    try:
        if hasattr(message, "edit_text"):
            await message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        else:
            await message.answer(text, reply_markup=keyboard, parse_mode="HTML")
    except Exception as e:
        logging.error(f"Ошибка при показе карточки: {e}")
        await message.answer(text, reply_markup=keyboard, parse_mode="HTML")


