@dp.callback_query_handler(lambda c: c.data == "back_to_card", state="*")
async def back_to_card(callback: types.CallbackQuery, state: FSMContext):
    """Вернуться к карточке логиста"""
    user_id = callback.from_user.id

    try:
        await state.finish()
        await show_card_after_edit(callback.message, user_id)
        await callback.answer()
        logging.info(f"Логист {user_id} вернулся к карточке")
    except Exception as e:
        logging.error(f"Ошибка при возврате к карточке: {e}", exc_info=True)
        try:
            await callback.answer("❌ Ошибка", show_alert=True)
        except Exception as answer_error:
            logging.debug(f"Не удалось отправить callback.answer в back_to_card: {answer_error}")


@dp.callback_query_handler(lambda c: c.data == "refresh_card", state="*")
async def refresh_logistic_card(callback: types.CallbackQuery, state: FSMContext):
    """Обновить экран карточки логиста."""
    await state.finish()
    await show_card_after_edit(callback.message, callback.from_user.id)
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data == "delete_logistic_card", state="*")
async def delete_logistic_card(callback: types.CallbackQuery, state: FSMContext):
    """Удаление карточки логиста."""
    await state.finish()
    user_id = callback.from_user.id

    if user_id not in logistics_cards:
        await callback.answer("❌ Карточка не найдена", show_alert=True)
        return

    del logistics_cards[user_id]
    save_logistics_cards_to_pickle()

    await callback.message.edit_text(
        "🗑 <b>Карточка логиста удалена</b>\n\n"
        "Вы можете создать новую карточку в любой момент.",
        parse_mode="HTML",
        reply_markup=InlineKeyboardMarkup().add(
            InlineKeyboardButton("➕ Создать карточку", callback_data="create_logistic_card")
        ),
    )
    await callback.answer("✅ Карточка удалена", show_alert=True)


