@dp.message_handler(lambda m: m.text == "📋 Создать предложение", state="*")
async def expeditor_create_offer_handler(message: types.Message, state: FSMContext):
    """Начать создание предложения экспедитора"""
    await state.finish()
    user_id = message.from_user.id

    if not is_expeditor_role((get_user_by_id(user_id) or {}).get("role")):
        await message.answer("❌ Доступ запрещен.")
        return

    await ExpeditorOfferStates.service_type.set()
    await message.answer(
        "<b>📋 Создание предложения</b>\n\n<b>Выберите тип услуги:</b>",
        reply_markup=expeditor_service_keyboard(),
        parse_mode="HTML",
    )


@dp.callback_query_handler(
    lambda c: c.data.startswith("service:"), state=ExpeditorOfferStates.service_type
)
async def set_service_type(callback: types.CallbackQuery, state: FSMContext):
    """Установить тип услуги"""
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if not is_expeditor_role(user_role):
        await state.finish()
        await callback.answer("❌ Доступно только экспедиторам", show_alert=True)
        return

    parts = callback.data.split(":")
    if len(parts) < 2:
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return
    service_type = parts[1]
    service_names = {
        "docs": "📄 Оформление документов",
        "customs": "🏢 Таможенное оформление",
        "freight": "🚢 Фрахтование",
        "full": "📦 Полный комплекс услуг",
    }
    if service_type not in service_names:
        await callback.answer("❌ Некорректный тип услуги", show_alert=True)
        return

    await state.update_data(service_type=service_names.get(service_type, service_type))
    await ExpeditorOfferStates.ports.set()

    await callback.message.edit_text(
        "<b>🏢 Укажите порты обслуживания:</b>\n\n"
        f"Выбрана услуга: {service_names.get(service_type, service_type)}\n\n"
        "Введите порты через запятую:\n<code>Новороссийск, Ростов-на-Дону</code>",
        parse_mode="HTML",
    )
    await callback.answer()


@dp.message_handler(state=ExpeditorOfferStates.ports)
async def set_expeditor_ports(message: types.Message, state: FSMContext):
    """Установить порты обслуживания"""
    user_role = (get_user_by_id(message.from_user.id) or {}).get("role")
    if not is_expeditor_role(user_role):
        await state.finish()
        await message.answer("❌ Доступно только экспедиторам.")
        return

    ports = message.text.strip()

    if len(ports) < 3:
        await message.answer("❌ Слишком короткое название портов")
        return

    await state.update_data(ports=ports)
    await ExpeditorOfferStates.price.set()
    await message.answer(
        "<b>💰 Укажите стоимость услуг (₽):</b>\n\nВведите цену: <code>50000</code>",
        parse_mode="HTML",
    )


@dp.message_handler(state=ExpeditorOfferStates.price)
async def set_expeditor_price(message: types.Message, state: FSMContext):
    """Установить цену услуги"""
    user_role = (get_user_by_id(message.from_user.id) or {}).get("role")
    if not is_expeditor_role(user_role):
        await state.finish()
        await message.answer("❌ Доступно только экспедиторам.")
        return

    try:
        price = float(message.text.replace(",", ".").replace(" ", ""))
        if price <= 0:
            raise ValueError
    except ValueError:
        await message.answer(
            "❌ Неверный формат. Введите число: <code>50000</code>", parse_mode="HTML"
        )
        return

    await state.update_data(price=price)
    await ExpeditorOfferStates.terms.set()
    await message.answer(
        "<b>📝 Укажите условия:</b>\n\nОпишите условия работы, сроки, гарантии:\n<code>Срок: 3-5 дней. Гарантия возврата.</code>",
        parse_mode="HTML",
    )


@dp.message_handler(state=ExpeditorOfferStates.terms)
async def set_expeditor_terms(message: types.Message, state: FSMContext):
    """Установить условия"""
    user_role = (get_user_by_id(message.from_user.id) or {}).get("role")
    if not is_expeditor_role(user_role):
        await state.finish()
        await message.answer("❌ Доступно только экспедиторам.")
        return

    terms = message.text.strip()

    if len(terms) < 10:
        await message.answer("❌ Слишком короткое описание условий.")
        return

    await state.update_data(terms=terms)
    await ExpeditorOfferStates.confirm.set()

    data = await state.get_data()
    text = "<b>✅ Подтверждение предложения:</b>\n\n"
    text += f"📋 {data['service_type']}\n"
    text += f"🏢 {data['ports']}\n"
    text += f"💰 {data['price']:,.0f} ₽\n"
    text += f"📝 {data['terms']}\n\nВсё верно?"

    keyboard = InlineKeyboardMarkup(row_width=2)
    keyboard.add(
        InlineKeyboardButton("✅ Подтвердить", callback_data="confirm_expeditor_offer"),
        InlineKeyboardButton("❌ Отменить", callback_data="cancel"),
    )
    await message.answer(text, reply_markup=keyboard, parse_mode="HTML")


@dp.callback_query_handler(
    lambda c: c.data == "confirm_expeditor_offer", state=ExpeditorOfferStates.confirm
)
async def confirm_expeditor_offer(callback: types.CallbackQuery, state: FSMContext):
    """Подтвердить создание предложения экспедитора"""
    data = await state.get_data()
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if not is_expeditor_role(user_role):
        await callback.answer("❌ Доступно только экспедиторам", show_alert=True)
        await state.finish()
        return

    required_fields = ("service_type", "ports", "price", "terms")
    if any(field not in data for field in required_fields):
        await state.finish()
        await callback.message.edit_text(
            "❌ Данные предложения повреждены или устарели.\n"
            "Запустите создание предложения заново."
        )
        await callback.answer()
        return

    offer_id = next_numeric_id(expeditor_offers)
    try:
        normalized_price = float(data["price"])
    except (TypeError, ValueError):
        await state.finish()
        await callback.message.edit_text(
            "❌ Некорректная стоимость в данных предложения.\n"
            "Запустите создание предложения заново."
        )
        await callback.answer()
        return

    offer = {
        "id": offer_id,
        "expeditor_id": user_id,
        "service_type": data["service_type"],
        "ports": data["ports"],
        "price": normalized_price,
        "terms": data["terms"],
        "status": "active",
        "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
    }

    expeditor_offers[offer_id] = offer
    save_expeditor_offers()

    await callback.message.edit_text(
        f"<b>✅ Предложение создано!</b>\n\nПредложение #{offer_id}\n"
        f"📋 {data['service_type']}\n"
        f"🏢 {data['ports']}\n"
        f"💰 {normalized_price:,.0f} ₽\n\n"
        "Ваше предложение будет отображаться экспортёрам.",
        parse_mode="HTML",
    )
    await state.finish()
    await callback.answer()


@dp.message_handler(
    lambda m: m.text == "💼 Мои предложения"
    and (get_user_by_id(m.from_user.id) or {}).get("role")
    and is_expeditor_role((get_user_by_id(m.from_user.id) or {}).get("role")),
    state="*",
)
async def expeditor_my_offers_handler(message: types.Message, state: FSMContext):
    """Показать предложения экспедитора"""
    await state.finish()
    user_id = message.from_user.id

    my_offers = {
        oid: o
        for oid, o in expeditor_offers.items()
        if same_id(o.get("expeditor_id"), user_id)
    }

    if not my_offers:
        await message.answer(
            "<b>💼 Мои предложения</b>\n\nУ вас пока нет предложений.\n\nСоздайте через <b>📋 Создать предложение</b>",
            parse_mode="HTML",
        )
        return

    active = sum(
        1 for o in my_offers.values() if normalize_transition_status(o.get("status")) == "active"
    )
    text = f"<b>💼 Мои предложения</b>\n\nВсего: <b>{len(my_offers)}</b>\nАктивных: <b>{active}</b>\n\n"

    for idx, (offer_id, offer) in enumerate(list(my_offers.items())[:10], 1):
        text += f"{idx}. <b>Предложение #{offer_id}</b>\n"
        text += f"   📋 {offer.get('service_type', '')}\n"
        text += f"   🏢 {offer.get('ports', '')}\n"
        text += f"   💰 {offer.get('price', 0):,.0f} ₽\n"
        text += f"   Статус: {offer.get('status', 'active')}\n\n"

    if len(my_offers) > 10:
        text += f"\n...и ещё {len(my_offers) - 10}\n"

    await message.answer(text, parse_mode="HTML")


# ========== ДОПОЛНИТЕЛЬНЫЕ ОБРАБОТЧИКИ ==========
# ============================================================================
# ЭКСПОРТЁР: ПРОСМОТР ПРЕДЛОЖЕНИЙ ЛОГИСТОВ
# ============================================================================
@dp.callback_query_handler(lambda c: c.data.startswith("show_all_offers_"), state="*")
async def show_all_offers_redirect(callback: types.CallbackQuery, state: FSMContext):
    """Совместимость со старым callback show_all_offers_*."""
    await state.finish()
    try:
        request_ref = callback.data.split("_")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (ValueError, IndexError):
        await callback.answer("❌ Ошибка данных", show_alert=True)
        return

    callback.data = f"view_request_offers_all_{request_id}"
    await view_request_offers(callback, state)


@dp.callback_query_handler(
    lambda c: c.data.startswith("view_request_offers_"), state="*"
)
async def view_request_offers(callback: types.CallbackQuery, state: FSMContext):
    """Просмотр предложений логистов по заявке"""
    await state.finish()

    show_all_pending = str(callback.data).startswith("view_request_offers_all_")
    try:
        request_ref = callback.data.split("_")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка получения ID заявки", show_alert=True)
        return

    _, request = find_shipping_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    user_id = callback.from_user.id

    # Проверяем права доступа: только владелец заявки (экспортёр)
    if not same_id(request.get("exporter_id"), user_id):
        await callback.answer("❌ Это не ваша заявка", show_alert=True)
        return

    # Получаем все предложения по заявке
    offers = [
        (offer_id, offer)
        for offer_id, offer in logistic_offers.items()
        if logistic_offer_matches_request(offer, request_id, "exporter")
    ]

    if not offers:
        text = (
            f"📦 <b>ПРЕДЛОЖЕНИЯ ПО ЗАЯВКЕ #{request_id}</b>\n\n"
            "❌ Пока нет предложений от логистов\n\n"
            "<i>Логисты получили уведомление о вашей заявке.\n"
            "Предложения появятся в ближайшее время.</i>"
        )

        keyboard = InlineKeyboardMarkup()
        keyboard.add(
            InlineKeyboardButton("🔙 К заявкам", callback_data="my_shipping_requests")
        )
        keyboard.add(
            InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main")
        )

        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        await callback.answer()
        return

    # Группируем по статусам
    by_status = {"pending": [], "accepted": [], "rejected": []}
    for offer_id, offer in offers:
        status = normalize_transition_status(offer.get("status", "pending"))
        if status in {"active", "new", "open"}:
            status = "pending"
        elif status in {"assigned", "in_progress", "completed"}:
            status = "accepted"
        elif status == "cancelled":
            status = "rejected"
        if status in by_status:
            by_status[status].append((offer_id, offer))
        else:
            by_status["pending"].append((offer_id, offer))

    # Сортируем по цене (низкие первые) в каждом статусе
    for status in by_status:
        by_status[status].sort(key=lambda x: x[1].get("price", 999_999_999))

    # Информация о заявке / пуле
    pull_id = request.get("pull_id")
    all_pulls = pulls.get("pulls", {})
    pull_info = all_pulls.get(pull_id, {}) if pull_id is not None else {}

    req_route_from = request.get("route_from") or request.get("from_city") or "—"
    req_route_to = request.get("route_to") or request.get("to_city") or "—"
    text = (
        f"📦 <b>ПРЕДЛОЖЕНИЯ ПО ЗАЯВКЕ #{request_id}</b>\n\n"
        f"🌾 Культура: {pull_info.get('culture', request.get('culture', 'Не указана'))}\n"
        f"📦 Объём: {request.get('volume', 0):.1f} т\n"
        f"📍 Маршрут: {req_route_from} → {req_route_to}\n"
    )

    if pull_info.get("port"):
        text += f"🚢 Порт: {pull_info.get('port')}\n"

    text += "\n━━━━━━━━━━━━━━━━━━━━\n\n"

    # Статистика
    total = len(offers)
    pending = len(by_status["pending"])
    accepted = len(by_status["accepted"])
    rejected = len(by_status["rejected"])

    text += (
        "📊 <b>СТАТИСТИКА:</b>\n"
        f"📋 Всего предложений: <b>{total}</b>\n"
        f"🕐 Ожидают решения: <b>{pending}</b>\n"
        f"✅ Принято: <b>{accepted}</b>\n"
        f"❌ Отклонено: <b>{rejected}</b>\n\n"
    )

    # Лучшее ожидающее предложение
    if pending > 0:
        best_offer_id, best_offer = by_status["pending"][0]
        text += "💰 <b>ЛУЧШЕЕ ПРЕДЛОЖЕНИЕ:</b>\n"
        text += f"💵 Цена: <b>{best_offer.get('price', 0):,.0f} ₽</b>\n"
        text += f"🚛 Транспорт: {best_offer.get('vehicle_type', '—')}\n"
        text += f"📅 Дата: {best_offer.get('delivery_date', '—')}\n\n"

    text += "━━━━━━━━━━━━━━━━━━━━\n\n"
    text += "Выберите предложение для просмотра:"

    keyboard = InlineKeyboardMarkup(row_width=1)

    # Показываем ожидающие предложения (в т.ч. legacy active)
    pending_offers_for_list = by_status["pending"] if show_all_pending else by_status["pending"][:5]
    for offer_id, offer in pending_offers_for_list:
        logist_id = get_offer_logist_id(offer)
        logist_info = get_user_by_id(logist_id) or {}

        logist_name = (
            logist_info.get("company_name")
            or logist_info.get("company_details")
            or logist_info.get("name")
            or f"Логист #{logist_id}"
        )

        price = offer.get("price", 0)
        vehicle = offer.get("vehicle_type", "Не указан")

        button_text = f"💰 {price:,.0f} ₽ | {vehicle[:15]} | {str(logist_name)[:20]}"

        keyboard.add(
            InlineKeyboardButton(
                button_text, callback_data=f"view_offer_details_{offer_id}"
            )
        )

    if len(by_status["pending"]) > 5 and not show_all_pending:
        keyboard.add(
            InlineKeyboardButton(
                f"➕ Показать ещё {len(by_status['pending']) - 5}",
                callback_data=f"show_all_offers_{request_id}",
            )
        )
    elif len(by_status["pending"]) > 5 and show_all_pending:
        keyboard.add(
            InlineKeyboardButton(
                "🔽 Свернуть список", callback_data=f"view_request_offers_{request_id}"
            )
        )

    # Кнопка сравнения
    if pending >= 2:
        keyboard.add(
            InlineKeyboardButton(
                "⚖️ Сравнить предложения", callback_data=f"compare_offers_{request_id}"
            )
        )

    keyboard.add(
        InlineKeyboardButton(
            "🔄 Обновить", callback_data=f"view_request_offers_{request_id}"
        )
    )
    keyboard.add(
        InlineKeyboardButton("🔙 К заявкам", callback_data="my_shipping_requests")
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("view_offer_details_"), state="*"
)
async def view_offer_details_for_exporter(
    callback: types.CallbackQuery, state: FSMContext
):
    """Детальный просмотр предложения"""
    await state.finish()

    try:
        offer_ref = callback.data.split("_")[-1]
        offer_id = int(offer_ref) if str(offer_ref).isdigit() else offer_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка получения ID", show_alert=True)
        return

    resolved_offer_id, offer = find_logistic_offer_by_id(offer_id)
    if not offer:
        await callback.answer("❌ Предложение не найдено", show_alert=True)
        return
    offer_id = resolved_offer_id
    request_id = offer.get("request_id")
    offer_source = str(offer.get("source") or "").strip().lower()
    if offer_source == "logistic":
        offer_source = "logistics"
    if offer_source not in {"exporter", "farmer", "logistics"}:
        source_candidates = set()
        request_key = request_id if isinstance(request_id, str) else str(request_id)
        if request_id in shipping_requests or request_key in shipping_requests:
            source_candidates.add("exporter")
        if request_id in logistics_requests or request_key in logistics_requests:
            source_candidates.add("logistics")
        if (
            request_id in farmer_shipping_requests
            or request_key in farmer_shipping_requests
            or request_id in farmer_logistics_requests
            or request_key in farmer_logistics_requests
        ):
            source_candidates.add("farmer")
        if len(source_candidates) == 1:
            offer_source = next(iter(source_candidates))
        else:
            inferred_source = infer_logistic_offer_source(request_id)
            if (
                inferred_source in {"exporter", "farmer", "logistics"}
                and (not source_candidates or inferred_source in source_candidates)
            ):
                offer_source = inferred_source
            else:
                await callback.answer(
                    "❌ Не удалось определить тип заявки для предложения",
                    show_alert=True,
                )
                return
    if offer_source == "farmer":
        _, request = find_farmer_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("farmer_id")
    elif offer_source == "logistics":
        request = logistics_requests.get(request_id) or logistics_requests.get(str(request_id))
        request_owner_id = (
            (request if isinstance(request, dict) else {}).get("customer_id")
            or (request if isinstance(request, dict) else {}).get("created_by")
            or (request if isinstance(request, dict) else {}).get("exporter_id")
            or (request if isinstance(request, dict) else {}).get("logist_id")
        )
    else:
        _, request = find_shipping_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("exporter_id")
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    if not logistic_offer_matches_request(offer, request_id, offer_source):
        await callback.answer("❌ Предложение не относится к выбранной заявке", show_alert=True)
        return

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")

    # Проверяем права
    if not (user_role == "admin" or same_id(request_owner_id, user_id)):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return

    # Информация о логисте
    logist_id = get_offer_logist_id(offer)
    logist_info = get_user_by_id(logist_id) or {}
    logist_name = logist_info.get("company_name", "Не указана")
    logist_phone = logist_info.get("phone", "Не указан")

    # Статистика логиста
    logist_offers = [
        o
        for o in logistic_offers.values()
        if isinstance(o, dict)
        and same_id((o.get("logist_id") or o.get("logistic_id")), logist_id)
    ]
    logist_deliveries = [
        d for d in deliveries.values() if same_id(d.get("logist_id"), logist_id)
    ]
    completed = len(
        [d for d in logist_deliveries if normalize_transition_status(d.get("status")) == "completed"]
    )
    total_offers = len(logist_offers)

    text = f"📋 <b>ДЕТАЛИ ПРЕДЛОЖЕНИЯ #{offer_id}</b>\n\n"

    # Информация о предложении
    text += "<b>💰 ПРЕДЛОЖЕНИЕ:</b>\n"
    text += f"💵 Стоимость: <b>{offer.get('price', 0):,.0f} ₽</b>\n"
    text += f"🚛 Транспорт: <b>{offer.get('vehicle_type', 'Не указан')}</b>\n"
    text += f"📅 Дата доставки: <b>{offer.get('delivery_date', 'Не указана')}</b>\n"

    if offer.get("additional_info"):
        text += f"\nℹ️ Дополнительно:\n<i>{offer.get('additional_info')}</i>\n"

    text += f"\n📅 Создано: {offer.get('created_at', 'Не указано')}\n\n"

    text += "━━━━━━━━━━━━━━━━━━━━\n\n"

    # Информация о логисте
    text += "<b>🚚 ЛОГИСТИЧЕСКАЯ КОМПАНИЯ:</b>\n"
    text += f"🏢 Название: <b>{logist_name}</b>\n"
    text += f"📞 Телефон: {logist_phone}\n\n"

    # Статистика
    text += "<b>📊 СТАТИСТИКА:</b>\n"
    text += f"✅ Завершённых доставок: <b>{completed}</b>\n"
    text += f"📋 Всего предложений: <b>{total_offers}</b>\n"

    if completed > 0:
        # Средняя стоимость
        completed_deliveries = []
        for d in logist_deliveries:
            if normalize_transition_status(d.get("status")) != "completed":
                continue
            _, delivery_offer = find_logistic_offer_by_id(d.get("offer_id"))
            completed_deliveries.append((delivery_offer or {}).get("price", 0))
        if completed_deliveries:
            avg_price = sum(completed_deliveries) / len(completed_deliveries)
            text += f"💰 Средняя стоимость: <b>{avg_price:,.0f} ₽</b>\n"

    text += "\n━━━━━━━━━━━━━━━━━━━━\n\n"

    # Статус предложения
    status = normalize_transition_status(offer.get("status", "pending"))

    if status in {"pending", "active"}:
        text += "⏳ <b>Ожидает вашего решения</b>"
    elif status == "accepted":
        text += "✅ <b>Предложение принято</b>"
    elif status == "rejected":
        text += "❌ <b>Предложение отклонено</b>"
        if offer.get("rejection_reason"):
            text += f"\n<i>Причина: {offer.get('rejection_reason')}</i>"

    keyboard = InlineKeyboardMarkup(row_width=2)

    if status in {"pending", "active"}:
        keyboard.add(
            InlineKeyboardButton(
                "✅ Принять", callback_data=f"accept_offer_{offer_id}"
            ),
            InlineKeyboardButton(
                "❌ Отклонить", callback_data=f"reject_offer_{offer_id}"
            ),
        )

    if offer_source == "farmer":
        keyboard.add(
            InlineKeyboardButton(
                "🔙 К заявке", callback_data=f"view_request:farmer:{request_id}"
            )
        )
    elif offer_source == "logistics":
        keyboard.add(
            InlineKeyboardButton(
                "🔙 К заявке", callback_data=f"view_logistics_req:{request_id}"
            )
        )
    else:
        keyboard.add(
            InlineKeyboardButton(
                "🔙 К предложениям", callback_data=f"view_request_offers_{request_id}"
            )
        )
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("compare_offers_"), state="*")
async def compare_offers(callback: types.CallbackQuery, state: FSMContext):
    """Сравнение предложений"""
    await state.finish()

    try:
        request_ref = callback.data.split("_")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return

    _, request = find_shipping_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")

    if not (same_id(request.get("exporter_id"), user_id) or user_role == "admin"):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return

    # Получаем ожидающие предложения
    offers = [
        (offer_id, offer)
        for offer_id, offer in logistic_offers.items()
        if logistic_offer_matches_request(offer, request_id, "exporter")
        and normalize_transition_status(offer.get("status")) in {"pending", "active"}
    ]

    if len(offers) < 2:
        await callback.answer(
            "❌ Недостаточно предложений для сравнения", show_alert=True
        )
        return

    # Сортируем по цене
    offers.sort(key=lambda x: x[1].get("price", 999999))

    text = "⚖️ <b>СРАВНЕНИЕ ПРЕДЛОЖЕНИЙ</b>\n\n"
    text += f"📦 Заявка #{request_id}\n"
    text += f"📊 Сравниваем {len(offers)} предложений\n\n"
    text += "━━━━━━━━━━━━━━━━━━━━\n\n"

    # Показываем топ-3
    for i, (offer_id, offer) in enumerate(offers[:3], 1):
        logist_id = get_offer_logist_id(offer)
        logist_info = get_user_by_id(logist_id) or {}
        logist_name = logist_info.get("company_name", f"Логист #{logist_id}")

        medal = "🥇" if i == 1 else "🥈" if i == 2 else "🥉"

        text += f"{medal} <b>#{i} - {logist_name}</b>\n"
        text += f"💰 Цена: <b>{offer.get('price', 0):,.0f} ₽</b>\n"
        text += f"🚛 Транспорт: {offer.get('vehicle_type')}\n"
        text += f"📅 Дата: {offer.get('delivery_date')}\n"

        # Статистика логиста
        logist_deliveries = [
            d
            for d in deliveries.values()
            if same_id(d.get("logist_id"), logist_id)
            and normalize_transition_status(d.get("status")) == "completed"
        ]
        completed = len(logist_deliveries)

        text += f"✅ Доставок: {completed}\n"
        text += "\n"

    if len(offers) > 3:
        text += f"<i>... и ещё {len(offers) - 3} предложений</i>\n\n"

    # Анализ
    prices = [o[1].get("price", 0) for o in offers]
    min_price = min(prices)
    max_price = max(prices)
    avg_price = sum(prices) / len(prices)

    text += "━━━━━━━━━━━━━━━━━━━━\n\n"
    text += "📊 <b>АНАЛИЗ ЦЕН:</b>\n"
    text += f"💵 Минимальная: <b>{min_price:,.0f} ₽</b>\n"
    text += f"💰 Средняя: <b>{avg_price:,.0f} ₽</b>\n"
    text += f"💸 Максимальная: <b>{max_price:,.0f} ₽</b>\n"
    text += f"📈 Разброс: <b>{max_price - min_price:,.0f} ₽</b>\n\n"

    # Рекомендация
    best_offer_id, best_offer = offers[0]
    text += "💡 <b>РЕКОМЕНДАЦИЯ:</b>\n"
    text += f"Самое выгодное предложение #{best_offer_id}\n"
    text += f"Экономия: <b>{avg_price - min_price:,.0f} ₽</b>"

    keyboard = InlineKeyboardMarkup(row_width=1)

    # Кнопки для топ-3
    for i, (offer_id, offer) in enumerate(offers[:3], 1):
        medal = "🥇" if i == 1 else "🥈" if i == 2 else "🥉"
        price = offer.get("price", 0)

        keyboard.add(
            InlineKeyboardButton(
                f"{medal} Выбрать #{i} ({price:,.0f} ₽)",
                callback_data=f"view_offer_details_{offer_id}",
            )
        )

    keyboard.add(
        InlineKeyboardButton(
            "📋 Все предложения", callback_data=f"view_request_offers_{request_id}"
        )
    )
    keyboard.add(
        InlineKeyboardButton(
            "🔙 Назад", callback_data=f"view_request_offers_{request_id}"
        )
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


# ============================================================================
# ЭКСПОРТЁР: ПРИНЯТИЕ И ОТКЛОНЕНИЕ ПРЕДЛОЖЕНИЙ
# ============================================================================


class AcceptOfferStatesGroup(StatesGroup):
    """FSM для принятия предложения"""

    offer_id = State()
    confirm = State()


class RejectOfferStatesGroup(StatesGroup):
    """FSM для отклонения предложения"""

    offer_id = State()
    reason = State()


@dp.callback_query_handler(lambda c: c.data.startswith("accept_offer_"), state="*")
async def accept_offer_start(callback: types.CallbackQuery, state: FSMContext):
    """Начало принятия предложения экспортёром"""
    await state.finish()

    try:
        offer_ref = callback.data.split("_")[-1]
        offer_id = int(offer_ref) if str(offer_ref).isdigit() else offer_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка получения ID", show_alert=True)
        return

    resolved_offer_id, offer = find_logistic_offer_by_id(offer_id)
    if not offer:
        await callback.answer("❌ Предложение не найдено", show_alert=True)
        return
    offer_id = resolved_offer_id
    request_id = offer.get("request_id")
    offer_source = str(offer.get("source") or "").strip().lower()
    if offer_source == "logistic":
        offer_source = "logistics"
    if offer_source not in {"exporter", "farmer", "logistics"}:
        source_candidates = set()
        request_key = request_id if isinstance(request_id, str) else str(request_id)
        if request_id in shipping_requests or request_key in shipping_requests:
            source_candidates.add("exporter")
        if request_id in logistics_requests or request_key in logistics_requests:
            source_candidates.add("logistics")
        if (
            request_id in farmer_shipping_requests
            or request_key in farmer_shipping_requests
            or request_id in farmer_logistics_requests
            or request_key in farmer_logistics_requests
        ):
            source_candidates.add("farmer")
        if len(source_candidates) == 1:
            offer_source = next(iter(source_candidates))
        else:
            inferred_source = infer_logistic_offer_source(request_id)
            if (
                inferred_source in {"exporter", "farmer", "logistics"}
                and (not source_candidates or inferred_source in source_candidates)
            ):
                offer_source = inferred_source
            else:
                await callback.answer(
                    "❌ Не удалось определить тип заявки для предложения",
                    show_alert=True,
                )
                return
    if offer_source == "farmer":
        _, request = find_farmer_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("farmer_id")
    elif offer_source == "logistics":
        request = logistics_requests.get(request_id) or logistics_requests.get(str(request_id))
        request_owner_id = (
            (request if isinstance(request, dict) else {}).get("customer_id")
            or (request if isinstance(request, dict) else {}).get("created_by")
            or (request if isinstance(request, dict) else {}).get("exporter_id")
            or (request if isinstance(request, dict) else {}).get("logist_id")
        )
    else:
        _, request = find_shipping_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("exporter_id")
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    if not logistic_offer_matches_request(offer, request_id, offer_source):
        await callback.answer("❌ Предложение не относится к выбранной заявке", show_alert=True)
        return
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")

    # Проверки доступа и статусов
    if not (user_role == "admin" or same_id(request_owner_id, user_id)):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return
    if not is_request_open_for_offers(request.get("status")):
        await callback.answer("❌ Заявка уже не принимает предложения", show_alert=True)
        return
    if get_assigned_logist_id(request):
        await callback.answer("❌ По заявке уже назначен логист", show_alert=True)
        return

    offer_status = normalize_transition_status(offer.get("status") or "pending")
    if offer_status not in {"pending", "active"}:
        await callback.answer("❌ Предложение уже обработано", show_alert=True)
        return

    # Проверяем, нет ли уже принятого предложения по этой заявке
    accepted_offers = [
        o
        for o in logistic_offers.values()
        if logistic_offer_matches_request(o, request_id, offer_source)
        and normalize_transition_status(o.get("status")) == "accepted"
    ]

    if accepted_offers:
        await callback.answer(
            "❌ По этой заявке уже принято другое предложение", show_alert=True
        )
        return

    # Информация о предложении
    logist_id = get_offer_logist_id(offer)
    logist_info = get_user_by_id(logist_id) or {}
    logist_name = logist_info.get("company_name", "Не указана")

    pull_id = request.get("pull_id")
    all_pulls = pulls.get("pulls", {})
    pull_info = all_pulls.get(pull_id, {}) if pull_id is not None else {}

    text = f"✅ <b>ПРИНЯТИЕ ПРЕДЛОЖЕНИЯ #{offer_id}</b>\n\n"
    text += f"📦 <b>ЗАЯВКА #{request_id}</b>\n"
    text += f"🌾 Культура: {pull_info.get('culture', request.get('culture', 'Не указана'))}\n"
    text += f"📦 Объём: {request.get('volume', 0):.1f} т\n"
    route_from = request.get("route_from") or request.get("from") or request.get("from_city") or ""
    route_to = request.get("route_to") or request.get("to") or request.get("to_city") or ""
    text += f"📍 Маршрут: {route_from} → {route_to}\n\n"

    text += "━━━━━━━━━━━━━━━━━━━━\n\n"

    text += "<b>ПРЕДЛОЖЕНИЕ:</b>\n"
    text += f"🚚 Логист: <b>{logist_name}</b>\n"
    text += f"💰 Стоимость: <b>{offer.get('price', 0):,.0f} ₽</b>\n"
    text += f"🚛 Транспорт: {offer.get('vehicle_type')}\n"
    text += f"📅 Дата доставки: {offer.get('delivery_date')}\n\n"

    text += "━━━━━━━━━━━━━━━━━━━━\n\n"

    text += "⚠️ <b>ВАЖНО:</b>\n"
    text += "• Будет создана доставка\n"
    text += "• Остальные предложения будут отклонены\n"
    text += "• Логист получит уведомление\n"
    text += "• Отменить действие будет невозможно\n\n"

    text += "✅ Подтвердите принятие предложения"

    keyboard = InlineKeyboardMarkup(row_width=2)
    keyboard.add(
        InlineKeyboardButton(
            "✅ Подтверждаю", callback_data=f"confirm_accept_{offer_id}"
        ),
        InlineKeyboardButton(
            "❌ Отмена", callback_data=f"view_offer_details_{offer_id}"
        ),
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("confirm_accept_"), state="*")
async def accept_offer_confirmed(callback: types.CallbackQuery, state: FSMContext):
    """Подтверждение принятия предложения"""
    await state.finish()

    try:
        offer_ref = callback.data.split("_")[-1]
        offer_id = int(offer_ref) if str(offer_ref).isdigit() else offer_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return

    resolved_offer_id, offer = find_logistic_offer_by_id(offer_id)
    if not offer:
        await callback.answer("❌ Предложение не найдено", show_alert=True)
        return
    offer_id = resolved_offer_id
    request_id = offer.get("request_id")
    offer_source = str(offer.get("source") or "").strip().lower()
    if offer_source == "logistic":
        offer_source = "logistics"
    if offer_source not in {"exporter", "farmer", "logistics"}:
        source_candidates = set()
        request_key = request_id if isinstance(request_id, str) else str(request_id)
        if request_id in shipping_requests or request_key in shipping_requests:
            source_candidates.add("exporter")
        if request_id in logistics_requests or request_key in logistics_requests:
            source_candidates.add("logistics")
        if (
            request_id in farmer_shipping_requests
            or request_key in farmer_shipping_requests
            or request_id in farmer_logistics_requests
            or request_key in farmer_logistics_requests
        ):
            source_candidates.add("farmer")
        if len(source_candidates) == 1:
            offer_source = next(iter(source_candidates))
        else:
            inferred_source = infer_logistic_offer_source(request_id)
            if (
                inferred_source in {"exporter", "farmer", "logistics"}
                and (not source_candidates or inferred_source in source_candidates)
            ):
                offer_source = inferred_source
            else:
                await callback.answer(
                    "❌ Не удалось определить тип заявки для предложения",
                    show_alert=True,
                )
                return
    if offer_source == "farmer":
        _, request = find_farmer_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("farmer_id")
    elif offer_source == "logistics":
        request = logistics_requests.get(request_id) or logistics_requests.get(str(request_id))
        request_owner_id = (
            (request if isinstance(request, dict) else {}).get("customer_id")
            or (request if isinstance(request, dict) else {}).get("created_by")
            or (request if isinstance(request, dict) else {}).get("exporter_id")
            or (request if isinstance(request, dict) else {}).get("logist_id")
        )
    else:
        _, request = find_shipping_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("exporter_id")

    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    if not logistic_offer_matches_request(offer, request_id, offer_source):
        await callback.answer("❌ Предложение не относится к выбранной заявке", show_alert=True)
        return
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")

    # Проверка доступа
    if not (user_role == "admin" or same_id(request_owner_id, user_id)):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return
    if not is_request_open_for_offers(request.get("status")):
        await callback.answer("❌ Заявка уже не принимает предложения", show_alert=True)
        return
    if get_assigned_logist_id(request):
        await callback.answer("❌ По заявке уже назначен логист", show_alert=True)
        return

    # Защита от повторной обработки: оффер должен быть в открытом статусе
    offer_status = normalize_transition_status(offer.get("status") or "pending")
    if offer_status not in {"pending", "active"}:
        await callback.answer("❌ Предложение уже обработано", show_alert=True)
        return

    # Дополнительная защита: по заявке не должно быть другого accepted
    already_accepted = any(
        logistic_offer_matches_request(o, request_id, offer_source)
        and normalize_transition_status(o.get("status")) == "accepted"
        for o in logistic_offers.values()
    )
    if already_accepted:
        await callback.answer(
            "❌ По этой заявке уже принято другое предложение", show_alert=True
        )
        return

    # Принимаем предложение
    offer["status"] = "accepted"
    offer["accepted_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    offer["accepted_by"] = user_id

    # Обновляем статус заявки
    request["status"] = "assigned"
    request["selected_logistic"] = get_offer_logist_id(offer)
    request["assigned_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    request["logist_id"] = get_offer_logist_id(offer)
    request["assigned_logist_id"] = get_offer_logist_id(offer)

    # Создаём доставку (или обновляем существующую по request_id)
    existing_delivery = next(
        (
            d
            for d in deliveries.values()
            if same_id(d.get("request_id"), request_id)
            and (
                same_id(d.get("farmer_id"), request_owner_id)
                if offer_source == "farmer"
                else (
                    same_id(d.get("customer_id"), request_owner_id)
                    or same_id(d.get("created_by"), request_owner_id)
                    or same_id(d.get("exporter_id"), request_owner_id)
                    or same_id(d.get("logist_id"), request_owner_id)
                )
                if offer_source == "logistics"
                else same_id(d.get("exporter_id"), request_owner_id)
            )
            and (
                str(d.get("source") or "").strip().lower() in {"", offer_source}
                or (
                    offer_source == "logistics"
                    and str(d.get("source") or "").strip().lower() == "logistic"
                )
            )
        ),
        None,
    )
    if existing_delivery:
        existing_delivery_status = normalize_transition_status(
            existing_delivery.get("status")
        )
        if existing_delivery_status in {"completed", "cancelled"}:
            await callback.answer(
                "❌ По заявке уже есть закрытая доставка", show_alert=True
            )
            return
        delivery_id = existing_delivery.get("id")
        existing_delivery["offer_id"] = offer_id
        if offer_source == "farmer":
            existing_delivery["farmer_id"] = request_owner_id
        elif offer_source == "logistics":
            existing_delivery["customer_id"] = request_owner_id
            if request.get("exporter_id"):
                existing_delivery["exporter_id"] = request.get("exporter_id")
        else:
            existing_delivery["exporter_id"] = request_owner_id
        existing_delivery["logist_id"] = get_offer_logist_id(offer)
        existing_delivery["pull_id"] = request.get("pull_id")
        existing_delivery["route_from"] = (
            request.get("route_from") or request.get("from") or request.get("from_city")
        )
        existing_delivery["route_to"] = (
            request.get("route_to") or request.get("to") or request.get("to_city")
        )
        existing_delivery["volume"] = request.get("volume")
        existing_delivery["price"] = offer.get("price")
        existing_delivery["vehicle_type"] = offer.get("vehicle_type")
        existing_delivery["delivery_date"] = offer.get("delivery_date")
        existing_delivery["status"] = "pending"
        existing_delivery["source"] = offer_source
        existing_delivery["updated_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    else:
        delivery_id = next_numeric_id(deliveries)
        delivery = {
            "id": delivery_id,
            "request_id": request_id,
            "offer_id": offer_id,
            "logist_id": get_offer_logist_id(offer),
            "pull_id": request.get("pull_id"),
            "route_from": request.get("route_from") or request.get("from") or request.get("from_city"),
            "route_to": request.get("route_to") or request.get("to") or request.get("to_city"),
            "volume": request.get("volume"),
            "price": offer.get("price"),
            "vehicle_type": offer.get("vehicle_type"),
            "delivery_date": offer.get("delivery_date"),
            "status": "pending",
            "source": offer_source,
            "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        }
        if offer_source == "farmer":
            delivery["farmer_id"] = request_owner_id
        elif offer_source == "logistics":
            delivery["customer_id"] = request_owner_id
            if request.get("exporter_id"):
                delivery["exporter_id"] = request.get("exporter_id")
        else:
            delivery["exporter_id"] = request_owner_id
        deliveries[delivery_id] = delivery

    # Отклоняем остальные предложения по этой заявке
    request_customer_id = request_owner_id or user_id
    rejected_count = 0
    for other_offer_id, other_offer in logistic_offers.items():
        if not isinstance(other_offer, dict):
            continue
        if (
            logistic_offer_matches_request(other_offer, request_id, offer_source)
            and other_offer_id != offer_id
            and normalize_transition_status(other_offer.get("status")) in {"pending", "active"}
        ):
            other_offer["status"] = "rejected"
            other_offer["rejected_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            other_offer["rejection_reason"] = "Принято другое предложение"
            rejected_count += 1

            # Уведомляем логистов
            other_logist_id = get_offer_logist_id(other_offer)
            if other_logist_id:
                asyncio.create_task(
                    notify_logistic_offer_rejected(
                        other_offer_id,
                        request_customer_id,
                        "Принято другое предложение",
                    )
                )

    # Сохраняем данные
    if offer_source == "farmer":
        save_farmers_logistics()
    elif offer_source == "logistics":
        save_logistics_requests_to_pickle()
    else:
        save_shipping_requests()
    save_logistic_offers()
    save_deliveries()

    # Уведомляем принятого логиста
    logist_id = get_offer_logist_id(offer)
    if logist_id:
        asyncio.create_task(
            notify_logistic_offer_accepted(offer_id, request_customer_id)
        )

    # Сообщение пользователю
    logist_info = get_user_by_id(logist_id) or {}
    logist_name = logist_info.get("company_name", "Не указана")

    text = "🎉 <b>ПРЕДЛОЖЕНИЕ ПРИНЯТО!</b>\n\n"
    text += f"✅ Предложение #{offer_id} успешно принято\n"
    text += f"📦 Доставка #{delivery_id} создана\n\n"
    text += "━━━━━━━━━━━━━━━━━━━━\n\n"
    text += "<b>ДЕТАЛИ ДОСТАВКИ:</b>\n"
    text += f"🚚 Логист: {logist_name}\n"
    text += f"💰 Стоимость: {offer.get('price', 0):,.0f} ₽\n"
    text += f"🚛 Транспорт: {offer.get('vehicle_type')}\n"
    text += f"📅 Дата: {offer.get('delivery_date')}\n\n"

    if rejected_count > 0:
        text += f"ℹ️ Отклонено предложений: {rejected_count}\n\n"

    text += "━━━━━━━━━━━━━━━━━━━━\n\n"
    text += "<b>СЛЕДУЮЩИЕ ШАГИ:</b>\n"
    text += "1. Логист получит уведомление\n"
    text += "2. Свяжитесь для уточнения деталей\n"
    text += "3. Отслеживайте доставку в разделе «Мои доставки»"

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton(
            f"📦 Доставка #{delivery_id}",
            callback_data=f"view_delivery_{delivery_id}",
        )
    )
    if offer_source == "farmer":
        keyboard.add(
            InlineKeyboardButton("📬 Мои заявки", callback_data="farmer_my_requests_menu")
        )
    else:
        keyboard.add(
            InlineKeyboardButton("📋 Мои доставки", callback_data="exporter_deliveries")
        )
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer("✅ Предложение принято!")

    logging.info(
        f"✅ Экспортёр {user_id} принял предложение #{offer_id}, создана доставка #{delivery_id}"
    )


@dp.callback_query_handler(lambda c: c.data.startswith("reject_offer_"), state="*")
async def reject_offer_start(callback: types.CallbackQuery, state: FSMContext):
    """Начало отклонения предложения"""
    await state.finish()

    try:
        offer_ref = callback.data.split("_")[-1]
        offer_id = int(offer_ref) if str(offer_ref).isdigit() else offer_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка получения ID", show_alert=True)
        return

    resolved_offer_id, offer = find_logistic_offer_by_id(offer_id)
    if not offer:
        await callback.answer("❌ Предложение не найдено", show_alert=True)
        return
    offer_id = resolved_offer_id
    request_id = offer.get("request_id")
    offer_source = str(offer.get("source") or "").strip().lower()
    if offer_source == "logistic":
        offer_source = "logistics"
    if offer_source not in {"exporter", "farmer", "logistics"}:
        source_candidates = set()
        request_key = request_id if isinstance(request_id, str) else str(request_id)
        if request_id in shipping_requests or request_key in shipping_requests:
            source_candidates.add("exporter")
        if request_id in logistics_requests or request_key in logistics_requests:
            source_candidates.add("logistics")
        if (
            request_id in farmer_shipping_requests
            or request_key in farmer_shipping_requests
            or request_id in farmer_logistics_requests
            or request_key in farmer_logistics_requests
        ):
            source_candidates.add("farmer")
        if len(source_candidates) == 1:
            offer_source = next(iter(source_candidates))
        else:
            inferred_source = infer_logistic_offer_source(request_id)
            if (
                inferred_source in {"exporter", "farmer", "logistics"}
                and (not source_candidates or inferred_source in source_candidates)
            ):
                offer_source = inferred_source
            else:
                await callback.answer(
                    "❌ Не удалось определить тип заявки для предложения",
                    show_alert=True,
                )
                return
    if offer_source == "farmer":
        _, request = find_farmer_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("farmer_id")
    elif offer_source == "logistics":
        request = logistics_requests.get(request_id) or logistics_requests.get(str(request_id))
        request_owner_id = (
            (request if isinstance(request, dict) else {}).get("customer_id")
            or (request if isinstance(request, dict) else {}).get("created_by")
            or (request if isinstance(request, dict) else {}).get("exporter_id")
            or (request if isinstance(request, dict) else {}).get("logist_id")
        )
    else:
        _, request = find_shipping_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("exporter_id")

    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    if not logistic_offer_matches_request(offer, request_id, offer_source):
        await callback.answer("❌ Предложение не относится к выбранной заявке", show_alert=True)
        return

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")

    if not (user_role == "admin" or same_id(request_owner_id, user_id)):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return

    offer_status = normalize_transition_status(offer.get("status") or "pending")
    if offer_status not in {"pending", "active"}:
        await callback.answer("❌ Предложение уже обработано", show_alert=True)
        return

    await state.update_data(offer_id=offer_id)

    logist_id = get_offer_logist_id(offer)
    logist_info = get_user_by_id(logist_id) or {}
    logist_name = logist_info.get("company_name", "Не указана")

    text = f"❌ <b>ОТКЛОНЕНИЕ ПРЕДЛОЖЕНИЯ #{offer_id}</b>\n\n"
    text += f"🚚 Логист: {logist_name}\n"
    text += f"💰 Цена: {offer.get('price', 0):,.0f} ₽\n\n"
    text += "━━━━━━━━━━━━━━━━━━━━\n\n"
    text += "<b>Укажите причину отклонения</b>\n"
    text += "<i>(необязательно, но рекомендуется)</i>\n\n"
    text += "Возможные причины:\n"
    text += "• Высокая цена\n"
    text += "• Несоответствие транспорта\n"
    text += "• Неподходящие сроки\n"
    text += "• Принято другое предложение\n\n"
    text += "Или нажмите 'Без причины'"

    keyboard = InlineKeyboardMarkup(row_width=1)

    reasons = [
        ("Высокая цена", "reject_reason_price_high"),
        ("Несоответствие транспорта", "reject_reason_transport_mismatch"),
        ("Неподходящие сроки", "reject_reason_bad_timing"),
        ("Принято другое предложение", "reject_reason_other_offer_accepted"),
    ]

    for reason_text, callback_data in reasons:
        keyboard.add(InlineKeyboardButton(reason_text, callback_data=callback_data))

    keyboard.add(
        InlineKeyboardButton(
            "✍️ Указать свою причину", callback_data="reject_reason_custom"
        )
    )
    keyboard.add(
        InlineKeyboardButton("➡️ Без причины", callback_data="reject_reason_none")
    )
    keyboard.add(
        InlineKeyboardButton(
            "🔙 Отмена", callback_data=f"view_offer_details_{offer_id}"
        )
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await RejectOfferStatesGroup.reason.set()
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("reject_reason_"), state=RejectOfferStatesGroup.reason
)
async def reject_offer_reason_selected(
    callback: types.CallbackQuery, state: FSMContext
):
    """Выбор причины отклонения"""
    reason_key = callback.data.replace("reject_reason_", "")

    data = await state.get_data()
    offer_id = data.get("offer_id")

    if reason_key == "custom":
        text = "✍️ <b>УКАЖИТЕ ПРИЧИНУ ОТКЛОНЕНИЯ</b>\n\n"
        text += "Введите текст причины (до 200 символов):"

        keyboard = InlineKeyboardMarkup()
        keyboard.add(
            InlineKeyboardButton("❌ Отмена", callback_data=f"reject_offer_{offer_id}")
        )

        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        await callback.answer()
        return

    reason_map = {
        "price_high": "Высокая цена",
        "transport_mismatch": "Несоответствие транспорта",
        "bad_timing": "Неподходящие сроки",
        "other_offer_accepted": "Принято другое предложение",
        "none": None,
    }
    if reason_key not in reason_map:
        await callback.answer("❌ Некорректная причина", show_alert=True)
        return
    reason = reason_map[reason_key]

    # Отклоняем предложение
    await reject_offer_execute(callback, state, offer_id, reason)


class CallbackProxy:
    """Лёгкий proxy для повторного использования callback-ориентированных функций."""

    def __init__(self, user_id, message):
        self.from_user = type("obj", (object,), {"id": user_id})
        self.message = message

    async def answer(self, text="", show_alert=False):
        return None


@dp.message_handler(state=RejectOfferStatesGroup.reason)
async def reject_offer_custom_reason(message: types.Message, state: FSMContext):
    """Ввод своей причины отклонения"""
    reason = message.text.strip()
    if not reason:
        await message.answer("❌ Причина не может быть пустой. Введите текст:")
        return

    if len(reason) > 200:
        await message.answer(
            "❌ Слишком длинная причина (максимум 200 символов)!\n\nВведите короче:"
        )
        return

    data = await state.get_data()
    offer_id = data.get("offer_id")

    fake_callback = CallbackProxy(message.from_user.id, message)

    await reject_offer_execute(fake_callback, state, offer_id, reason)


async def reject_offer_execute(
    callback_or_fake, state: FSMContext, offer_id: int, reason: str = None
):
    """Выполнение отклонения предложения"""

    resolved_offer_id, offer = find_logistic_offer_by_id(offer_id)
    if not offer:
        if hasattr(callback_or_fake, "answer"):
            await callback_or_fake.answer("❌ Предложение не найдено", show_alert=True)
        return
    offer_id = resolved_offer_id
    request_id = offer.get("request_id")
    offer_source = str(offer.get("source") or "").strip().lower()
    if offer_source == "logistic":
        offer_source = "logistics"
    if offer_source not in {"exporter", "farmer", "logistics"}:
        source_candidates = set()
        request_key = request_id if isinstance(request_id, str) else str(request_id)
        if request_id in shipping_requests or request_key in shipping_requests:
            source_candidates.add("exporter")
        if request_id in logistics_requests or request_key in logistics_requests:
            source_candidates.add("logistics")
        if (
            request_id in farmer_shipping_requests
            or request_key in farmer_shipping_requests
            or request_id in farmer_logistics_requests
            or request_key in farmer_logistics_requests
        ):
            source_candidates.add("farmer")
        if len(source_candidates) == 1:
            offer_source = next(iter(source_candidates))
        else:
            inferred_source = infer_logistic_offer_source(request_id)
            if (
                inferred_source in {"exporter", "farmer", "logistics"}
                and (not source_candidates or inferred_source in source_candidates)
            ):
                offer_source = inferred_source
            else:
                if hasattr(callback_or_fake, "answer"):
                    await callback_or_fake.answer(
                        "❌ Не удалось определить тип заявки для предложения",
                        show_alert=True,
                    )
                return
    if offer_source == "farmer":
        _, request = find_farmer_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("farmer_id")
    elif offer_source == "logistics":
        request = logistics_requests.get(request_id) or logistics_requests.get(str(request_id))
        request_owner_id = (
            (request if isinstance(request, dict) else {}).get("customer_id")
            or (request if isinstance(request, dict) else {}).get("created_by")
            or (request if isinstance(request, dict) else {}).get("exporter_id")
            or (request if isinstance(request, dict) else {}).get("logist_id")
        )
    else:
        _, request = find_shipping_request_by_id(request_id)
        request_owner_id = (request if isinstance(request, dict) else {}).get("exporter_id")

    user_id = callback_or_fake.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")

    if not request:
        if hasattr(callback_or_fake, "answer"):
            await callback_or_fake.answer("❌ Заявка не найдена", show_alert=True)
        return
    if not logistic_offer_matches_request(offer, request_id, offer_source):
        if hasattr(callback_or_fake, "answer"):
            await callback_or_fake.answer(
                "❌ Предложение не относится к выбранной заявке",
                show_alert=True,
            )
        return
    if not (user_role == "admin" or same_id(request_owner_id, user_id)):
        if hasattr(callback_or_fake, "answer"):
            await callback_or_fake.answer("❌ Нет доступа", show_alert=True)
        return
    offer_status = normalize_transition_status(offer.get("status") or "pending")
    if offer_status not in {"pending", "active"}:
        if hasattr(callback_or_fake, "answer"):
            await callback_or_fake.answer(
                "❌ Предложение уже обработано", show_alert=True
            )
        return

    # Отклоняем предложение
    offer["status"] = "rejected"
    offer["rejected_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    offer["rejected_by"] = user_id
    if reason:
        offer["rejection_reason"] = reason

    save_logistic_offers()
    request_state_updated = False
    if offer_source == "exporter":
        request_state_updated = refresh_exporter_request_offer_state(request_id)
    elif request:
        request_source = "farmer" if offer_source == "farmer" else "logistics"
        request["offers_count"] = count_logistic_offers_for_request(
            request_id, request_source
        )
        if is_request_open_for_offers(request.get("status")):
            request["status"] = "has_offers" if request["offers_count"] > 0 else "active"
        request_state_updated = True

    if request_state_updated and offer_source == "exporter":
        save_shipping_requests()
    if request_state_updated and offer_source == "farmer":
        save_farmers_logistics()
    if request_state_updated and offer_source == "logistics":
        save_logistics_requests_to_pickle()

    # Уведомляем логиста
    logist_id = get_offer_logist_id(offer)
    request_customer_id = request_owner_id or user_id
    if logist_id:
        asyncio.create_task(
            notify_logistic_offer_rejected(offer_id, request_customer_id, reason)
        )

    # Сообщение
    text = "❌ <b>ПРЕДЛОЖЕНИЕ ОТКЛОНЕНО</b>\n\n"
    text += f"✅ Предложение #{offer_id} отклонено\n"
    text += f"📋 Заявка #{request_id}\n\n"

    if reason:
        text += f"💬 Причина: <i>{reason}</i>\n\n"

    text += "ℹ️ Логист получил уведомление об отклонении"

    keyboard = InlineKeyboardMarkup()
    if offer_source == "farmer":
        keyboard.add(
            InlineKeyboardButton(
                "📋 К заявке", callback_data=f"view_request:farmer:{request_id}"
            )
        )
    elif offer_source == "logistics":
        keyboard.add(
            InlineKeyboardButton(
                "📋 К заявке", callback_data=f"view_logistics_req:{request_id}"
            )
        )
    else:
        keyboard.add(
            InlineKeyboardButton(
                "📋 Другие предложения", callback_data=f"view_request_offers_{request_id}"
            )
        )
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))

    if hasattr(callback_or_fake.message, "edit_text"):
        await callback_or_fake.message.edit_text(
            text, reply_markup=keyboard, parse_mode="HTML"
        )
    else:
        await callback_or_fake.message.answer(
            text, reply_markup=keyboard, parse_mode="HTML"
        )

    await state.finish()
    if hasattr(callback_or_fake, "answer"):
        await callback_or_fake.answer("✅ Предложение отклонено")

    logging.info(f"❌ Экспортёр {user_id} отклонил предложение #{offer_id}")


# ============================================================================
# ЭКСПОРТЁР: УПРАВЛЕНИЕ ЗАЯВКАМИ НА ДОСТАВКУ
# ============================================================================
@dp.callback_query_handler(lambda c: c.data == "my_shipping_requests", state="*")
async def show_my_shipping_requests(callback: types.CallbackQuery, state: FSMContext):
    """Список заявок экспортёра на доставку"""
    await state.finish()

    user_id = callback.from_user.id

    # Получаем заявки пользователя (с дедупликацией int/str ключей)
    my_requests = []
    seen_request_ids = set()
    for req_id, req in shipping_requests.items():
        if not isinstance(req, dict):
            continue
        if not same_id(req.get("exporter_id"), user_id):
            continue
        canonical_id = req.get("id", req_id)
        canonical_key = f"exporter:{canonical_id}"
        if canonical_key in seen_request_ids:
            continue
        seen_request_ids.add(canonical_key)
        my_requests.append((canonical_id, req, "exporter"))
    for req_id, req in logistics_requests.items():
        if not isinstance(req, dict):
            continue
        logistics_owner_id = (
            req.get("customer_id")
            or req.get("created_by")
            or req.get("exporter_id")
        )
        if not same_id(logistics_owner_id, user_id):
            continue
        canonical_id = req.get("id", req_id)
        canonical_key = f"logistics:{canonical_id}"
        if canonical_key in seen_request_ids:
            continue
        seen_request_ids.add(canonical_key)
        my_requests.append((canonical_id, req, "logistics"))

    if not my_requests:
        text = "📦 <b>МОИ ЗАЯВКИ</b>\n\n"
        text += "❌ У вас пока нет заявок на перевозку/логистику\n\n"
        text += "<i>Создайте заявку из раздела 'Мои пулы'</i>"

        keyboard = InlineKeyboardMarkup()
        keyboard.add(
            InlineKeyboardButton("➕ Создать пул", callback_data="create_pull")
        )
        keyboard.add(
            InlineKeyboardButton("🔙 Главное меню", callback_data="back_to_main")
        )

        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        await callback.answer()
        return

    # Группируем по статусам
    by_status = {
        "active": [],
        "has_offers": [],
        "assigned": [],
        "expeditor_selected": [],
        "in_progress": [],
        "completed": [],
        "cancelled": [],
    }

    for req_id, req, _source in my_requests:
        status = normalize_transition_status(req.get("status") or "active")
        if status != "has_offers" and is_request_open_for_offers(status):
            status = "active"
        if status not in by_status:
            status = "active"
        by_status[status].append((req_id, req, _source))

    # Сортируем по дате (новые первые)
    for status in by_status:
        by_status[status].sort(key=lambda x: x[1].get("created_at", ""), reverse=True)

    text = "📦 <b>МОИ ЗАЯВКИ</b>\n\n"
    text += f"Всего заявок: <b>{len(my_requests)}</b>\n\n"

    # Статистика
    active = len(by_status["active"]) + len(by_status["has_offers"])
    assigned = len(by_status["assigned"])
    expeditor_selected = len(by_status["expeditor_selected"])
    in_progress = len(by_status["in_progress"])
    completed = len(by_status["completed"])

    text += f"🆕 Активные: <b>{active}</b>\n"
    text += f"👤 Назначены: <b>{assigned}</b>\n"
    text += f"🚛 Экспедитор выбран: <b>{expeditor_selected}</b>\n"
    text += f"🚚 В пути: <b>{in_progress}</b>\n"
    text += f"✅ Завершены: <b>{completed}</b>\n\n"
    text += "━━━━━━━━━━━━━━━━━━━━\n\n"
    text += "Выберите заявку:"

    keyboard = InlineKeyboardMarkup(row_width=1)

    # Показываем заявки
    for status_key, status_name, emoji in [
        ("active", "Активные", "🆕"),
        ("has_offers", "Есть отклики", "📬"),
        ("assigned", "Назначены", "👤"),
        ("expeditor_selected", "Экспедитор выбран", "🚛"),
        ("in_progress", "В пути", "🚚"),
        ("completed", "Завершены", "✅"),
    ]:
        requests = by_status[status_key]
        if requests:
            for req_id, req, source in requests[:5]:
                pull_id = req.get("pull_id")
                all_pulls = pulls.get("pulls", {}) if isinstance(pulls, dict) else {}
                pull_info = all_pulls.get(pull_id) or all_pulls.get(str(pull_id), {})
                culture = req.get("culture") or pull_info.get("culture", "Не указана")
                volume = req.get("volume", 0)

                # Подсчёт предложений
                offers_count = len(
                    [
                        o
                        for o in logistic_offers.values()
                        if logistic_offer_matches_request(o, req_id, source)
                        and normalize_transition_status(o.get("status")) in {"pending", "active"}
                    ]
                )
                expeditor_offers_count = count_open_expeditor_request_offers_for_request(
                    req_id, source
                )

                source_mark = "📦" if source == "logistics" else "🚛"
                button_text = f"{emoji} {source_mark} #{req_id} | {culture} {volume:.0f}т"
                if offers_count > 0 and status_key in {"active", "has_offers"}:
                    button_text += f" | 📬 {offers_count}"
                if expeditor_offers_count > 0 and status_key in {
                    "assigned",
                    "expeditor_selected",
                }:
                    button_text += f" | 🚛 {expeditor_offers_count}"

                if source == "logistics":
                    keyboard.add(
                        InlineKeyboardButton(
                            button_text, callback_data=f"view_logistics_req:{req_id}"
                        )
                    )
                else:
                    keyboard.add(
                        InlineKeyboardButton(
                            button_text, callback_data=f"view_my_request_{req_id}"
                        )
                    )

    keyboard.add(
        InlineKeyboardButton("🔄 Обновить", callback_data="my_shipping_requests")
    )
    keyboard.add(InlineKeyboardButton("🔙 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("view_my_request_"), state="*")
async def view_my_request_details(callback: types.CallbackQuery, state: FSMContext):
    """Детальный просмотр своей заявки"""
    await state.finish()
    try:
        request_ref = callback.data.split("_")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка получения ID", show_alert=True)
        return

    _, request = find_shipping_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    user_id = callback.from_user.id

    if not same_id(request.get("exporter_id"), user_id):
        await callback.answer("❌ Это не ваша заявка", show_alert=True)
        return

    pull_id = request.get("pull_id")
    all_pulls = pulls.get("pulls", {}) if isinstance(pulls, dict) else {}
    pull_info = all_pulls.get(pull_id) or all_pulls.get(str(pull_id), {})
    route_from = request.get("route_from") or request.get("from_city") or "Не указано"
    route_to = request.get("route_to") or request.get("to_city") or "Не указано"
    text = f"📦 <b>ЗАЯВКА #{request_id}</b>\n\n"
    text += f"🌾 Культура: <b>{pull_info.get('culture', 'Не указана')}</b>\n"
    text += f"📦 Объём: <b>{request.get('volume', 0):.1f} т</b>\n"
    text += f"📍 Откуда: {route_from}\n"
    text += f"📍 Куда: {route_to}\n"
    preferred_date = request.get("loading_date") or request.get("desired_date")
    if preferred_date:
        text += f"📅 Желаемая дата: {preferred_date}\n"
    if request.get("budget"):
        text += f"💰 Бюджет: {request.get('budget'):,.0f} ₽\n"
    if request.get("requirements"):
        text += f"\n📋 Требования:\n{request.get('requirements')}\n"
    text += f"\n📅 Создана: {request.get('created_at', 'Не указано')}\n\n"
    text += "━━━━━━━━━━━━━━━━━━━━\n\n"

    status = normalize_transition_status(request.get("status") or "active")
    status_icon = status_map.get(status, "⚪").split()[0]
    status_name = get_status_name(status)
    text += f"📊 Статус: <b>{status_icon} {status_name}</b>\n\n"

    all_offers = [
        o
        for o in logistic_offers.values()
        if logistic_offer_matches_request(o, request_id, "exporter")
    ]
    pending_offers = [
        o for o in all_offers if normalize_transition_status(o.get("status")) in {"pending", "active"}
    ]
    accepted_offers = [
        o for o in all_offers if normalize_transition_status(o.get("status")) == "accepted"
    ]
    expeditor_offers = [
        o
        for o in expeditor_request_offers.values()
        if same_id(o.get("request_id"), request_id)
        and str(o.get("source") or "").strip().lower() in {"", "exporter"}
    ]
    expeditor_pending_offers = [
        o
        for o in expeditor_offers
        if normalize_transition_status(o.get("status") or "pending") in {"pending", "active"}
    ]

    text += "📬 Предложений:\n"
    text += f"  • Ожидают решения: <b>{len(pending_offers)}</b>\n"
    text += f"  • Принято: <b>{len(accepted_offers)}</b>\n"
    text += f"  • Всего: <b>{len(all_offers)}</b>\n\n"
    if get_assigned_logist_id(request):
        text += "🚛 Экспедиторских откликов:\n"
        text += f"  • Ожидают решения: <b>{len(expeditor_pending_offers)}</b>\n"
        text += f"  • Всего: <b>{len(expeditor_offers)}</b>\n\n"

    assigned_logist_id = get_assigned_logist_id(request)
    if assigned_logist_id:
        logist_info = get_user_by_id(assigned_logist_id) or {}
        logist_company = (
            logist_info.get("company_name")
            or logist_info.get("company_details")
            or logist_info.get("name")
            or "Не указана"
        )
        text += f"🚚 Логист: <b>{logist_company}</b>\n"
        if logist_info.get("phone"):
            text += f"📞 Телефон: {logist_info.get('phone')}\n"

    keyboard = InlineKeyboardMarkup(row_width=2)
    if is_request_open_for_offers(status):
        if len(pending_offers) > 0:
            keyboard.add(
                InlineKeyboardButton(
                    f"📬 Предложения ({len(pending_offers)})",
                    callback_data=f"view_request_offers_{request_id}",
                )
            )
        keyboard.add(
            InlineKeyboardButton(
                "✏️ Редактировать", callback_data=f"edit_request:{request_id}"
            ),
            InlineKeyboardButton(
                "❌ Отменить", callback_data=f"cancel_request_{request_id}"
            ),
        )
    elif status in {"assigned", "expeditor_selected"}:
        keyboard.add(
            InlineKeyboardButton(
                "📦 Доставка", callback_data=f"view_delivery_by_request_{request_id}"
            )
        )
        keyboard.add(
            InlineKeyboardButton(
                "📬 Предложения", callback_data=f"view_request_offers_{request_id}"
            )
        )
        keyboard.add(
            InlineKeyboardButton(
                f"🚛 Экспедиторы ({len(expeditor_pending_offers)})",
                callback_data=f"view_expeditor_offers_for_request:{request_id}",
            )
        )
    elif status in ["in_progress", "completed"]:
        keyboard.add(
            InlineKeyboardButton(
                "📦 Доставка", callback_data=f"view_delivery_by_request_{request_id}"
            )
        )
        if len(expeditor_offers) > 0:
            keyboard.add(
                InlineKeyboardButton(
                    "🚛 Предложения экспедиторов",
                    callback_data=f"view_expeditor_offers_for_request:{request_id}",
                )
            )

    keyboard.add(
        InlineKeyboardButton("🔙 К заявкам", callback_data="my_shipping_requests")
    )
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data.startswith("cancel_request_"), state="*")
async def cancel_request_confirm(callback: types.CallbackQuery, state: FSMContext):
    """Подтверждение отмены заявки"""
    await state.finish()

    try:
        request_ref = callback.data.split("_")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return

    _, request = find_shipping_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    user_id = callback.from_user.id

    if not same_id(request.get("exporter_id"), user_id):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return

    request_status = normalize_transition_status(request.get("status"))
    cancellable_statuses = {
        "pending",
        "active",
        "has_offers",
        "new",
        "open",
        "assigned",
        "expeditor_selected",
        "in_progress",
    }
    if request_status not in cancellable_statuses:
        await callback.answer("❌ Заявку в этом статусе нельзя отменить", show_alert=True)
        return

    # Подсчёт предложений
    pending_offers = [
        o
        for o in logistic_offers.values()
        if logistic_offer_matches_request(o, request_id, "exporter")
        and normalize_transition_status(o.get("status")) in {"pending", "active"}
    ]

    text = f"❓ <b>ОТМЕНА ЗАЯВКИ #{request_id}</b>\n\n"
    text += "Вы уверены, что хотите отменить заявку?\n\n"

    if len(pending_offers) > 0:
        text += f"⚠️ У вас есть <b>{len(pending_offers)}</b> ожидающих предложений!\n"
        text += "Все предложения будут автоматически отклонены.\n\n"

    text += "<i>Это действие нельзя будет отменить</i>"

    keyboard = InlineKeyboardMarkup(row_width=2)
    keyboard.add(
        InlineKeyboardButton(
            "✅ Да, отменить", callback_data=f"confirm_cancel_request_{request_id}"
        ),
        InlineKeyboardButton("❌ Нет", callback_data=f"view_my_request_{request_id}"),
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("confirm_cancel_request_"), state="*"
)
async def cancel_request_confirmed(callback: types.CallbackQuery, state: FSMContext):
    """Отмена заявки подтверждена"""
    await state.finish()

    try:
        request_ref = callback.data.split("_")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return

    _, request = find_shipping_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    user_id = callback.from_user.id

    if not same_id(request.get("exporter_id"), user_id):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return
    request_status = normalize_transition_status(request.get("status"))
    cancellable_statuses = {
        "pending",
        "active",
        "has_offers",
        "new",
        "open",
        "assigned",
        "expeditor_selected",
        "in_progress",
    }
    if request_status not in cancellable_statuses:
        await callback.answer("❌ Заявку в этом статусе нельзя отменить", show_alert=True)
        return

    # Отменяем заявку
    request["status"] = "cancelled"
    request["cancelled_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    # Закрываем все незакрытые предложения по заявке
    cancelled_offers = 0
    cancelled_deliveries = 0
    cancelled_expeditor_offers = 0
    cancelled_expeditor_routes = 0
    now_str = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    should_notify_logistics = False
    closed_offer_statuses = {
        "rejected",
        "cancelled",
        "canceled",
        "completed",
        "filled",
        "sold",
        "closed",
        "delivered",
    }
    for offer_id, offer in logistic_offers.items():
        if not isinstance(offer, dict):
            continue
        offer_status = normalize_transition_status(offer.get("status"))
        if (
            logistic_offer_matches_request(offer, request_id, "exporter")
            and offer_status not in closed_offer_statuses
        ):
            offer["status"] = "rejected"
            offer["rejected_at"] = now_str
            offer["rejection_reason"] = "Заявка отменена заказчиком"
            cancelled_offers += 1
            if get_offer_logist_id(offer):
                should_notify_logistics = True

    for exp_offer in expeditor_request_offers.values():
        if not isinstance(exp_offer, dict):
            continue
        if not same_id(exp_offer.get("request_id"), request_id):
            continue
        exp_offer_source = str(exp_offer.get("source") or "").strip().lower()
        if exp_offer_source == "logistic":
            exp_offer_source = "logistics"
        if exp_offer_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
            request_key = request_id if isinstance(request_id, str) else str(request_id)
            if request_id in shipping_requests or request_key in shipping_requests:
                source_candidates.add("exporter")
            if request_id in logistics_requests or request_key in logistics_requests:
                source_candidates.add("logistics")
            if (
                request_id in farmer_shipping_requests
                or request_key in farmer_shipping_requests
                or request_id in farmer_logistics_requests
                or request_key in farmer_logistics_requests
            ):
                source_candidates.add("farmer")
            if len(source_candidates) == 1:
                exp_offer_source = next(iter(source_candidates))
            else:
                inferred_source = infer_logistic_offer_source(request_id)
                if (
                    inferred_source in {"exporter", "farmer", "logistics"}
                    and (not source_candidates or inferred_source in source_candidates)
                ):
                    exp_offer_source = inferred_source
                else:
                    continue
        if exp_offer_source != "exporter":
            continue
        exp_status = normalize_transition_status(exp_offer.get("status") or "pending")
        if exp_status in {"completed", "cancelled", "rejected"}:
            continue
        exp_offer["status"] = "rejected"
        exp_offer["rejected_at"] = now_str
        exp_offer["rejection_reason"] = "Заявка отменена заказчиком"
        cancelled_expeditor_offers += 1

    for exp_route in expeditor_offers.values():
        if not isinstance(exp_route, dict):
            continue
        if not same_id(exp_route.get("request_id"), request_id):
            continue
        route_source = str(exp_route.get("source") or "").strip().lower()
        if route_source == "logistic":
            route_source = "logistics"
        if route_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
            request_key = request_id if isinstance(request_id, str) else str(request_id)
            if request_id in shipping_requests or request_key in shipping_requests:
                source_candidates.add("exporter")
            if request_id in logistics_requests or request_key in logistics_requests:
                source_candidates.add("logistics")
            if (
                request_id in farmer_shipping_requests
                or request_key in farmer_shipping_requests
                or request_id in farmer_logistics_requests
                or request_key in farmer_logistics_requests
            ):
                source_candidates.add("farmer")
            if len(source_candidates) == 1:
                route_source = next(iter(source_candidates))
            else:
                inferred_source = infer_logistic_offer_source(request_id)
                if (
                    inferred_source in {"exporter", "farmer", "logistics"}
                    and (not source_candidates or inferred_source in source_candidates)
                ):
                    route_source = inferred_source
                else:
                    continue
        if route_source not in {"", "exporter"}:
            continue
        route_status = normalize_transition_status(exp_route.get("status") or "pending")
        if route_status in {"completed", "cancelled", "rejected"}:
            continue
        exp_route["status"] = "cancelled"
        exp_route["cancelled_at"] = now_str
        cancelled_expeditor_routes += 1

    # Отменяем связанные доставки
    for delivery in deliveries.values():
        if not isinstance(delivery, dict):
            continue
        if not same_id(delivery.get("request_id"), request_id):
            continue
        if not same_id(delivery.get("exporter_id"), request.get("exporter_id")):
            continue
        delivery_source = str(delivery.get("source") or "").strip().lower()
        if delivery_source == "logistic":
            delivery_source = "logistics"
        if delivery_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
            request_key = request_id if isinstance(request_id, str) else str(request_id)
            if request_id in shipping_requests or request_key in shipping_requests:
                source_candidates.add("exporter")
            if request_id in logistics_requests or request_key in logistics_requests:
                source_candidates.add("logistics")
            if (
                request_id in farmer_shipping_requests
                or request_key in farmer_shipping_requests
                or request_id in farmer_logistics_requests
                or request_key in farmer_logistics_requests
            ):
                source_candidates.add("farmer")
            if len(source_candidates) == 1:
                delivery_source = next(iter(source_candidates))
            else:
                inferred_source = infer_logistic_offer_source(request_id)
                if (
                    inferred_source in {"exporter", "farmer", "logistics"}
                    and (not source_candidates or inferred_source in source_candidates)
                ):
                    delivery_source = inferred_source
                else:
                    continue
        if delivery_source != "exporter":
            continue
        if normalize_transition_status(delivery.get("status")) in {
            "completed",
            "cancelled",
        }:
            continue
        delivery["status"] = "cancelled"
        delivery["cancelled_at"] = now_str
        cancelled_deliveries += 1

    cancelled_deals = 0
    for deal in deals.values():
        if not isinstance(deal, dict):
            continue
        if not same_id(deal.get("request_id"), request_id):
            continue
        deal_source = str(deal.get("source") or "").strip().lower()
        if deal_source == "logistic":
            deal_source = "logistics"
        if deal_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
            request_key = request_id if isinstance(request_id, str) else str(request_id)
            if request_id in shipping_requests or request_key in shipping_requests:
                source_candidates.add("exporter")
            if request_id in logistics_requests or request_key in logistics_requests:
                source_candidates.add("logistics")
            if (
                request_id in farmer_shipping_requests
                or request_key in farmer_shipping_requests
                or request_id in farmer_logistics_requests
                or request_key in farmer_logistics_requests
            ):
                source_candidates.add("farmer")
            if len(source_candidates) == 1:
                deal_source = next(iter(source_candidates))
            else:
                inferred_source = infer_logistic_offer_source(request_id)
                if (
                    inferred_source in {"exporter", "farmer", "logistics"}
                    and (not source_candidates or inferred_source in source_candidates)
                ):
                    deal_source = inferred_source
                else:
                    continue
        if deal_source != "exporter":
            continue
        if request.get("exporter_id") and not same_id(
            deal.get("exporter_id"), request.get("exporter_id")
        ):
            continue
        if normalize_transition_status(deal.get("status")) in {
            "completed",
            "cancelled",
        }:
            continue
        deal["status"] = "cancelled"
        deal["cancelled_at"] = now_str
        cancelled_deals += 1

    if should_notify_logistics:
        asyncio.create_task(
            notify_logistic_request_cancelled(request_id, "Заказчик отменил заявку")
        )
    expeditor_id = get_assigned_expeditor_id(request)
    if expeditor_id:
        try:
            await bot.send_message(
                expeditor_id,
                "🚫 <b>Заявка на перевозку отменена заказчиком</b>\n\n"
                f"🆔 Заявка #{request_id}\n"
                "Дальнейшее исполнение не требуется.",
                parse_mode="HTML",
            )
        except Exception as e:
            logging.debug(
                f"Не удалось уведомить экспедитора {expeditor_id} об отмене заявки #{request_id}: {e}"
            )

    save_shipping_requests()
    save_logistic_offers()
    if cancelled_expeditor_offers:
        save_expeditor_data()
    if cancelled_expeditor_routes:
        save_expeditor_offers()
    if cancelled_deals:
        save_deals_to_pickle()
    if cancelled_deliveries:
        save_deliveries()

    text = f"✅ <b>ЗАЯВКА #{request_id} ОТМЕНЕНА</b>\n\n"
    text += "Заявка успешно отменена.\n"

    if cancelled_offers > 0:
        text += f"\n📬 Отклонено предложений: {cancelled_offers}\n"
        text += "Логисты получили уведомления.\n"
    if cancelled_expeditor_offers > 0:
        text += f"🚛 Отклонено предложений экспедиторов: {cancelled_expeditor_offers}\n"
    if cancelled_expeditor_routes > 0:
        text += f"✈️ Отменено маршрутов экспедиторов: {cancelled_expeditor_routes}\n"
    if cancelled_deliveries > 0:
        text += f"🚚 Отменено доставок: {cancelled_deliveries}\n"
    if cancelled_deals > 0:
        text += f"📋 Отменено сделок: {cancelled_deals}\n"

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton("📦 Мои заявки", callback_data="my_shipping_requests")
    )
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer("✅ Заявка отменена")

    logging.info(f"❌ Экспортёр {user_id} отменил заявку #{request_id}")


# ============================================================================
# ЛОГИСТИЧЕСКАЯ ЗАЯВКА: ОТМЕНА ВЛАДЕЛЬЦЕМ
# ============================================================================
@dp.callback_query_handler(
    lambda c: c.data.startswith("cancel_logistics_request:"), state="*"
)
async def cancel_logistics_request_confirm(
    callback: types.CallbackQuery, state: FSMContext
):
    await state.finish()

    try:
        request_ref = callback.data.split(":", 1)[1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return

    request = logistics_requests.get(request_id) or logistics_requests.get(str(request_id))
    if not isinstance(request, dict):
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    owner_id = (
        request.get("customer_id")
        or request.get("created_by")
        or request.get("exporter_id")
        or request.get("logist_id")
    )
    if not (user_role == "admin" or same_id(owner_id, user_id)):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return

    request_status = normalize_transition_status(request.get("status"))
    cancellable_statuses = {
        "pending",
        "active",
        "has_offers",
        "new",
        "open",
        "assigned",
        "expeditor_selected",
        "in_progress",
    }
    if request_status not in cancellable_statuses:
        await callback.answer("❌ Заявку в этом статусе нельзя отменить", show_alert=True)
        return

    pending_offers = [
        o
        for o in logistic_offers.values()
        if logistic_offer_matches_request(o, request_id, "logistics")
        and normalize_transition_status(o.get("status")) in {"pending", "active"}
    ]

    text = f"❓ <b>ОТМЕНА ЗАЯВКИ #{request_id}</b>\n\n"
    text += "Вы уверены, что хотите отменить логистическую заявку?\n\n"
    if pending_offers:
        text += f"⚠️ У вас есть <b>{len(pending_offers)}</b> ожидающих предложений!\n"
        text += "Все предложения будут автоматически отклонены.\n\n"
    text += "<i>Это действие нельзя будет отменить</i>"

    keyboard = InlineKeyboardMarkup(row_width=2)
    keyboard.add(
        InlineKeyboardButton(
            "✅ Да, отменить",
            callback_data=f"confirm_cancel_logistics_request:{request_id}",
        ),
        InlineKeyboardButton("❌ Нет", callback_data=f"view_logistics_req:{request_id}"),
    )

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("confirm_cancel_logistics_request:"), state="*"
)
async def cancel_logistics_request_confirmed(
    callback: types.CallbackQuery, state: FSMContext
):
    await state.finish()

    try:
        request_ref = callback.data.split(":", 1)[1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return

    request = logistics_requests.get(request_id) or logistics_requests.get(str(request_id))
    if not isinstance(request, dict):
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    owner_id = (
        request.get("customer_id")
        or request.get("created_by")
        or request.get("exporter_id")
        or request.get("logist_id")
    )
    if not (user_role == "admin" or same_id(owner_id, user_id)):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return

    request_status = normalize_transition_status(request.get("status"))
    cancellable_statuses = {
        "pending",
        "active",
        "has_offers",
        "new",
        "open",
        "assigned",
        "expeditor_selected",
        "in_progress",
    }
    if request_status not in cancellable_statuses:
        await callback.answer("❌ Заявку в этом статусе нельзя отменить", show_alert=True)
        return

    now_str = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    request["status"] = "cancelled"
    request["cancelled_at"] = now_str

    cancelled_offers = 0
    cancelled_deliveries = 0
    cancelled_expeditor_offers = 0
    cancelled_expeditor_routes = 0
    cancelled_deals = 0
    should_notify_logistics = False
    closed_offer_statuses = {
        "rejected",
        "cancelled",
        "canceled",
        "completed",
        "filled",
        "sold",
        "closed",
        "delivered",
    }

    for offer in logistic_offers.values():
        if not isinstance(offer, dict):
            continue
        offer_status = normalize_transition_status(offer.get("status"))
        if not logistic_offer_matches_request(offer, request_id, "logistics"):
            continue
        if offer_status in closed_offer_statuses:
            continue
        offer["status"] = "rejected"
        offer["rejected_at"] = now_str
        offer["rejection_reason"] = "Заявка отменена заказчиком"
        cancelled_offers += 1
        if get_offer_logist_id(offer):
            should_notify_logistics = True

    for exp_offer in expeditor_request_offers.values():
        if not isinstance(exp_offer, dict):
            continue
        if not same_id(exp_offer.get("request_id"), request_id):
            continue
        exp_offer_source = str(exp_offer.get("source") or "").strip().lower()
        if exp_offer_source == "logistic":
            exp_offer_source = "logistics"
        if exp_offer_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
            request_key = request_id if isinstance(request_id, str) else str(request_id)
            if request_id in shipping_requests or request_key in shipping_requests:
                source_candidates.add("exporter")
            if request_id in logistics_requests or request_key in logistics_requests:
                source_candidates.add("logistics")
            if (
                request_id in farmer_shipping_requests
                or request_key in farmer_shipping_requests
                or request_id in farmer_logistics_requests
                or request_key in farmer_logistics_requests
            ):
                source_candidates.add("farmer")
            if len(source_candidates) == 1:
                exp_offer_source = next(iter(source_candidates))
            else:
                inferred_source = infer_logistic_offer_source(request_id)
                if (
                    inferred_source in {"exporter", "farmer", "logistics"}
                    and (not source_candidates or inferred_source in source_candidates)
                ):
                    exp_offer_source = inferred_source
                else:
                    continue
        if exp_offer_source != "logistics":
            continue
        exp_status = normalize_transition_status(exp_offer.get("status") or "pending")
        if exp_status in {"completed", "cancelled", "rejected"}:
            continue
        exp_offer["status"] = "rejected"
        exp_offer["rejected_at"] = now_str
        exp_offer["rejection_reason"] = "Заявка отменена заказчиком"
        cancelled_expeditor_offers += 1

    for exp_route in expeditor_offers.values():
        if not isinstance(exp_route, dict):
            continue
        if not same_id(exp_route.get("request_id"), request_id):
            continue
        route_source = str(exp_route.get("source") or "").strip().lower()
        if route_source == "logistic":
            route_source = "logistics"
        if route_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
