# ============================================================================
# ЭКСПОРТЁР: ПРОСМОТР ДОСТАВОК
# ============================================================================
@dp.callback_query_handler(lambda c: c.data == "exporter_deliveries", state="*")
async def show_exporter_deliveries(callback: types.CallbackQuery, state: FSMContext):
    """Список доставок экспортёра"""
    await state.finish()

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if user_role not in {"exporter", "admin"}:
        await callback.answer("❌ Раздел доступен только экспортёрам", show_alert=True)
        return

    # Получаем доставки экспортёра (admin видит все доставки source=exporter)
    my_deliveries = []
    seen_delivery_ids = set()
    for deliv_id, deliv in deliveries.items():
        if not isinstance(deliv, dict):
            continue
        delivery_source = str(deliv.get("source") or "").strip().lower()
        if delivery_source == "logistic":
            delivery_source = "logistics"
        if delivery_source not in {"exporter", "farmer", "logistics"}:
            inferred_source = infer_logistic_offer_source(deliv.get("request_id"))
            if inferred_source in {"exporter", "farmer", "logistics"}:
                delivery_source = inferred_source
            else:
                continue
        if user_role == "admin":
            if delivery_source != "exporter":
                continue
        else:
            if not same_id(deliv.get("exporter_id"), user_id):
                continue
            if delivery_source != "exporter":
                continue
        canonical_id = deliv.get("id", deliv_id)
        canonical_key = str(canonical_id)
        if canonical_key in seen_delivery_ids:
            continue
        seen_delivery_ids.add(canonical_key)
        my_deliveries.append((canonical_id, deliv))

    if not my_deliveries:
        text = "📦 <b>МОИ ДОСТАВКИ</b>\n\n"
        text += "❌ У вас пока нет доставок\n\n"
        text += "<i>Доставки появятся после принятия предложений логистов</i>"

        keyboard = InlineKeyboardMarkup()
        keyboard.add(
            InlineKeyboardButton("📋 Мои заявки", callback_data="my_shipping_requests")
        )
        keyboard.add(
            InlineKeyboardButton("🔙 Главное меню", callback_data="back_to_main")
        )

        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        await callback.answer()
        return

    # Группируем по статусам
    by_status = {"pending": [], "in_progress": [], "completed": [], "cancelled": []}

    for deliv_id, deliv in my_deliveries:
        status = normalize_transition_status(deliv.get("status", "pending"))
        if status in {"new", "assigned", "expeditor_selected", "accepted", "open"}:
            status = "pending"
        if status not in by_status:
            status = "pending"
        by_status[status].append((deliv_id, deliv))

    title = "📦 <b>ДОСТАВКИ ЭКСПОРТЁРОВ</b>" if user_role == "admin" else "📦 <b>МОИ ДОСТАВКИ</b>"
    text = f"{title}\n\n"
    text += f"Всего доставок: <b>{len(my_deliveries)}</b>\n\n"

    pending = len(by_status["pending"])
    in_progress = len(by_status["in_progress"])
    completed = len(by_status["completed"])

    text += f"🕐 Ожидают начала: <b>{pending}</b>\n"
    text += f"🚚 В пути: <b>{in_progress}</b>\n"
    text += f"✅ Завершены: <b>{completed}</b>\n\n"
    text += "━━━━━━━━━━━━━━━━━━━━\n\n"
    text += "Выберите доставку:"

    keyboard = InlineKeyboardMarkup(row_width=1)

    # Показываем доставки
    for status_key, status_name, emoji in [
        ("pending", "Ожидают", "🕐"),
        ("in_progress", "В пути", "🚚"),
        ("completed", "Завершены", "✅"),
    ]:
        delivs = by_status[status_key]
        if delivs:
            for deliv_id, deliv in delivs[:5]:
                route = f"{deliv.get('route_from', '')} → {deliv.get('route_to', '')}"
                volume = deliv.get("volume", 0)

                button_text = f"{emoji} #{deliv_id} | {route[:20]} | {volume:.0f}т"

                keyboard.add(
                    InlineKeyboardButton(
                        button_text, callback_data=f"view_delivery_{deliv_id}"
                    )
                )

    keyboard.add(
        InlineKeyboardButton("🔄 Обновить", callback_data="exporter_deliveries")
    )
    keyboard.add(InlineKeyboardButton("🔙 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("view_delivery_by_request_"), state="*"
)
async def view_delivery_by_request(callback: types.CallbackQuery, state: FSMContext):
    """Просмотр доставки по ID заявки (редирект на view_delivery_...)"""
    await state.finish()

    try:
        request_ref = callback.data.split("_")[-1]
        request_id = int(request_ref) if str(request_ref).isdigit() else request_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка ID заявки", show_alert=True)
        return

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    _, request = find_shipping_request_by_id(request_id)
    if not request:
        await callback.answer("❌ Заявка не найдена", show_alert=True)
        return
    is_request_owner = same_id(request.get("exporter_id"), user_id)
    if not (is_request_owner or user_role == "admin"):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return

    # Ищем доставку экспортёра по request_id
    delivery_id = None
    for deliv_id, deliv in deliveries.items():
        if not isinstance(deliv, dict):
            continue
        if not same_id(deliv.get("request_id"), request_id):
            continue
        if is_request_owner and not same_id(deliv.get("exporter_id"), user_id):
            continue
        deliv_source = str(deliv.get("source") or "").strip().lower()
        if deliv_source == "logistic":
            deliv_source = "logistics"
        if deliv_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
            request_key = request_id if isinstance(request_id, str) else str(request_id)
            if request_id in shipping_requests or request_key in shipping_requests:
                source_candidates.add("exporter")
            if request_id in logistics_requests or request_key in logistics_requests:
                source_candidates.add("logistics")
            if (
                request_id in farmer_shipping_requests
                or request_key in farmer_shipping_requests
                or request_id in farmer_logistics_requests
                or request_key in farmer_logistics_requests
            ):
                source_candidates.add("farmer")
            if len(source_candidates) == 1:
                deliv_source = next(iter(source_candidates))
            else:
                inferred_source = infer_logistic_offer_source(request_id)
                if (
                    inferred_source in {"exporter", "farmer", "logistics"}
                    and (not source_candidates or inferred_source in source_candidates)
                ):
                    deliv_source = inferred_source
                else:
                    continue
        if deliv_source != "exporter":
            continue
        if normalize_transition_status(deliv.get("status")) == "cancelled":
            continue
        delivery_id = deliv_id
        break

    if delivery_id is None:
        await callback.answer("❌ Доставка по этой заявке не найдена", show_alert=True)
        return

    # Меняем data и переиспользуем общий просмотр доставки
    callback.data = f"view_delivery_{delivery_id}"
    await view_delivery_details(callback, state)


