@dp.callback_query_handler(
    lambda c: c.data.startswith("view_expeditor_offer_")
    and not c.data.startswith("view_expeditor_offer_for_pull:")
    and not c.data.startswith("view_expeditor_offer_for_request:"),
    state="*",
)
async def view_expeditor_offer_details(
    callback: types.CallbackQuery, state: FSMContext
):
    """Детальный просмотр предложения экспедитора"""
    await state.finish()

    try:
        offer_ref = callback.data.split("_")[-1]
        offer_id = int(offer_ref) if str(offer_ref).isdigit() else offer_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка получения ID", show_alert=True)
        return

    resolved_offer_id, offer = find_expeditor_offer_by_id(offer_id)
    if not offer:
        await callback.answer("❌ Предложение не найдено", show_alert=True)
        return
    offer_id = resolved_offer_id
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    is_admin = user_role == "admin"

    if not (is_admin or same_id(offer.get("expeditor_id"), user_id)):
        await callback.answer("❌ Это не ваше предложение", show_alert=True)
        return

    text = f"📋 <b>ПРЕДЛОЖЕНИЕ #{offer_id}</b>\n\n"
    text += f"📦 Услуга: <b>{offer.get('service_type', 'Не указана')}</b>\n"
    text += f"🚢 Порты: {offer.get('ports', 'Не указаны')}\n"
    text += f"💰 Цена: <b>{offer.get('price', 0):,.0f} ₽</b>\n"
    text += f"📅 Сроки: {offer.get('terms', 'Не указаны')}\n\n"

    if offer.get("description"):
        text += f"📝 Описание:\n<i>{offer.get('description')}</i>\n\n"

    text += f"📅 Создано: {offer.get('created_at', 'Не указано')}\n\n"
    text += "━━━━━━━━━━━━━━━━━━━━\n\n"

    # Статус
    status = normalize_transition_status(offer.get("status", "active"))
    if status == "open":
        status = "active"
    elif status == "accepted":
        status = "selected"

    if status == "active":
        text += "📊 Статус: <b>🆕 Активно</b>\n"
        text += "Ваше предложение видно экспортёрам"
    elif status == "selected":
        text += "📊 Статус: <b>✅ Выбрано экспортёром</b>\n"
        if offer.get("exporter_id"):
            exporter_info = get_user_by_id(offer.get("exporter_id")) or {}
            text += (
                f"\n🏢 Экспортёр: {exporter_info.get('company_name', 'Не указано')}\n"
            )
            text += f"📞 Телефон: {exporter_info.get('phone', 'Не указан')}"
    elif status == "in_progress":
        text += "📊 Статус: <b>🚚 В работе</b>\n"
        text += "Предложение участвует в активной перевозке"
    elif status == "completed":
        text += "📊 Статус: <b>🏁 Завершено</b>"
        if offer.get("completed_at"):
            text += f"\n<i>Завершено: {offer.get('completed_at')}</i>"
    elif status == "rejected":
        text += "📊 Статус: <b>❌ Отклонено</b>"
        if offer.get("rejection_reason"):
            text += f"\n<i>Причина: {offer.get('rejection_reason')}</i>"
    elif status == "cancelled":
        text += "📊 Статус: <b>❌ Отменено</b>"

    keyboard = InlineKeyboardMarkup(row_width=2)

    if status == "active":
        keyboard.add(
            InlineKeyboardButton(
                "✏️ Редактировать", callback_data=f"edit_expeditor_offer_{offer_id}"
            ),
            InlineKeyboardButton(
                "❌ Отменить", callback_data=f"cancel_expeditor_offer_{offer_id}"
            ),
        )

    keyboard.add(
        InlineKeyboardButton("🔙 К предложениям", callback_data="expeditor_my_offers")
    )
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("cancel_expeditor_offer_"), state="*"
)
async def cancel_expeditor_offer(callback: types.CallbackQuery, state: FSMContext):
    """Отмена предложения экспедитора"""
    await state.finish()

    try:
        offer_ref = callback.data.split("_")[-1]
        offer_id = int(offer_ref) if str(offer_ref).isdigit() else offer_ref
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка", show_alert=True)
        return

    resolved_offer_id, offer = find_expeditor_offer_by_id(offer_id)
    if not offer:
        await callback.answer("❌ Предложение не найдено", show_alert=True)
        return
    offer_id = resolved_offer_id
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    is_admin = user_role == "admin"

    if not (is_admin or same_id(offer.get("expeditor_id"), user_id)):
        await callback.answer("❌ Нет доступа", show_alert=True)
        return

    if normalize_transition_status(offer.get("status")) != "active":
        await callback.answer(
            "❌ Можно отменить только активные предложения", show_alert=True
        )
        return

    # Отменяем
    offer["status"] = "cancelled"
    offer["cancelled_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    save_expeditor_offers()

    text = f"✅ <b>ПРЕДЛОЖЕНИЕ #{offer_id} ОТМЕНЕНО</b>\n\n"
    text += "Предложение больше не будет показываться экспортёрам"

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton("💼 Мои предложения", callback_data="expeditor_my_offers")
    )
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer("✅ Предложение отменено")

    logging.info(f"❌ Экспедитор {user_id} отменил предложение #{offer_id}")


@dp.callback_query_handler(lambda c: c.data == "expeditor_available_pulls", state="*")
async def show_expeditor_available_pulls(
    callback: types.CallbackQuery, state: FSMContext
):
    """Просмотр доступных пулов для экспедитора"""
    await state.finish()

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if not (is_expeditor_role(user_role) or user_role == "admin"):
        await callback.answer("❌ Раздел доступен только экспедиторам", show_alert=True)
        return
    is_admin = user_role == "admin"

    # Получаем предложения экспедитора для определения портов
    my_offers = [
        offer
        for offer in expeditor_offers.values()
        if (is_admin or same_id(offer.get("expeditor_id"), user_id))
        and normalize_transition_status(offer.get("status")) == "active"
    ]

    # Собираем порты из предложений
    my_ports = set()
    for offer in my_offers:
        ports_str = offer.get("ports", "")
        if ports_str:
            ports_list = [p.strip() for p in ports_str.split(",")]
            my_ports.update([p.lower() for p in ports_list])

    # ✅ ИСПРАВЛЕНО: Ищем подходящие пулы
    suitable_pulls = []
    all_pulls = pulls.get("pulls", {})  # ✅ ДОБАВЛЕНО

    for pull_id, pull in all_pulls.items():  # ✅ ИСПРАВЛЕНО
        if not isinstance(pull, dict):  # ✅ ДОБАВЛЕНО
            continue

        if normalize_transition_status(pull.get("status")) != "filled":
            continue

        pull_port = pull.get("port", "").lower()

        # Проверяем совпадение портов
        if not my_ports or any(port in pull_port for port in my_ports):
            suitable_pulls.append((pull_id, pull))

    if not suitable_pulls:
        text = "🚢 <b>ДОСТУПНЫЕ ПУЛЫ</b>\n\n"

        keyboard = InlineKeyboardMarkup()
        if not my_offers and not is_admin:
            text += "❌ Сейчас нет подходящих заполненных пулов.\n\n"
            text += "<i>У вас пока нет активных предложений. Создайте предложение заранее.</i>"
            keyboard.add(
                InlineKeyboardButton(
                    "➕ Создать предложение", callback_data="create_expeditor_offer"
                )
            )
        else:
            text += "❌ Сейчас нет подходящих заполненных пулов"
            if my_ports:
                text += f" по вашим портам.\n\nВаши порты: <i>{', '.join(my_ports)}</i>"
            else:
                text += "."

        keyboard.add(
            InlineKeyboardButton(
                "🔄 Обновить", callback_data="expeditor_available_pulls"
            )
        )

        keyboard.add(
            InlineKeyboardButton("🔙 Главное меню", callback_data="back_to_main")
        )

        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        await callback.answer()
        return

    # Сортируем по дате (новые первые)
    suitable_pulls.sort(key=lambda x: x[1].get("created_at", ""), reverse=True)

    text = "🚢 <b>ДОСТУПНЫЕ ПУЛЫ</b>\n\n"
    text += f"Найдено пулов: <b>{len(suitable_pulls)}</b>\n"

    if my_ports:
        text += f"Ваши порты: <i>{', '.join(my_ports)}</i>\n"

    text += "\n━━━━━━━━━━━━━━━━━━━━\n\n"
    text += "Выберите пул:"

    keyboard = InlineKeyboardMarkup(row_width=1)

    for pull_id, pull in suitable_pulls[:10]:
        culture = pull.get("culture", "Не указана")
        volume = pull.get("current_volume", 0)
        port = pull.get("port", "Не указан")

        button_text = f"📦 #{pull_id} | {culture} {volume:.0f}т | {port}"

        keyboard.add(
            InlineKeyboardButton(
                button_text, callback_data=f"view_pull_for_expeditor_{pull_id}"
            )
        )

    if len(suitable_pulls) > 10:
        keyboard.add(
            InlineKeyboardButton(
                f"➕ Показать ещё {len(suitable_pulls) - 10}",
                callback_data="show_more_pulls_expeditor",
            )
        )

    keyboard.add(
        InlineKeyboardButton("🔄 Обновить", callback_data="expeditor_available_pulls")
    )
    keyboard.add(InlineKeyboardButton("🔙 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(
    lambda c: c.data.startswith("view_pull_for_expeditor_"), state="*"
)
async def view_pull_for_expeditor(callback: types.CallbackQuery, state: FSMContext):
    """Просмотр пула для экспедитора"""
    await state.finish()
    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if not (is_expeditor_role(user_role) or user_role == "admin"):
        await callback.answer("❌ Раздел доступен только экспедиторам", show_alert=True)
        return

    try:
        pull_id = int(callback.data.split("_")[-1])
    except (IndexError, ValueError):
        await callback.answer("❌ Ошибка получения ID", show_alert=True)
        return

    resolved_pull_id, pull = find_pull_by_id(pull_id)
    pull_id = resolved_pull_id if resolved_pull_id is not None else pull_id

    if not pull:
        await callback.answer("❌ Пул не найден", show_alert=True)
        return

    text = f"📦 <b>ПУЛ #{pull_id}</b>\n\n"
    text += f"🌾 Культура: <b>{pull.get('culture', 'Не указана')}</b>\n"
    text += f"📦 Объём: <b>{pull.get('current_volume', 0):.1f} т</b>\n"
    text += f"🚢 Порт отгрузки: {pull.get('port', 'Не указан')}\n"
    text += f"📅 Дата отгрузки: {pull.get('shipment_date', 'Не указана')}\n\n"

    # Информация об экспортёре
    exporter_id = pull.get("exporter_id")
    if exporter_id:
        exporter_info = get_user_by_id(exporter_id) or {}
        text += "<b>🏢 ЭКСПОРТЁР:</b>\n"
        text += f"Компания: {exporter_info.get('company_name', 'Не указана')}\n"
        text += f"Телефон: {exporter_info.get('phone', 'Не указан')}\n"
        if exporter_info.get("email"):
            text += f"Email: {exporter_info.get('email')}\n"
        text += "\n"

    text += "━━━━━━━━━━━━━━━━━━━━\n\n"
    text += "💡 <b>Для сотрудничества:</b>\n"
    text += "Свяжитесь с экспортёром напрямую\n"
    text += "или отправьте предложение услуг"

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton("💼 Мои предложения", callback_data="expeditor_my_offers")
    )
    keyboard.add(
        InlineKeyboardButton("🔙 К пулам", callback_data="expeditor_available_pulls")
    )
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data == "expeditor_statistics", state="*")
async def show_expeditor_statistics(callback: types.CallbackQuery, state: FSMContext):
    """Статистика экспедитора"""
    await state.finish()

    user_id = callback.from_user.id
    user_role = (get_user_by_id(user_id) or {}).get("role")
    if not (is_expeditor_role(user_role) or user_role == "admin"):
        await callback.answer("❌ Раздел доступен только экспедиторам", show_alert=True)
        return
    is_admin = user_role == "admin"

    # Собираем статистику (admin видит агрегированно по всем экспедиторам)
    my_offers = []
    seen_offer_ids = set()
    for offer_id, offer in expeditor_offers.items():
        if not isinstance(offer, dict):
            continue
        if not is_admin and not same_id(offer.get("expeditor_id"), user_id):
            continue
        canonical_id = offer.get("id", offer_id)
        canonical_key = str(canonical_id)
        if canonical_key in seen_offer_ids:
            continue
        seen_offer_ids.add(canonical_key)
        my_offers.append(offer)

    total_offers = len(my_offers)
    active_offers = len(
        [
            o
            for o in my_offers
            if normalize_transition_status(o.get("status"))
            in {"active", "open", "pending", "new"}
        ]
    )
    selected_offers = len(
        [
            o
            for o in my_offers
            if normalize_transition_status(o.get("status"))
            in {"selected", "accepted", "assigned"}
        ]
    )

    # Подсчёт пулов по портам
    ports_dict = {}
    for offer in my_offers:
        ports_str = offer.get("ports", "")
        if ports_str:
            for port in ports_str.split(","):
                port = port.strip()
                ports_dict[port] = ports_dict.get(port, 0) + 1

    text = "📊 <b>СТАТИСТИКА ЭКСПЕДИТОРОВ</b>\n\n" if is_admin else "📊 <b>МОЯ СТАТИСТИКА</b>\n\n"
    text += "<b>ПРЕДЛОЖЕНИЯ:</b>\n"
    text += f"📋 Всего предложений: <b>{total_offers}</b>\n"
    text += f"🆕 Активных: <b>{active_offers}</b>\n"
    text += f"✅ Выбрано: <b>{selected_offers}</b>\n\n"

    if selected_offers > 0 and total_offers > 0:
        success_rate = (selected_offers / total_offers) * 100
        text += f"📈 Процент успеха: <b>{success_rate:.1f}%</b>\n\n"

    if ports_dict:
        text += "<b>ПОРТЫ:</b>\n"
        for port, count in sorted(ports_dict.items(), key=lambda x: x[1], reverse=True)[
            :5
        ]:
            text += f"🚢 {port}: {count} предложений\n"
        text += "\n"

    # Средняя цена услуг
    prices = [o.get("price", 0) for o in my_offers if o.get("price")]
    if prices:
        avg_price = sum(prices) / len(prices)
        text += "<b>ЦЕНООБРАЗОВАНИЕ:</b>\n"
        text += f"💰 Средняя цена: <b>{avg_price:,.0f} ₽</b>\n"
        text += f"💵 Мин. цена: {min(prices):,.0f} ₽\n"
        text += f"💸 Макс. цена: {max(prices):,.0f} ₽\n"

    keyboard = InlineKeyboardMarkup()
    keyboard.add(
        InlineKeyboardButton("💼 Мои предложения", callback_data="expeditor_my_offers")
    )
    keyboard.add(
        InlineKeyboardButton("🔄 Обновить", callback_data="expeditor_statistics")
    )
    keyboard.add(InlineKeyboardButton("🔙 Главное меню", callback_data="back_to_main"))

    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


# ============= ИНТЕРАКТИВНЫЙ ОБРАБОТЧИК: МОИ СДЕЛКИ С ФИЛЬТРАЦИЕЙ И ДЕТАЛЯМИ =============


# FSM состояния для просмотра сделок
class DealView(StatesGroup):
    viewing_deals = State()
    viewing_detail = State()


deals_cache = {}


# ==========================@==================================================
@dp.message_handler(lambda msg: msg.text in ["📋 Мои сделки"])
async def show_user_deals(message: types.Message, state: FSMContext):
    """✅ ГЛАВНЫЙ ОБРАБОТЧИК - показывает ВСЕ статусы, кнопки ТОЛЬКО если > 0"""
    await state.finish()

    user_id = message.from_user.id
    user_data = get_user_by_id(user_id) or {}
    user_role = user_data.get("role", "unknown")
    user_name = user_data.get("name", "Пользователь")

    logging.critical(f"📋 МОИ СДЕЛКИ/ПАРТИИ: user_id={user_id}, role={user_role}")

    try:
        keyboard = InlineKeyboardMarkup(row_width=1)
        text = ""

        # ============================================================================
        # 👨‍🌾 ФЕРМЕР
        # ============================================================================
        if user_role == "farmer":
            user_batches = get_user_batches(user_id)
            farmer_groups = {
                "active": {"active", "pending", "активна", "активен", "", "none"},
                "reserved": {"reserved", "зарезервирована"},
                "sold": {"sold", "проданные", "продано"},
                "canceled": {"cancelled", "отменено", "withdrawn", "снята", "снято"},
            }

            # Нормализуем статусы - приводим к нижнему регистру
            active = len(
                [
                    d
                    for d in user_batches
                    if status_in_group(d.get("status"), farmer_groups["active"])
                ]
            )
            reserved = len(
                [
                    d
                    for d in user_batches
                    if status_in_group(d.get("status"), farmer_groups["reserved"])
                    or d.get("reserved_volume", 0) > 0
                ]
            )
            sold = len(
                [
                    d
                    for d in user_batches
                    if status_in_group(d.get("status"), farmer_groups["sold"])
                    or d.get("sold")
                ]
            )
            canceled = len(
                [
                    d
                    for d in user_batches
                    if status_in_group(d.get("status"), farmer_groups["canceled"])
                ]
            )
            matches = len([d for d in user_batches if len(d.get("matches", [])) > 0])

            total = active + reserved + sold + canceled
            total_volume = sum([b.get("volume", 0) for b in user_batches])
            total_price = sum(
                [b.get("volume", 0) * b.get("price", 0) for b in user_batches]
            )

            text = (
                "<b>👨‍🌾 МОИ ПАРТИИ</b>\n\n"
                "<b>👨‍🌾 Фермер</b>\n"
                f"👤 {user_name}\n"
                f"📊 Всего: <b>{total}</b>\n"
                f"📦 Объём: {total_volume:,.0f}т\n"
                f"💰 Сумма: {total_price:,.0f}₽\n\n"
                f"✅ Активные: {active}\n"
                f"🔒 Зарезервированные: {reserved}\n"
                f"💰 Проданные: {sold}\n"
                f"❌ Снятые с продажи: {canceled}\n"
                f"🎯 С совпадениями: {matches}\n\n"
                "<b>Выберите статус:</b>"
            )

            # ТОЛЬКО кнопки если COUNT > 0
            if active > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"✅ Активные ({active})",
                        callback_data="deals_status:farmer:active",
                    )
                )
            if reserved > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"🔒 Зарезервированные ({reserved})",
                        callback_data="deals_status:farmer:reserved",
                    )
                )
            if sold > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"💰 Проданные ({sold})",
                        callback_data="deals_status:farmer:sold",
                    )
                )
            if canceled > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"❌ Снятые с продажи ({canceled})",
                        callback_data="deals_status:farmer:canceled",
                    )
                )
            if matches > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"🎯 С совпадениями ({matches})",
                        callback_data="deals_status:farmer:matches",
                    )
                )

            if total == 0:
                text = (
                    "👨‍🌾 <b>МОИ ПАРТИИ</b>\n\n"
                    f"👤 {user_name}\n"
                    "📭 <b>Партий не найдено</b>\n\n"
                    "💡 <b>Подсказка:</b> Создайте новую партию через '➕ Добавить партию'"
                )

        # ============================================================================
        # 📤 ЭКСПОРТЕР
        # ============================================================================
        elif user_role == "exporter":
            # ✅ ИСПРАВЛЕНО: Получаем пулы из правильного места
            all_pulls_dict = pulls.get("pulls", {})
            all_pulls = []
            seen_pull_ids = set()
            for pull_key, pull in all_pulls_dict.items():
                if not isinstance(pull, dict):
                    continue
                if not (
                    same_id(pull.get("exporter_id"), user_id)
                    or same_id(pull.get("creator_id"), user_id)
                ):
                    continue
                canonical_id = pull.get("id", pull_key)
                canonical_key = str(canonical_id)
                if canonical_key in seen_pull_ids:
                    continue
                seen_pull_ids.add(canonical_key)
                all_pulls.append(pull)

            active = len(
                [
                    d
                    for d in all_pulls
                    if is_pull_open_status(d.get("status"))
                ]
            )
            filled = len(
                [
                    d
                    for d in all_pulls
                    if status_in_group(d.get("status"), {"filled"})
                ]
            )
            closed = len(
                [
                    d
                    for d in all_pulls
                    if status_in_group(d.get("status"), {"closed"})
                ]
            )
            completed = len(
                [
                    d
                    for d in all_pulls
                    if status_in_group(d.get("status"), {"completed", "sold"})
                ]
            )
            cancelled = len(
                [
                    d
                    for d in all_pulls
                    if status_in_group(d.get("status"), {"cancelled"})
                ]
            )

            total_volume = sum(
                [p.get("target_volume", 0) for p in all_pulls if isinstance(p, dict)]
            )
            total_price = sum(
                [
                    p.get("target_volume", 0)
                    * (
                        get_safe_float(p.get("price_per_ton"), 0)
                        or get_safe_float(p.get("price"), 0)
                    )
                    for p in all_pulls
                    if isinstance(p, dict)
                ]
            )

            text = (
                "📤 <b>МОИ ПУЛЫ</b>\n\n"
                f"👤 {user_name}\n"
                f"📊 Всего: <b>{len(all_pulls)}</b>\n"
                f"📦 Объём: {total_volume:,.0f}т\n"
                f"💰 Сумма: {total_price:,.0f}₽\n\n"
                f"✅ Активные: {active}\n"
                f"🔒 Заполненные: {filled}\n"
                f"💰 Закрытые: {closed}\n"
                f"❌ Отмененные: {cancelled}\n"
                f"🎯 Завершенные: {completed}\n\n"
                "<b>Выберите статус:</b>"
            )

            # ТОЛЬКО кнопки если COUNT > 0
            if active > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"✅ Активные ({active})",
                        callback_data="deals_status:exporter:active",
                    )
                )
            if filled > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"🔒 Заполненные ({filled})",
                        callback_data="deals_status:exporter:filled",
                    )
                )
            if closed > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"💰 Закрытые ({closed})",
                        callback_data="deals_status:exporter:closed",
                    )
                )
            if cancelled > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"❌ Отмененные ({cancelled})",
                        callback_data="deals_status:exporter:cancelled",
                    )
                )
            if completed > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"🎯 Завершенные ({completed})",
                        callback_data="deals_status:exporter:completed",
                    )
                )

            if len(all_pulls) == 0:
                text = (
                    "📤 <b>МОИ ПУЛЫ</b>\n\n"
                    f"👤 {user_name}\n"
                    "📭 <b>Пулов не найдено</b>\n\n"
                    "💡 <b>Подсказка:</b> Создайте новый пул через '➕ Создать пул'"
                )

        # ============================================================================
        # 🚚 ЛОГИСТ
        # ============================================================================
        elif is_logistic_role(user_role):
            all_orders = []
            seen_order_ids = set()
            for delivery_key, delivery in deliveries.items():
                if not isinstance(delivery, dict):
                    continue
                if not same_id(get_assigned_logist_id(delivery), user_id):
                    continue
                canonical_id = delivery.get("id", delivery_key)
                canonical_key = str(canonical_id)
                if canonical_key in seen_order_ids:
                    continue
                seen_order_ids.add(canonical_key)
                all_orders.append(delivery)

            pending = len(
                [
                    d
                    for d in all_orders
                    if status_in_group(
                        d.get("status"),
                        {"pending", "new", "assigned", "expeditor_selected", "", "none"},
                    )
                ]
            )
            in_progress = len(
                [
                    d
                    for d in all_orders
                    if status_in_group(d.get("status"), {"in_progress"})
                ]
            )
            completed = len(
                [
                    d
                    for d in all_orders
                    if status_in_group(d.get("status"), {"completed"})
                ]
            )

            total_volume = sum([o.get("volume", 0) for o in all_orders])

            def _request_total_price(delivery):
                direct_price = get_safe_float(delivery.get("price"), 0)
                if direct_price > 0:
                    return direct_price
                offer_id = delivery.get("offer_id") or delivery.get("logistic_offer_id")
                if offer_id is None:
                    return 0
                _, linked_offer = find_logistic_offer_by_id(offer_id)
                if not isinstance(linked_offer, dict):
                    return 0
                return get_safe_float(linked_offer.get("price"), 0)

            total_price = sum([_request_total_price(o) for o in all_orders])

            text = (
                "🚚 <b>МОИ ДОСТАВКИ</b>\n\n"
                f"👤 {user_name}\n"
                f"📊 Всего: <b>{len(all_orders)}</b>\n"
                f"📦 Объём: {total_volume:,.0f}т\n"
                f"💰 Сумма: {total_price:,.0f}₽\n\n"
                f"⏳ Ожидающие: {pending}\n"
                f"🚗 В пути: {in_progress}\n"
                f"✅ Доставлено: {completed}\n\n"
                "<b>Выберите статус:</b>"
            )

            # ТОЛЬКО кнопки если COUNT > 0
            if pending > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"⏳ Ожидающие ({pending})",
                        callback_data="deals_status:logist:pending",
                    )
                )
            if in_progress > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"🚗 В пути ({in_progress})",
                        callback_data="deals_status:logist:in_progress",
                    )
                )
            if completed > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"✅ Доставлено ({completed})",
                        callback_data="deals_status:logist:completed",
                    )
                )

            if len(all_orders) == 0:
                text = (
                    "🚚 <b>МОИ ДОСТАВКИ</b>\n\n"
                    f"👤 {user_name}\n"
                    "📭 <b>Доставок не найдено</b>"
                )

        # ============================================================================
        # ✈️ ЭКСПЕДИТОР
        # ============================================================================
        elif is_expeditor_role(user_role):
            all_exp_items = []
            seen_offer_ids = set()
            for offer_key, offer in expeditor_offers.items():
                if not isinstance(offer, dict):
                    continue
                if not same_id(offer.get("expeditor_id"), user_id):
                    continue
                canonical_id = offer.get("id", offer_key)
                canonical_key = str(canonical_id)
                if canonical_key in seen_offer_ids:
                    continue
                seen_offer_ids.add(canonical_key)
                all_exp_items.append(
                    {
                        "item_type": "offer",
                        "status": offer.get("status"),
                        "volume": get_safe_float(offer.get("max_volume"), 0)
                        or get_safe_float(offer.get("volume"), 0),
                        "price": get_safe_float(offer.get("price"), 0),
                    }
                )

            seen_delivery_ids = set()
            for delivery_key, delivery in deliveries.items():
                if not isinstance(delivery, dict):
                    continue
                if not same_id(delivery.get("expeditor_id"), user_id):
                    continue
                canonical_id = delivery.get("id", delivery_key)
                canonical_key = str(canonical_id)
                if canonical_key in seen_delivery_ids:
                    continue
                seen_delivery_ids.add(canonical_key)
                all_exp_items.append(
                    {
                        "item_type": "delivery",
                        "status": delivery.get("status"),
                        "volume": get_safe_float(delivery.get("volume"), 0),
                        "price": get_safe_float(delivery.get("price"), 0),
                    }
                )

            active = len(
                [
                    d
                    for d in all_exp_items
                    if status_in_group(
                        d.get("status"),
                        {
                            "active",
                            "open",
                            "selected",
                            "pending",
                            "new",
                            "assigned",
                            "expeditor_selected",
                            "",
                            "none",
                        },
                    )
                ]
            )
            in_progress = len(
                [
                    d
                    for d in all_exp_items
                    if status_in_group(d.get("status"), {"in_progress"})
                ]
            )
            delivered = len(
                [
                    d
                    for d in all_exp_items
                    if status_in_group(d.get("status"), {"completed"})
                ]
            )

            total_volume = sum([d.get("volume", 0) for d in all_exp_items])
            total_price = sum([d.get("price", 0) for d in all_exp_items])

            text = (
                "✈️ <b>МОИ МАРШРУТЫ</b>\n\n"
                f"👤 {user_name}\n"
                f"📊 Всего: <b>{len(all_exp_items)}</b>\n"
                f"📦 Объём: {total_volume:,.0f}т\n"
                f"💰 Сумма: {total_price:,.0f}₽\n\n"
                f"🟢 Активные: {active}\n"
                f"⏳ В пути: {in_progress}\n"
                f"✅ Доставлено: {delivered}\n\n"
                "<b>Выберите статус:</b>"
            )

            # ТОЛЬКО кнопки если COUNT > 0
            if active > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"🟢 Активные ({active})",
                        callback_data="deals_status:expeditor:active",
                    )
                )
            if in_progress > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"⏳ В пути ({in_progress})",
                        callback_data="deals_status:expeditor:in_progress",
                    )
                )
            if delivered > 0:
                keyboard.add(
                    InlineKeyboardButton(
                        f"✅ Доставлено ({delivered})",
                        callback_data="deals_status:expeditor:completed",
                    )
                )

            if len(all_exp_items) == 0:
                text = (
                    "✈️ <b>МОИ МАРШРУТЫ</b>\n\n"
                    f"👤 {user_name}\n"
                    "📭 <b>Маршрутов не найдено</b>"
                )

        else:
            text = f"❓ Неизвестная роль: {user_role}"

        await message.answer(text, reply_markup=keyboard, parse_mode="HTML")
        logging.info(f"✅ Главное меню отправлено: {user_role}")

    except Exception as e:
        logging.error(f"❌ ОШИБКА: {e}", exc_info=True)
        await message.answer(f"❌ Ошибка: {str(e)}")


@dp.callback_query_handler(
    lambda q: q.data == "main_menu"
)
async def back_to_main_overview_handler(
    callback: types.CallbackQuery, state: FSMContext = None
):
    """✅ Возврат в главное меню для ВСЕХ кнопок назад"""
    user_id = callback.from_user.id
    current_time = time.time()
    last_click = last_back_click.get(user_id, 0)

    # ✅ ANTISPAM: игнорируем клики быстрее 0.5 секунды
    if current_time - last_click < 0.5:
        logging.info(f"⏱️ Защита от спама: {user_id} нажимает слишком быстро")
        await callback.answer("⏱️ Подождите немного...", show_alert=False)
        return

    last_back_click[user_id] = current_time
    await callback.answer()

    try:
        if state:
            try:
                await state.finish()
            except Exception as e:
                logging.debug(f"state.finish() failed in back_to_main: {e}")

        user_data = get_user_by_id(user_id) or {}
        role = user_data.get("role", "unknown").lower()

        logging.info(f"⬅️ Возврат в главное меню: role={role}, user_id={user_id}")

        # ✅ ВСЕГДА ИНИЦИАЛИЗИРУЕМ VARIABLES В НАЧАЛЕ!
        text = "<b>📊 Главное меню</b>\n\n"
        text += f"👤 Роль: <b>{role}</b>\n"
        text += f"👤 Пользователь: {user_data.get('name', 'Unknown')}\n\n"
        text += "Выберите действие:"

        keyboard = InlineKeyboardMarkup(row_width=1)
        keyboard.add(InlineKeyboardButton("📋 Мои сделки", callback_data="my_deals"))
        keyboard.add(InlineKeyboardButton("📊 Статистика", callback_data="stats"))
        keyboard.add(InlineKeyboardButton("⚙️ Настройки", callback_data="settings"))

        # ✅ TRY EDIT
        try:
            await callback.message.edit_text(
                text, reply_markup=keyboard, parse_mode="HTML"
            )
            logging.info("✅ Главное меню отредактировано успешно")
        except Exception as e:
            error_str = str(e).lower()
            if "not modified" in error_str:
                logging.info("⚠️ Сообщение уже содержит то же содержимое")
            else:
                logging.warning(f"⚠️ edit_text ошибка: {error_str}")
                try:
                    await callback.message.answer(
                        text, reply_markup=keyboard, parse_mode="HTML"
                    )
                    logging.info("✅ Новое сообщение отправлено")
                except Exception as e2:
                    logging.error(f"❌ answer ошибка: {e2}")

    except Exception as e:
        logging.error(f"❌ КРИТИЧЕСКАЯ ОШИБКА: {e}", exc_info=True)
        try:
            recovery_kb = InlineKeyboardMarkup()
            recovery_kb.add(
                InlineKeyboardButton("🏠 Повторить", callback_data="back_to_main")
            )
            await callback.message.edit_text(
                f"❌ Ошибка: {str(e)[:100]}",
                reply_markup=recovery_kb,
                parse_mode="HTML",
            )
        except Exception as recovery_error:
            logging.debug(f"Recovery edit failed in back_to_main: {recovery_error}")


@dp.callback_query_handler(lambda c: c.data == "my_deals", state="*")
async def my_deals_callback(callback: types.CallbackQuery, state: FSMContext):
    """Открывает единый экран сделок/партий с актуальной бизнес-логикой."""
    await state.finish()
    # Проксируем callback-контекст в message-handler, чтобы не поддерживать две
    # расходящиеся реализации меню "Мои сделки".
    class _DealsMessageProxy:
        def __init__(self, cb: types.CallbackQuery):
            self.from_user = cb.from_user
            self.answer = cb.message.answer

    await show_user_deals(_DealsMessageProxy(callback), state)
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data == "stats", state="*")
async def stats_callback(callback: types.CallbackQuery, state: FSMContext):
    """Статистика: админская для ADMIN_ID, базовая личная для остальных."""
    await state.finish()
    user_id = callback.from_user.id

    if user_id == ADMIN_ID:
        text = format_admin_statistics()
    else:
        role = (get_user_by_id(user_id) or {}).get("role", "unknown")
        my_batches = sum(
            1 for _, farmer_id, _ in iter_all_batches() if same_id(farmer_id, user_id)
        )
        my_deals = 0

        if role == "farmer":
            my_deals = my_batches
        elif role == "exporter":
            seen_pull_ids = set()
            for pull_key, pull in pulls.get("pulls", {}).items():
                if not isinstance(pull, dict):
                    continue
                if not (
                    same_id(pull.get("exporter_id"), user_id)
                    or same_id(pull.get("creator_id"), user_id)
                ):
                    continue
                canonical_id = pull.get("id", pull_key)
                seen_pull_ids.add(str(canonical_id))
            my_deals = len(seen_pull_ids)
        elif is_logistic_role(role):
            seen_delivery_ids = set()
            for delivery_key, delivery in deliveries.items():
                if not isinstance(delivery, dict):
                    continue
                if not same_id(get_assigned_logist_id(delivery), user_id):
                    continue
                canonical_id = delivery.get("id", delivery_key)
                seen_delivery_ids.add(str(canonical_id))
            my_deals = len(seen_delivery_ids)
        elif is_expeditor_role(role):
            seen_offer_ids = set()
            for offer_key, offer in expeditor_offers.items():
                if not isinstance(offer, dict):
                    continue
                if not same_id(offer.get("expeditor_id"), user_id):
                    continue
                canonical_id = offer.get("id", offer_key)
                seen_offer_ids.add(str(canonical_id))

            seen_delivery_ids = set()
            for delivery_key, delivery in deliveries.items():
                if not isinstance(delivery, dict):
                    continue
                if not same_id(delivery.get("expeditor_id"), user_id):
                    continue
                canonical_id = delivery.get("id", delivery_key)
                seen_delivery_ids.add(str(canonical_id))

            my_deals = len(seen_offer_ids) + len(seen_delivery_ids)
        else:
            for deal in deals.values():
                if not isinstance(deal, dict):
                    continue
                if same_id(deal.get("user_id"), user_id):
                    my_deals += 1

        text = (
            "📊 <b>Ваша статистика</b>\n\n"
            f"👤 Роль: {role}\n"
            f"🌾 Ваших партий: {my_batches}\n"
            f"📋 Ваших сделок: {my_deals}\n"
        )

    keyboard = InlineKeyboardMarkup()
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))
    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data == "settings", state="*")
async def settings_callback(callback: types.CallbackQuery, state: FSMContext):
    """Настройки профиля через существующие edit_profile callbacks."""
    await state.finish()
    keyboard = profile_edit_keyboard()
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))
    await callback.message.edit_text(
        "⚙️ <b>Настройки профиля</b>\n\nВыберите поле для изменения:",
        reply_markup=keyboard,
        parse_mode="HTML",
    )
    await callback.answer()


# ============================================================================
# ФИЛЬТР ПО СТАТУСУ
# ============================================================================
@dp.callback_query_handler(lambda q: q.data.startswith("deals_status:"))
async def filter_deals_by_status(callback: types.CallbackQuery):
    """✅ Фильтрует сделки по статусам - ПОЛНОСТЬЮ ИСПРАВЛЕНО"""
    await callback.answer()

    try:
        parts = callback.data.split(":")
        if len(parts) < 3:
            await callback.answer("Некорректный формат фильтра", show_alert=True)
            return

        requested_role = str(parts[1]).strip().lower()
        status = parts[2]
        user_id = callback.from_user.id
        user = get_user_by_id(user_id) or {}
        user_role = str(user.get("role", "")).strip().lower()

        if user_id == ADMIN_ID:
            role = requested_role
        elif user_role == "farmer":
            role = "farmer"
        elif user_role == "exporter":
            role = "exporter"
        elif is_logistic_role(user_role):
            role = "logist"
        elif is_expeditor_role(user_role):
            role = "expeditor"
        else:
            await callback.answer("Роль не определена", show_alert=True)
            return

        if requested_role != role and user_id != ADMIN_ID:
            logging.warning(
                "⚠️ deals_status role spoof blocked: requested=%s actual=%s user_id=%s",
                requested_role,
                role,
                user_id,
            )

        logging.info(f"📊 Фильтр: role={role}, status={status}, user_id={user_id}")

        filtered_items = []
        search_status = normalize_transition_status(status)
        logging.info(f"   🔍 Ищу статус: '{search_status}'")

        # ✅ УБРАНА СТРОКА: if search_status == "all": search_status = "active"

        # ✅ ЭМОДЗИ КУЛЬТУР
        culture_emoji = {
            "пшеница": "🌾",
            "ячмень": "🌾",
            "кукуруза": "🌽",
            "подсолнечник": "🌻",
            "соя": "🫘",
            "рапс": "🌿",
        }

        # ════════════════════════════════════════════════════════════════════
        # 👨‍🌾 ФЕРМЕР - БАТЧИ
        # ════════════════════════════════════════════════════════════════════
        if role == "farmer":
            farmer_groups = {
                "active": {"active", "pending", "активна", "активен", "", "none"},
                "reserved": {"reserved", "зарезервирована"},
                "sold": {"sold", "проданные", "продано"},
                "canceled": {"cancelled", "отменено", "withdrawn", "снята", "снято"},
                "cancelled": {"cancelled", "отменено", "withdrawn", "снята", "снято"},
            }

            user_batches = get_user_batches(user_id)
            logging.info(f"   📦 Батчей у фермера: {len(user_batches)}")
            logging.info(f"   🔍 Ищу статус: '{search_status}'")

            for idx, batch in enumerate(user_batches):
                batch_status = batch.get("status", "Активна")
                logging.info(
                    f"      Батч #{idx}: '{batch.get('culture', 'N/A')}' → статус='{batch_status}'"
                )

                # ✅ ИСПРАВЛЕННАЯ ЛОГИКА!
                if search_status == "all":
                    # Показываем ВСЕ батчи
                    filtered_items.append(
                        {
                            "index": idx,
                            "culture": batch.get("culture", "N/A"),
                            "volume": batch.get("volume", 0),
                            "price": batch.get("price", 0),
                            "status": batch_status,
                            "id": batch.get("id", idx),
                        }
                    )
                    logging.info("         ✅ ДОБАВЛЕНА в результаты (all)!")
                elif search_status == "matches" and len(batch.get("matches", [])) > 0:
                    filtered_items.append(
                        {
                            "index": idx,
                            "culture": batch.get("culture", "N/A"),
                            "volume": batch.get("volume", 0),
                            "price": batch.get("price", 0),
                            "status": batch_status,
                            "id": batch.get("id", idx),
                        }
                    )
                    logging.info("         ✅ ДОБАВЛЕНА в результаты (matches)!")
                elif status_in_group(
                    batch_status,
                    farmer_groups.get(search_status, {search_status}),
                ):
                    # Показываем только с конкретным статусом
                    filtered_items.append(
                        {
                            "index": idx,
                            "culture": batch.get("culture", "N/A"),
                            "volume": batch.get("volume", 0),
                            "price": batch.get("price", 0),
                            "status": batch_status,
                            "id": batch.get("id", idx),
                        }
                    )
                    logging.info("         ✅ ДОБАВЛЕНА в результаты!")

            logging.info(
                f"   ✅ Всего найдено батчей: {len(filtered_items)} из {len(user_batches)}"
            )

        # ════════════════════════════════════════════════════════════════════
        # 📤 ЭКСПОРТЕР - ПУЛЫ
        # ════════════════════════════════════════════════════════════════════
        elif role == "exporter":
            pull_count = 0
            all_pulls = pulls.get("pulls", {})
            seen_pull_ids = set()

            for pull_id, pull in all_pulls.items():
                if not isinstance(pull, dict):
                    continue

                if (
                    same_id(pull.get("creator_id"), user_id)
                    or same_id(pull.get("exporter_id"), user_id)
                ):
                    canonical_pull_id = pull.get("id", pull_id)
                    canonical_pull_key = str(canonical_pull_id)
                    if canonical_pull_key in seen_pull_ids:
                        continue
                    seen_pull_ids.add(canonical_pull_key)
                    pull_count += 1
                    pull_status = pull.get("status", "active")

                    logging.info(
                        f"      Пул #{pull.get('id')}: '{pull.get('culture', 'N/A')}' → статус='{pull_status}'"
                    )

                    # ✅ ИСПРАВЛЕННАЯ ЛОГИКА!
                    if search_status == "all":
                        # Показываем ВСЕ пулы
                        filtered_items.append(
                            {
                                "index": pull.get("id"),
                                "culture": pull.get("culture", "N/A"),
                                "volume": pull.get("current_volume", 0),
                                "target": pull.get("target_volume", 0),
                                "price": pull.get("price_per_ton", pull.get("price", 0)),
                                "status": pull_status,
                                "id": canonical_pull_id,
                            }
                        )
                        logging.info("         ✅ ДОБАВЛЕН в результаты (all)!")
                    elif (
                        search_status == "active"
                        and is_pull_open_status(pull_status)
                    ) or status_in_group(pull_status, {search_status}):
                        # Показываем только с конкретным статусом
                        filtered_items.append(
                            {
                                "index": pull.get("id"),
                                "culture": pull.get("culture", "N/A"),
                                "volume": pull.get("current_volume", 0),
                                "target": pull.get("target_volume", 0),
                                "price": pull.get("price_per_ton", pull.get("price", 0)),
                                "status": pull_status,
                                "id": canonical_pull_id,
                            }
                        )
                        logging.info(
                            f"         ✅ ДОБАВЛЕН в результаты (status={search_status})!"
                        )

            logging.info(
                f"   ✅ Всего найдено пулов: {len(filtered_items)} из {pull_count}"
            )

        # ════════════════════════════════════════════════════════════════════
        # 🚚 ЛОГИСТ - ДОСТАВКИ
        # ════════════════════════════════════════════════════════════════════
        elif is_logistic_role(role):
            ship_count = 0
            seen_delivery_ids = set()
            for delivery_id, delivery in deliveries.items():
                if not isinstance(delivery, dict):
                    continue
                assigned_logist_id = get_assigned_logist_id(delivery)
                if not assigned_logist_id:
                    linked_request = None
                    request_ref = delivery.get("request_id")
                    delivery_source = str(delivery.get("source") or "").strip().lower()
                    if delivery_source == "logistic":
                        delivery_source = "logistics"
                    if delivery_source not in {"exporter", "farmer", "logistics"}:
                        source_candidates = set()
                        request_key = request_ref if isinstance(request_ref, str) else str(request_ref)
                        if request_ref in shipping_requests or request_key in shipping_requests:
                            source_candidates.add("exporter")
                        if request_ref in logistics_requests or request_key in logistics_requests:
                            source_candidates.add("logistics")
                        if (
                            request_ref in farmer_shipping_requests
                            or request_key in farmer_shipping_requests
                            or request_ref in farmer_logistics_requests
                            or request_key in farmer_logistics_requests
                        ):
                            source_candidates.add("farmer")
                        if len(source_candidates) == 1:
                            delivery_source = next(iter(source_candidates))
                        else:
                            inferred_source = infer_logistic_offer_source(request_ref)
                            if (
                                inferred_source in {"exporter", "farmer", "logistics"}
                                and (not source_candidates or inferred_source in source_candidates)
                            ):
                                delivery_source = inferred_source
                            else:
                                continue
                    if delivery_source == "farmer":
                        _, linked_request = find_farmer_request_by_id(request_ref)
                    elif delivery_source == "logistics":
                        linked_request = logistics_requests.get(request_ref) or logistics_requests.get(
                            str(request_ref)
                        )
                    else:
                        _, linked_request = find_shipping_request_by_id(request_ref)
                    linked_request = linked_request if isinstance(linked_request, dict) else {}
                    assigned_logist_id = get_assigned_logist_id(linked_request)
                if same_id(assigned_logist_id, user_id):
                    canonical_id = delivery.get("id", delivery_id)
                    canonical_key = str(canonical_id)
                    if canonical_key in seen_delivery_ids:
                        continue
                    seen_delivery_ids.add(canonical_key)
                    ship_count += 1
                    ship_status = delivery.get("status", "Открыт")

                    logging.info(
                        f"      Доставка #{delivery.get('id', canonical_id)}: "
                        f"{delivery.get('route_from') or delivery.get('from_city') or delivery.get('from')}→"
                        f"{delivery.get('route_to') or delivery.get('to_city') or delivery.get('to')} "
                        f"→ статус='{ship_status}'"
                    )

                    # ✅ ИСПРАВЛЕННАЯ ЛОГИКА!
                    if search_status == "all":
                        filtered_items.append(
                            {
                                "index": delivery.get("id", canonical_id),
                                "from": (
                                    delivery.get("route_from")
                                    or delivery.get("from_city")
                                    or delivery.get("from")
                                    or "N/A"
                                ),
                                "to": (
                                    delivery.get("route_to")
                                    or delivery.get("to_city")
                                    or delivery.get("to")
                                    or "N/A"
                                ),
                                "volume": delivery.get("volume", 0),
                                "price": delivery.get("price", 0),
                                "status": ship_status,
                                "id": f"delivery_{canonical_id}",
                            }
                        )
                        logging.info("         ✅ ДОБАВЛЕНА в результаты (all)!")
                    elif status_in_group(
                        ship_status,
                        {
                            "pending",
                            "new",
                            "assigned",
                            "expeditor_selected",
                            "",
                            "none",
                        }
                        if search_status == "pending"
                        else {search_status},
                    ):
                        filtered_items.append(
                            {
                                "index": delivery.get("id", canonical_id),
                                "from": (
                                    delivery.get("route_from")
                                    or delivery.get("from_city")
                                    or delivery.get("from")
                                    or "N/A"
                                ),
                                "to": (
                                    delivery.get("route_to")
                                    or delivery.get("to_city")
                                    or delivery.get("to")
                                    or "N/A"
                                ),
                                "volume": delivery.get("volume", 0),
                                "price": delivery.get("price", 0),
                                "status": ship_status,
                                "id": f"delivery_{canonical_id}",
                            }
                        )
                        logging.info("         ✅ ДОБАВЛЕНА в результаты!")

            logging.info(
                f"   ✅ Всего найдено доставок: {len(filtered_items)} из {ship_count}"
            )

        # ════════════════════════════════════════════════════════════════════
        # ✈️ ЭКСПЕДИТОР - МАРШРУТЫ
        # ════════════════════════════════════════════════════════════════════
        elif is_expeditor_role(role):
            offer_count = 0
            seen_offer_ids = set()
            for offer_id, offer in expeditor_offers.items():
                if not isinstance(offer, dict):
                    continue
                if same_id(offer.get("expeditor_id"), user_id):
                    canonical_id = offer.get("id", offer_id)
                    canonical_key = str(canonical_id)
                    if canonical_key in seen_offer_ids:
                        continue
                    seen_offer_ids.add(canonical_key)
                    offer_count += 1
                    offer_status = offer.get("status", "Открыт")

                    logging.info(
                        f"      Маршрут #{offer.get('id')}: {offer.get('from_port')}→{offer.get('to_port')} → статус='{offer_status}'"
                    )

                    # ✅ ИСПРАВЛЕННАЯ ЛОГИКА!
                    if search_status == "all":
                        filtered_items.append(
                            {
                                "index": offer.get("id"),
                                "from": (
                                    offer.get("from_port")
                                    or offer.get("route_from")
                                    or offer.get("from_city")
                                    or offer.get("from")
                                    or "N/A"
                                ),
                                "to": (
                                    offer.get("to_port")
                                    or offer.get("route_to")
                                    or offer.get("to_city")
                                    or offer.get("to")
                                    or "N/A"
                                ),
                                "volume": offer.get("max_volume", 0),
                                "price": offer.get("price", 0),
                                "status": offer_status,
                                "id": f"offer_{canonical_id}",
                            }
                        )
                        logging.info("         ✅ ДОБАВЛЕН в результаты (all)!")
                    elif status_in_group(
                        offer_status,
                        {"active", "open", "selected", "", "none"}
                        if search_status == "active"
                        else {search_status},
                    ):
                        filtered_items.append(
                            {
                                "index": offer.get("id"),
                                "from": (
                                    offer.get("from_port")
                                    or offer.get("route_from")
                                    or offer.get("from_city")
                                    or offer.get("from")
                                    or "N/A"
                                ),
                                "to": (
                                    offer.get("to_port")
                                    or offer.get("route_to")
                                    or offer.get("to_city")
                                    or offer.get("to")
                                    or "N/A"
                                ),
                                "volume": offer.get("max_volume", 0),
                                "price": offer.get("price", 0),
                                "status": offer_status,
                                "id": f"offer_{canonical_id}",
                            }
                        )
                        logging.info("         ✅ ДОБАВЛЕН в результаты!")

            request_count = 0
            seen_request_ids = set()
            for delivery_key, delivery in deliveries.items():
                if not isinstance(delivery, dict):
                    continue
                assigned_expeditor_id = get_assigned_expeditor_id(delivery)
                linked_request = None
                if not assigned_expeditor_id:
                    request_ref = delivery.get("request_id")
                    delivery_source = str(delivery.get("source") or "").strip().lower()
                    if delivery_source == "logistic":
                        delivery_source = "logistics"
                    if delivery_source not in {"exporter", "farmer", "logistics"}:
                        source_candidates = set()
                        request_key = request_ref if isinstance(request_ref, str) else str(request_ref)
                        if request_ref in shipping_requests or request_key in shipping_requests:
                            source_candidates.add("exporter")
                        if request_ref in logistics_requests or request_key in logistics_requests:
                            source_candidates.add("logistics")
                        if (
                            request_ref in farmer_shipping_requests
                            or request_key in farmer_shipping_requests
                            or request_ref in farmer_logistics_requests
                            or request_key in farmer_logistics_requests
                        ):
                            source_candidates.add("farmer")
                        if len(source_candidates) == 1:
                            delivery_source = next(iter(source_candidates))
                        else:
                            inferred_source = infer_logistic_offer_source(request_ref)
                            if (
                                inferred_source in {"exporter", "farmer", "logistics"}
                                and (not source_candidates or inferred_source in source_candidates)
                            ):
                                delivery_source = inferred_source
                            else:
                                continue
                    if delivery_source == "farmer":
                        _, linked_request = find_farmer_request_by_id(request_ref)
                    elif delivery_source == "logistics":
                        linked_request = logistics_requests.get(
                            request_ref
                        ) or logistics_requests.get(str(request_ref))
                    else:
                        _, linked_request = find_shipping_request_by_id(request_ref)
                    linked_request = linked_request if isinstance(linked_request, dict) else {}
                    assigned_expeditor_id = get_assigned_expeditor_id(linked_request)
                if not same_id(assigned_expeditor_id, user_id):
                    continue
                canonical_id = delivery.get("id", delivery_key)
                canonical_key = str(canonical_id)
                if canonical_key in seen_request_ids:
                    continue
                seen_request_ids.add(canonical_key)
                request_count += 1
                req_status = delivery.get("status", "Открыт")
                req_status_effective = normalize_transition_status(
                    linked_request.get("status") or req_status
                )
                route_from = delivery.get("route_from") or delivery.get("from_city") or delivery.get(
                    "from"
                ) or "N/A"
                route_to = delivery.get("route_to") or delivery.get("to_city") or delivery.get(
                    "to"
                ) or "N/A"
                matches_status = False
                if search_status == "all":
                    matches_status = True
                elif search_status == "active":
                    matches_status = status_in_group(
                        req_status_effective,
                        {
                            "active",
                            "open",
                            "selected",
                            "pending",
                            "new",
                            "assigned",
                            "expeditor_selected",
                            "",
                            "none",
                        },
                    )
                else:
                    matches_status = status_in_group(req_status_effective, {search_status})

                if not matches_status:
                    continue

                filtered_items.append(
                    {
                        "index": delivery.get("id", canonical_id),
                        "from": route_from,
                        "to": route_to,
                        "volume": delivery.get("volume", 0),
                        "price": delivery.get("price", 0),
                        "status": req_status,
                        "id": f"delivery_{canonical_id}",
                    }
                )

            logging.info(
                f"   ✅ Всего найдено маршрутов/заявок: {len(filtered_items)} "
                f"(offers={offer_count}, requests={request_count})"
            )

        # ════════════════════════════════════════════════════════════════════
        # ✅ КОМПАКТНЫЙ ТЕКСТ
        # ════════════════════════════════════════════════════════════════════
        status_titles = {
            "active": "АКТИВНЫЕ",
            "pending": "ОЖИДАЮЩИЕ",
            "reserved": "ЗАРЕЗЕРВИРОВАННЫЕ",
            "sold": "ПРОДАННЫЕ",
            "matches": "С СОВПАДЕНИЯМИ",
            "filled": "ЗАПОЛНЕННЫЕ",
            "closed": "ЗАКРЫТЫЕ",
            "cancelled": "ОТМЕНЕННЫЕ",
            "in_progress": "В РАБОТЕ",
            "delivered": "ДОСТАВЛЕННЫЕ",
            "completed": "ЗАВЕРШЕННЫЕ",
            "all": "ВСЕ",  # ✅ ДОБАВЛЕНО!
        }

        title = status_titles.get(search_status, search_status.upper())

        if filtered_items:
            text = f"<b>✅ {title}</b> ({len(filtered_items)} шт.)\n\n"
            text += "<i>Выберите элемент для просмотра деталей:</i>"
        else:
            text = f"📭 <b>Нет {title.lower()} элементов</b>"
            logging.warning(f"   ⚠️ НЕ НАЙДЕНО элементов со статусом '{search_status}'")

        # ════════════════════════════════════════════════════════════════════
        # ✅ КНОПКИ С ЭМОДЗИ КУЛЬТУР
        # ════════════════════════════════════════════════════════════════════
        keyboard = InlineKeyboardMarkup(row_width=1)

        if filtered_items:
            for item in filtered_items:
                callback_data = f"deal_detail:{role}:{item['id']}:{search_status}"

                if role == "farmer":
                    culture = item.get("culture", "").lower()
                    emoji = culture_emoji.get(culture, "🌾")
                    button_text = f"{emoji} {item['culture']}"

                elif role == "exporter":
                    culture = item.get("culture", "").lower()
                    emoji = culture_emoji.get(culture, "🌾")
                    progress = 0
                    if item["target"] > 0:
                        progress = (item["volume"] / item["target"]) * 100

                    # ✅ ДОБАВЛЕН ЭМОДЗИ СТАТУСА
                    status_emoji_map = {
                        "active": "🔓",
                        "closed": "🔒",
                        "filled": "✅",
                        "shipped": "🚢",
                        "completed": "🎉",
                    }
                    status_icon = status_emoji_map.get(
                        normalize_transition_status(item["status"]), "❓"
                    )

                    button_text = (
                        f"{status_icon} {emoji} {item['culture']} ({progress:.0f}%)"
                    )

                elif is_logistic_role(role) or is_expeditor_role(role):
                    button_text = f"🚚 {item['from']} → {item['to']}"

                keyboard.add(
                    InlineKeyboardButton(button_text, callback_data=callback_data)
                )

        keyboard.add(InlineKeyboardButton("◀️ Назад", callback_data="back_to_main"))

        await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
        logging.info(f"   ✅ Показано {len(filtered_items)} элементов пользователю")

    except Exception as e:
        logging.error(f"❌ Ошибка в фильтре: {e}", exc_info=True)
        await callback.answer(f"❌ Ошибка: {str(e)[:50]}", show_alert=True)


