@dp.callback_query_handler(lambda c: c.data == "create_pull", state="*")
async def create_pull_alias(callback: types.CallbackQuery, state: FSMContext):
    """Alias для старой inline-кнопки создания пула."""
    await state.finish()
    user_id = callback.from_user.id
    if (get_user_by_id(user_id) or {}).get("role") not in {"exporter", "admin"}:
        await callback.answer("❌ Доступно только экспортёру", show_alert=True)
        return

    await CreatePullStatesGroup.culture.set()
    await callback.message.edit_text(
        "🌾 <b>Создание пула</b>\n\n"
        "<b>Шаг 1 из 10</b>\n\n"
        "Выберите культуру:",
        reply_markup=culture_keyboard(),
        parse_mode="HTML",
    )
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data == "view_pools", state="*")
async def view_pools_alias(callback: types.CallbackQuery, state: FSMContext):
    """Alias для inline-кнопки просмотра пулов фермером."""
    await state.finish()
    user_id = callback.from_user.id
    if (get_user_by_id(user_id) or {}).get("role") not in {"farmer", "admin"}:
        await callback.answer("❌ Доступно только фермеру", show_alert=True)
        return

    all_pulls = pulls.get("pulls", {})
    open_pulls = []
    for pull_id, pull in all_pulls.items():
        if isinstance(pull, dict) and is_pull_open_status(pull.get("status")):
            pull_data = pull.copy()
            pull_data["pull_id"] = pull_id
            open_pulls.append(pull_data)

    if not open_pulls:
        keyboard = InlineKeyboardMarkup()
        keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))
        await callback.message.edit_text(
            "🎯 Сейчас нет открытых пулов для участия.",
            reply_markup=keyboard,
        )
        await callback.answer()
        return

    keyboard = InlineKeyboardMarkup(row_width=1)
    for pull in open_pulls[:10]:
        pull_id = pull.get("pull_id")
        progress = (
            pull.get("current_volume", 0) / pull.get("target_volume", 1) * 100
            if pull.get("target_volume", 1) > 0
            else 0
        )
        keyboard.add(
            InlineKeyboardButton(
                f"🌾 {pull.get('culture', '?')} - {pull.get('target_volume', 0)}т ({progress:.0f}%)",
                callback_data=f"view_pull:{pull_id}",
            )
        )
    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))
    await callback.message.edit_text(
        f"🎯 <b>Активные пулы</b> ({len(open_pulls)} шт.)\n\nВыберите пул:",
        reply_markup=keyboard,
        parse_mode="HTML",
    )
    await callback.answer()


