@dp.callback_query_handler(lambda c: c.data == "back_to_exp_deliveries", state="*")
async def back_to_exp_deliveries_alias(callback: types.CallbackQuery, state: FSMContext):
    """Возврат к списку доставок экспедитора/логиста."""
    await state.finish()
    user_id = callback.from_user.id
    role = (get_user_by_id(user_id) or {}).get("role")

    if is_logistic_role(role):
        await show_my_deliveries(callback, state)
        return

    if not is_expeditor_role(role):
        await callback.answer("❌ Раздел недоступен", show_alert=True)
        return

    my_deliveries = []
    seen_delivery_ids = set()
    for deliv_id, deliv in deliveries.items():
        if not isinstance(deliv, dict):
            continue
        linked_request = None
        assigned_expeditor_id = get_assigned_expeditor_id(deliv)
        if not assigned_expeditor_id:
            request_ref = deliv.get("request_id")
            delivery_source = str(deliv.get("source") or "").strip().lower()
            if delivery_source == "logistic":
                delivery_source = "logistics"
            if delivery_source not in {"exporter", "farmer", "logistics"}:
                source_candidates = set()
                request_key = request_ref if isinstance(request_ref, str) else str(request_ref)
                if request_ref in shipping_requests or request_key in shipping_requests:
                    source_candidates.add("exporter")
                if request_ref in logistics_requests or request_key in logistics_requests:
                    source_candidates.add("logistics")
                if (
                    request_ref in farmer_shipping_requests
                    or request_key in farmer_shipping_requests
                    or request_ref in farmer_logistics_requests
                    or request_key in farmer_logistics_requests
                ):
                    source_candidates.add("farmer")
                if len(source_candidates) == 1:
                    delivery_source = next(iter(source_candidates))
                else:
                    inferred_source = infer_logistic_offer_source(request_ref)
                    if (
                        inferred_source in {"exporter", "farmer", "logistics"}
                        and (not source_candidates or inferred_source in source_candidates)
                    ):
                        delivery_source = inferred_source
                    else:
                        continue
            if delivery_source == "farmer":
                _, linked_request = find_farmer_request_by_id(request_ref)
            elif delivery_source == "logistics":
                linked_request = logistics_requests.get(request_ref) or logistics_requests.get(
                    str(request_ref)
                )
            else:
                _, linked_request = find_shipping_request_by_id(request_ref)
            linked_request = linked_request if isinstance(linked_request, dict) else {}
            assigned_expeditor_id = get_assigned_expeditor_id(linked_request)
        if not same_id(assigned_expeditor_id, user_id):
            continue
        delivery_status_norm = normalize_transition_status(deliv.get("status"))
        request_status_norm = normalize_transition_status(linked_request.get("status"))
        effective_status = (
            request_status_norm
            if request_status_norm in {"in_progress", "expeditor_selected"}
            else delivery_status_norm
        )
        if effective_status not in {
            "in_progress",
            "expeditor_selected",
        }:
            continue
        canonical_id = deliv.get("id", deliv_id)
        canonical_key = str(canonical_id)
        if canonical_key in seen_delivery_ids:
            continue
        seen_delivery_ids.add(canonical_key)
        my_deliveries.append((canonical_id, deliv))

    keyboard = InlineKeyboardMarkup(row_width=1)

    if not my_deliveries:
        keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))
        await callback.message.edit_text(
            "🚛 <b>Мои доставки</b>\n\n📋 У вас нет активных доставок.",
            reply_markup=keyboard,
            parse_mode="HTML",
        )
        await callback.answer()
        return

    text = (
        "🚛 <b>Мои активные доставки</b>\n\n"
        f"📋 Всего доставок: <b>{len(my_deliveries)}</b>\n\n"
        "Выберите доставку:"
    )

    for deliv_key, deliv in my_deliveries:
        delivery_id = deliv.get("id") or deliv_key
        request_ref = deliv.get("request_id")
        delivery_source = str(deliv.get("source") or "").strip().lower()
        if delivery_source == "logistic":
            delivery_source = "logistics"
        if delivery_source not in {"exporter", "farmer", "logistics"}:
            source_candidates = set()
            request_key = request_ref if isinstance(request_ref, str) else str(request_ref)
            if request_ref in shipping_requests or request_key in shipping_requests:
                source_candidates.add("exporter")
            if request_ref in logistics_requests or request_key in logistics_requests:
                source_candidates.add("logistics")
            if (
                request_ref in farmer_shipping_requests
                or request_key in farmer_shipping_requests
                or request_ref in farmer_logistics_requests
                or request_key in farmer_logistics_requests
            ):
                source_candidates.add("farmer")
            if len(source_candidates) == 1:
                delivery_source = next(iter(source_candidates))
            else:
                inferred_source = infer_logistic_offer_source(request_ref)
                if (
                    inferred_source in {"exporter", "farmer", "logistics"}
                    and (not source_candidates or inferred_source in source_candidates)
                ):
                    delivery_source = inferred_source
                else:
                    continue
        linked_request = None
        if delivery_source == "farmer":
            _, linked_request = find_farmer_request_by_id(request_ref)
        elif delivery_source == "logistics":
            linked_request = logistics_requests.get(request_ref) or logistics_requests.get(
                str(request_ref)
            )
        else:
            _, linked_request = find_shipping_request_by_id(request_ref)
        linked_request = linked_request if isinstance(linked_request, dict) else {}
        culture = deliv.get("culture") or linked_request.get("culture") or "N/A"
        volume = deliv.get("volume", 0) or 0
        route_to = deliv.get("route_to") or deliv.get("to_city") or "—"
        keyboard.add(
            InlineKeyboardButton(
                f"🚚 #{delivery_id} | {culture} | {volume:.0f} т → {route_to}",
                callback_data=f"exp_delivery:delivery_{delivery_id}",
            )
        )

    keyboard.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))
    await callback.message.edit_text(text, reply_markup=keyboard, parse_mode="HTML")
    await callback.answer()


@dp.callback_query_handler(lambda c: c.data == "delivery_history", state="*")
async def delivery_history_alias(callback: types.CallbackQuery, state: FSMContext):
    """История доставок через callback-кнопку."""
    await state.finish()
    user_id = callback.from_user.id
    role = (get_user_by_id(user_id) or {}).get("role")

    if is_expeditor_role(role):
        completed = []
        seen_delivery_ids = set()
        for deliv_id, deliv in deliveries.items():
            if not isinstance(deliv, dict):
                continue
            linked_request = None
            assigned_expeditor_id = get_assigned_expeditor_id(deliv)
            if not assigned_expeditor_id:
                request_ref = deliv.get("request_id")
                delivery_source = str(deliv.get("source") or "").strip().lower()
                if delivery_source == "logistic":
                    delivery_source = "logistics"
                if delivery_source not in {"exporter", "farmer", "logistics"}:
                    source_candidates = set()
                    request_key = request_ref if isinstance(request_ref, str) else str(request_ref)
                    if request_ref in shipping_requests or request_key in shipping_requests:
                        source_candidates.add("exporter")
                    if request_ref in logistics_requests or request_key in logistics_requests:
                        source_candidates.add("logistics")
                    if (
                        request_ref in farmer_shipping_requests
                        or request_key in farmer_shipping_requests
                        or request_ref in farmer_logistics_requests
                        or request_key in farmer_logistics_requests
                    ):
                        source_candidates.add("farmer")
                    if len(source_candidates) == 1:
                        delivery_source = next(iter(source_candidates))
                    else:
                        inferred_source = infer_logistic_offer_source(request_ref)
                        if (
                            inferred_source in {"exporter", "farmer", "logistics"}
                            and (not source_candidates or inferred_source in source_candidates)
                        ):
                            delivery_source = inferred_source
                        else:
                            continue
                if delivery_source == "farmer":
                    _, linked_request = find_farmer_request_by_id(request_ref)
                elif delivery_source == "logistics":
                    linked_request = logistics_requests.get(request_ref) or logistics_requests.get(
                        str(request_ref)
                    )
                else:
                    _, linked_request = find_shipping_request_by_id(request_ref)
                linked_request = linked_request if isinstance(linked_request, dict) else {}
                assigned_expeditor_id = get_assigned_expeditor_id(linked_request)
            if not same_id(assigned_expeditor_id, user_id):
                continue
            if normalize_transition_status(deliv.get("status")) != "completed":
                continue
            canonical_id = deliv.get("id", deliv_id)
            canonical_key = str(canonical_id)
            if canonical_key in seen_delivery_ids:
                continue
            seen_delivery_ids.add(canonical_key)
            completed.append((canonical_id, deliv))
        if not completed:
            await callback.message.edit_text(
                "✔️ <b>История доставок</b>\n\n📋 У вас пока нет завершённых доставок.",
                parse_mode="HTML",
                reply_markup=InlineKeyboardMarkup().add(
                    InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main")
                ),
            )
            await callback.answer()
            return

        text = f"✔️ <b>История доставок</b>\n\n📋 Всего завершено: <b>{len(completed)}</b>\n\n"
        for deliv_id, deliv in completed[-10:]:
            text += (
                f"🚚 <b>Доставка #{deliv_id}</b>\n"
                f"   {deliv.get('culture', 'N/A')} | {(deliv.get('volume', 0) or 0):.0f} т\n"
                f"   ✅ Завершена: {deliv.get('completed_at', '—')}\n\n"
            )

        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))
        await callback.message.edit_text(text, parse_mode="HTML", reply_markup=kb)
        await callback.answer()
        return

    if is_logistic_role(role):
        completed = []
        seen_delivery_ids = set()
        for deliv_id, deliv in deliveries.items():
            if not isinstance(deliv, dict):
                continue
            if not same_id(get_assigned_logist_id(deliv), user_id):
                continue
            if normalize_transition_status(deliv.get("status")) != "completed":
                continue
            canonical_id = deliv.get("id", deliv_id)
            canonical_key = str(canonical_id)
            if canonical_key in seen_delivery_ids:
                continue
            seen_delivery_ids.add(canonical_key)
            completed.append((canonical_id, deliv))

        if not completed:
            kb = InlineKeyboardMarkup()
            kb.add(InlineKeyboardButton("🚛 Мои доставки", callback_data="my_deliveries"))
            kb.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))
            await callback.message.edit_text(
                "✔️ <b>История доставок</b>\n\n📋 У вас пока нет завершённых доставок.",
                parse_mode="HTML",
                reply_markup=kb,
            )
            await callback.answer()
            return

        text = f"✔️ <b>История доставок</b>\n\n📋 Завершено: <b>{len(completed)}</b>\n\n"
        for deliv_id, deliv in completed[-10:]:
            text += (
                f"🚚 <b>Доставка #{deliv_id}</b>\n"
                f"   {(deliv.get('route_from') or deliv.get('from_city') or '—')} → {(deliv.get('route_to') or deliv.get('to_city') or '—')}\n"
                f"   💰 {deliv.get('price', 0):,.0f} ₽\n\n".replace(",", " ")
            )

        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("🚛 Мои доставки", callback_data="my_deliveries"))
        kb.add(InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main"))
        await callback.message.edit_text(text, parse_mode="HTML", reply_markup=kb)
        await callback.answer()
        return

    await callback.answer("❌ Раздел недоступен", show_alert=True)


@dp.callback_query_handler(lambda c: c.data == "back", state="*")
async def legacy_back_alias(callback: types.CallbackQuery, state: FSMContext):
    await back_to_main_handler(callback, state)


@dp.callback_query_handler(
    lambda c: c.data
    in {
        "vehicle:truck",
        "vehicle:train",
        "vehicle:ship",
        "transport:auto",
        "transport:rail",
        "transport:sea",
        "transport_type:truck",
        "transport_type:train",
        "transport_type:ship",
    },
    state="*",
)
async def legacy_transport_callback_alias(
    callback: types.CallbackQuery, state: FSMContext
):
    """Совместимость со старыми callback токенами выбора транспорта."""
    await state.finish()
    await callback.answer(
        "ℹ️ Этот формат выбора транспорта устарел. Открыл главное меню.",
        show_alert=False,
    )
    await back_to_main_handler(callback, state)


@dp.callback_query_handler(state="*")
async def unknown_callback_fallback(callback: types.CallbackQuery, state: FSMContext):
    """Последний fallback: не даём callback-ам зависать без ответа."""
    await state.finish()
    await callback.answer("ℹ️ Эта кнопка больше не активна.", show_alert=False)
    try:
        await callback.message.edit_text(
            "ℹ️ Эта кнопка больше не поддерживается.\n"
            "Вернитесь в главное меню.",
            reply_markup=InlineKeyboardMarkup().add(
                InlineKeyboardButton("🏠 Главное меню", callback_data="back_to_main")
            ),
        )
    except Exception as e:
        logging.debug(f"Не удалось отрисовать unknown_callback_fallback: {e}")


